create or replace function public.recompute_odyssey_character_combat_state(p_character_id uuid)
returns jsonb
language plpgsql
as $body$
declare
  v_character record;
  v_body_summary jsonb := '{}'::jsonb;
  v_active_effects jsonb := '[]'::jsonb;
  v_active_penalties jsonb := '[]'::jsonb;
  v_overlay_lines text[] := array[]::text[];
  v_overlay_text text := '';
  v_overlay_data jsonb := '{}'::jsonb;
  v_armor_total integer := 0;
  v_state_version integer := 1;
  v_tracker_minor integer := 0;
  v_tracker_serious integer := 0;
  v_is_alive boolean := true;
  v_is_conscious boolean := true;
  v_head jsonb := '{}'::jsonb;
  v_l_arm jsonb := '{}'::jsonb;
  v_r_arm jsonb := '{}'::jsonb;
  v_torso jsonb := '{}'::jsonb;
  v_l_leg jsonb := '{}'::jsonb;
  v_r_leg jsonb := '{}'::jsonb;
  v_shield jsonb := '{}'::jsonb;
  v_special jsonb := '{}'::jsonb;
begin
  select *
  into v_character
  from public.odyssey_characters
  where id = p_character_id;

  if not found then
    raise exception 'Character % was not found', p_character_id;
  end if;

  select
    coalesce(
      jsonb_object_agg(
        b.part_key,
        jsonb_build_object(
          'current_hp', b.current_hp,
          'max_hp', b.max_hp,
          'armor', b.armor,
          'minor', b.minor,
          'serious', b.serious,
          'critical', greatest(0, coalesce(b.critical, greatest(0, b.max_hp - b.current_hp))),
          'max_critical', coalesce(nullif(b.max_critical, 0), b.max_hp),
          'destroyed', b.destroyed,
          'disabled', b.disabled,
          'notes', b.notes
        )
      ),
      '{}'::jsonb
    ),
    coalesce(sum(b.armor), 0)
  into v_body_summary, v_armor_total
  from public.odyssey_character_body_parts b
  where b.character_id = p_character_id;

  select
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'id', e.id,
          'effect_key', e.effect_key,
          'name', e.name,
          'description', e.description,
          'source', e.source,
          'source_character_id', e.source_character_id,
          'duration_type', e.duration_type,
          'rounds_left', e.rounds_left,
          'data', e.data,
          'created_by', e.created_by,
          'created_at', e.created_at
        )
        order by e.created_at desc
      ),
      '[]'::jsonb
    )
  into v_active_effects
  from public.odyssey_character_effects e
  where e.character_id = p_character_id
    and e.is_active = true;

  select
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'effect_id', e.id,
          'effect_key', e.effect_key,
          'effect_name', e.name,
          'kind', penalty->>'kind',
          'skill', penalty->>'skill',
          'part_key', penalty->>'part_key',
          'value', coalesce((penalty->>'value')::integer, 0)
        )
        order by e.created_at desc
      ),
      '[]'::jsonb
    )
  into v_active_penalties
  from public.odyssey_character_effects e
  join lateral jsonb_array_elements(
    case
      when jsonb_typeof(e.data->'penalties') = 'array' then e.data->'penalties'
      else '[]'::jsonb
    end
  ) as penalty on true
  where e.character_id = p_character_id
    and e.is_active = true;

  v_head := coalesce(v_body_summary->'Head', '{}'::jsonb);
  v_l_arm := coalesce(v_body_summary->'L.Arm', '{}'::jsonb);
  v_r_arm := coalesce(v_body_summary->'R.Arm', '{}'::jsonb);
  v_torso := coalesce(v_body_summary->'Torso', '{}'::jsonb);
  v_l_leg := coalesce(v_body_summary->'L.Leg', '{}'::jsonb);
  v_r_leg := coalesce(v_body_summary->'R.Leg', '{}'::jsonb);
  v_shield := coalesce(v_body_summary->'Shield', '{}'::jsonb);
  v_special := coalesce(v_body_summary->'Special', '{}'::jsonb);

  if coalesce((v_shield->>'max_hp')::integer, 0) > 0
     or coalesce((v_shield->>'current_hp')::integer, 0) > 0
     or coalesce((v_shield->>'armor')::integer, 0) > 0 then
    v_overlay_lines := array_append(
      v_overlay_lines,
      format(
        'Shield %s/%s(%s)',
        coalesce(v_shield->>'current_hp', '0'),
        coalesce(v_shield->>'max_hp', '0'),
        coalesce(v_shield->>'armor', '0')
      )
    );
  end if;

  if coalesce((v_special->>'max_hp')::integer, 0) > 0
     or coalesce((v_special->>'current_hp')::integer, 0) > 0
     or coalesce((v_special->>'armor')::integer, 0) > 0 then
    v_overlay_lines := array_append(
      v_overlay_lines,
      format(
        'Special %s/%s(%s)',
        coalesce(v_special->>'current_hp', '0'),
        coalesce(v_special->>'max_hp', '0'),
        coalesce(v_special->>'armor', '0')
      )
    );
  end if;

  v_overlay_lines := array_append(
    v_overlay_lines,
    format(
      'Head %s/%s(%s) | L.Arm %s/%s(%s) | R.Arm %s/%s(%s)',
      coalesce(v_head->>'current_hp', '0'),
      coalesce(v_head->>'max_hp', '0'),
      coalesce(v_head->>'armor', '0'),
      coalesce(v_l_arm->>'current_hp', '0'),
      coalesce(v_l_arm->>'max_hp', '0'),
      coalesce(v_l_arm->>'armor', '0'),
      coalesce(v_r_arm->>'current_hp', '0'),
      coalesce(v_r_arm->>'max_hp', '0'),
      coalesce(v_r_arm->>'armor', '0')
    )
  );

  v_overlay_lines := array_append(
    v_overlay_lines,
    format(
      'Torso %s/%s(%s) | L.Leg %s/%s(%s) | R.Leg %s/%s(%s)',
      coalesce(v_torso->>'current_hp', '0'),
      coalesce(v_torso->>'max_hp', '0'),
      coalesce(v_torso->>'armor', '0'),
      coalesce(v_l_leg->>'current_hp', '0'),
      coalesce(v_l_leg->>'max_hp', '0'),
      coalesce(v_l_leg->>'armor', '0'),
      coalesce(v_r_leg->>'current_hp', '0'),
      coalesce(v_r_leg->>'max_hp', '0'),
      coalesce(v_r_leg->>'armor', '0')
    )
  );

  v_overlay_text := array_to_string(v_overlay_lines, E'\n');
  v_tracker_minor := greatest(0, least(4, coalesce(v_character.tracker_minor, 0)));
  v_tracker_serious := greatest(0, least(2, coalesce(v_character.tracker_serious, 0)));

  v_is_alive :=
    greatest(
      coalesce((v_head->>'current_hp')::integer, 0) +
      coalesce((v_l_arm->>'current_hp')::integer, 0) +
      coalesce((v_r_arm->>'current_hp')::integer, 0) +
      coalesce((v_torso->>'current_hp')::integer, 0) +
      coalesce((v_l_leg->>'current_hp')::integer, 0) +
      coalesce((v_r_leg->>'current_hp')::integer, 0),
      0
    ) > 0;

  v_is_conscious :=
    coalesce((v_head->>'current_hp')::integer, 0) > 0
    and coalesce((v_torso->>'current_hp')::integer, 0) > 0;

  select coalesce(state_version, 0) + 1
  into v_state_version
  from public.odyssey_character_combat_state
  where character_id = p_character_id;

  v_state_version := greatest(1, coalesce(v_state_version, 1));
  v_overlay_data := jsonb_build_object(
    'lines', to_jsonb(v_overlay_lines),
    'armorTotal', v_armor_total,
    'stateVersion', v_state_version
  );

  insert into public.odyssey_character_combat_state (
    character_id,
    campaign_id,
    room_id,
    body_summary,
    armor_summary,
    active_effects,
    active_penalties,
    overlay_text,
    overlay_data,
    tracker_minor,
    tracker_serious,
    is_alive,
    is_conscious,
    state_version
  )
  values (
    p_character_id,
    coalesce(v_character.campaign_id, ''),
    coalesce(v_character.room_id, ''),
    v_body_summary,
    jsonb_build_object(
      'total', v_armor_total,
      'parts', v_body_summary
    ),
    v_active_effects,
    v_active_penalties,
    v_overlay_text,
    v_overlay_data,
    v_tracker_minor,
    v_tracker_serious,
    v_is_alive,
    v_is_conscious,
    v_state_version
  )
  on conflict (character_id) do update
  set
    campaign_id = excluded.campaign_id,
    room_id = excluded.room_id,
    body_summary = excluded.body_summary,
    armor_summary = excluded.armor_summary,
    active_effects = excluded.active_effects,
    active_penalties = excluded.active_penalties,
    overlay_text = excluded.overlay_text,
    overlay_data = excluded.overlay_data,
    tracker_minor = excluded.tracker_minor,
    tracker_serious = excluded.tracker_serious,
    is_alive = excluded.is_alive,
    is_conscious = excluded.is_conscious,
    state_version = excluded.state_version
  returning state_version into v_state_version;

  update public.odyssey_characters
  set
    active_combat_state_version = v_state_version,
    updated_at = timezone('utc', now())
  where id = p_character_id;

  return jsonb_build_object(
    'character_id', v_character.id,
    'character_key', v_character.character_key,
    'campaign_id', v_character.campaign_id,
    'room_id', v_character.room_id,
    'state_version', v_state_version,
    'tracker_minor', v_tracker_minor,
    'tracker_serious', v_tracker_serious,
    'combat_state', jsonb_build_object(
      'body_summary', v_body_summary,
      'armor_summary', jsonb_build_object(
        'total', v_armor_total,
        'parts', v_body_summary
      ),
      'active_effects', v_active_effects,
      'active_penalties', v_active_penalties,
      'overlay_text', v_overlay_text,
      'overlay_data', v_overlay_data,
      'is_alive', v_is_alive,
      'is_conscious', v_is_conscious,
      'tracker_minor', v_tracker_minor,
      'tracker_serious', v_tracker_serious,
      'state_version', v_state_version
    )
  );
end;
$body$;

create or replace function public.get_odyssey_character_sheet(p_character_key text)
returns jsonb
language sql
stable
as $body$
  select
    jsonb_build_object(
      'character_id', c.id,
      'character_key', c.character_key,
      'character_bucket', c.character_bucket,
      'source_template_key', c.source_template_key,
      'campaign_id', c.campaign_id,
      'room_id', c.room_id,
      'enabled', c.enabled,
      'tracker_minor', c.tracker_minor,
      'tracker_serious', c.tracker_serious,
      'owner_player_id', c.owner_player_id,
      'owner_player_name', c.owner_player_name,
      'resources', c.resources,
      'characteristics',
        coalesce(
          (
            select jsonb_agg(
              jsonb_build_object(
                'key', a.key,
                'label', a.label,
                'value', a.value,
                'sort_order', a.sort_order
              )
              order by a.sort_order, a.key
            )
            from public.odyssey_character_characteristics a
            where a.character_id = c.id
          ),
          '[]'::jsonb
        ),
      'skills',
        coalesce(
          (
            select jsonb_agg(
              jsonb_build_object(
                'name', s.name,
                'value', s.value,
                'category', s.category,
                'strength_bonus', s.strength_bonus,
                'sort_order', s.sort_order
              )
              order by s.sort_order, s.name
            )
            from public.odyssey_character_skills s
            where s.character_id = c.id
          ),
          '[]'::jsonb
        ),
      'weapons',
        coalesce(
          (
            select jsonb_agg(
              jsonb_build_object(
                'weapon_kind', w.weapon_kind,
                'name', w.name,
                'damage', w.damage,
                'accuracy', w.accuracy,
                'ammoCurrent', w.ammo_current,
                'ammoMax', w.ammo_max,
                'sort_order', w.sort_order
              )
              order by w.weapon_kind, w.sort_order, w.name
            )
            from public.odyssey_character_weapons w
            where w.character_id = c.id
          ),
          '[]'::jsonb
        ),
      'body_parts',
        coalesce(
          (
            select jsonb_agg(
              jsonb_build_object(
                'part_key', b.part_key,
                'current_hp', b.current_hp,
                'max_hp', b.max_hp,
                'armor', b.armor,
                'minor', b.minor,
                'serious', b.serious,
                'critical', b.critical,
                'max_critical', b.max_critical,
                'destroyed', b.destroyed,
                'disabled', b.disabled,
                'notes', b.notes,
                'sort_order', b.sort_order
              )
              order by b.sort_order, b.part_key
            )
            from public.odyssey_character_body_parts b
            where b.character_id = c.id
          ),
          '[]'::jsonb
        )
    )
  from public.odyssey_characters c
  where c.character_key = trim(p_character_key)
    and c.is_deleted = false;
$body$;

create or replace function public.upsert_odyssey_character_sheet(p_payload jsonb)
returns jsonb
language plpgsql
as $body$
declare
  v_character_key text := trim(coalesce(p_payload->>'character_key', ''));
  v_character_id uuid;
  v_character_bucket text := case lower(coalesce(p_payload->>'character_bucket', 'player'))
    when 'npc_template' then 'npc_template'
    when 'npc_active' then 'npc_active'
    else 'player'
  end;
  v_source_template_key text := trim(coalesce(p_payload->>'source_template_key', ''));
  v_enabled boolean := coalesce((p_payload->>'enabled')::boolean, true);
  v_tracker_minor integer := greatest(0, least(4, coalesce((p_payload->>'tracker_minor')::integer, 0)));
  v_tracker_serious integer := greatest(0, least(2, coalesce((p_payload->>'tracker_serious')::integer, 0)));
  v_owner_player_id text := coalesce(p_payload->>'owner_player_id', '');
  v_owner_player_name text := coalesce(p_payload->>'owner_player_name', '');
  v_campaign_id text := trim(coalesce(p_payload->>'campaign_id', ''));
  v_room_id text := trim(coalesce(p_payload->>'room_id', ''));
  v_resources jsonb := case
    when jsonb_typeof(p_payload->'resources') = 'object' then p_payload->'resources'
    else '{}'::jsonb
  end;
begin
  if v_character_key = '' then
    raise exception 'character_key is required';
  end if;

  insert into public.odyssey_characters (
    character_key,
    character_bucket,
    source_template_key,
    enabled,
    tracker_minor,
    tracker_serious,
    owner_player_id,
    owner_player_name,
    campaign_id,
    room_id,
    resources,
    is_deleted
  )
  values (
    v_character_key,
    v_character_bucket,
    v_source_template_key,
    v_enabled,
    v_tracker_minor,
    v_tracker_serious,
    v_owner_player_id,
    v_owner_player_name,
    v_campaign_id,
    v_room_id,
    v_resources,
    false
  )
  on conflict (character_key) do update
  set
    character_bucket = excluded.character_bucket,
    source_template_key = excluded.source_template_key,
    enabled = excluded.enabled,
    tracker_minor = excluded.tracker_minor,
    tracker_serious = excluded.tracker_serious,
    owner_player_id = excluded.owner_player_id,
    owner_player_name = excluded.owner_player_name,
    campaign_id = excluded.campaign_id,
    room_id = excluded.room_id,
    resources = excluded.resources,
    is_deleted = false
  returning id into v_character_id;

  delete from public.odyssey_character_characteristics where character_id = v_character_id;
  delete from public.odyssey_character_skills where character_id = v_character_id;
  delete from public.odyssey_character_weapons where character_id = v_character_id;
  delete from public.odyssey_character_body_parts where character_id = v_character_id;

  insert into public.odyssey_character_characteristics (
    character_id,
    key,
    label,
    value,
    sort_order
  )
  select
    v_character_id,
    trim(coalesce(entry.value->>'key', '')),
    coalesce(nullif(trim(entry.value->>'label'), ''), trim(coalesce(entry.value->>'key', ''))),
    greatest(0, least(20, coalesce((entry.value->>'value')::integer, 0))),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'characteristics') = 'array' then p_payload->'characteristics'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality)
  where trim(coalesce(entry.value->>'key', '')) <> '';

  insert into public.odyssey_character_skills (
    character_id,
    name,
    value,
    category,
    strength_bonus,
    sort_order
  )
  select
    v_character_id,
    trim(coalesce(entry.value->>'name', '')),
    greatest(0, least(10, coalesce((entry.value->>'value')::integer, 0))),
    case lower(coalesce(entry.value->>'category', 'applied'))
      when 'combat' then 'combat'
      when 'abilities' then 'abilities'
      else 'applied'
    end,
    coalesce((entry.value->>'strength_bonus')::boolean, false),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'skills') = 'array' then p_payload->'skills'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality)
  where trim(coalesce(entry.value->>'name', '')) <> '';

  insert into public.odyssey_character_weapons (
    character_id,
    weapon_kind,
    name,
    damage,
    accuracy,
    ammo_current,
    ammo_max,
    sort_order
  )
  select
    v_character_id,
    case lower(coalesce(entry.value->>'weapon_kind', 'melee'))
      when 'ranged' then 'ranged'
      else 'melee'
    end,
    coalesce(nullif(trim(entry.value->>'name'), ''), 'Weapon'),
    greatest(-99, least(99, coalesce((entry.value->>'damage')::integer, 0))),
    greatest(-99, least(99, coalesce((entry.value->>'accuracy')::integer, 0))),
    greatest(0, coalesce((entry.value->>'ammoCurrent')::integer, (entry.value->>'ammo_current')::integer, 0)),
    greatest(0, coalesce((entry.value->>'ammoMax')::integer, (entry.value->>'ammo_max')::integer, 0)),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'weapons') = 'array' then p_payload->'weapons'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality);

  insert into public.odyssey_character_body_parts (
    character_id,
    part_key,
    current_hp,
    max_hp,
    armor,
    minor,
    serious,
    critical,
    max_critical,
    destroyed,
    disabled,
    notes,
    sort_order
  )
  select
    v_character_id,
    trim(coalesce(entry.value->>'part_key', '')),
    greatest(0, coalesce((entry.value->>'current_hp')::integer, 0)),
    greatest(0, coalesce((entry.value->>'max_hp')::integer, 0)),
    greatest(0, coalesce((entry.value->>'armor')::integer, 0)),
    greatest(0, least(3, coalesce((entry.value->>'minor')::integer, 0))),
    greatest(0, least(1, coalesce((entry.value->>'serious')::integer, 0))),
    greatest(0, coalesce((entry.value->>'critical')::integer, 0)),
    greatest(0, coalesce((entry.value->>'max_critical')::integer, (entry.value->>'max_hp')::integer, 0)),
    coalesce((entry.value->>'destroyed')::boolean, false),
    coalesce((entry.value->>'disabled')::boolean, false),
    coalesce(entry.value->>'notes', ''),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'body_parts') = 'array' then p_payload->'body_parts'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality)
  where trim(coalesce(entry.value->>'part_key', '')) in ('Head', 'L.Arm', 'R.Arm', 'Torso', 'L.Leg', 'R.Leg', 'Shield', 'Special');

  perform public.recompute_odyssey_character_combat_state(v_character_id);

  return public.get_odyssey_character_sheet(v_character_key);
end;
$body$;

grant execute on function public.get_odyssey_character_sheet(text) to anon, authenticated;
grant execute on function public.upsert_odyssey_character_sheet(jsonb) to anon, authenticated;


create or replace function public.odyssey_overlay_mix_hex_color(
  p_start_hex text,
  p_end_hex text,
  p_ratio numeric
)
returns text
language plpgsql
immutable
as $body$
declare
  v_start text := upper(regexp_replace(coalesce(p_start_hex, ''), '[^0-9A-Fa-f]', '', 'g'));
  v_end text := upper(regexp_replace(coalesce(p_end_hex, ''), '[^0-9A-Fa-f]', '', 'g'));
  v_ratio numeric := greatest(0, least(1, coalesce(p_ratio, 0)));
  v_start_r integer;
  v_start_g integer;
  v_start_b integer;
  v_end_r integer;
  v_end_g integer;
  v_end_b integer;
  v_result_r integer;
  v_result_g integer;
  v_result_b integer;
begin
  if length(v_start) <> 6 then
    v_start := '000000';
  end if;
  if length(v_end) <> 6 then
    v_end := '000000';
  end if;

  v_start_r := get_byte(decode(substr(v_start, 1, 2), 'hex'), 0);
  v_start_g := get_byte(decode(substr(v_start, 3, 2), 'hex'), 0);
  v_start_b := get_byte(decode(substr(v_start, 5, 2), 'hex'), 0);
  v_end_r := get_byte(decode(substr(v_end, 1, 2), 'hex'), 0);
  v_end_g := get_byte(decode(substr(v_end, 3, 2), 'hex'), 0);
  v_end_b := get_byte(decode(substr(v_end, 5, 2), 'hex'), 0);

  v_result_r := greatest(0, least(255, round(v_start_r + ((v_end_r - v_start_r) * v_ratio))::integer));
  v_result_g := greatest(0, least(255, round(v_start_g + ((v_end_g - v_start_g) * v_ratio))::integer));
  v_result_b := greatest(0, least(255, round(v_start_b + ((v_end_b - v_start_b) * v_ratio))::integer));

  return
    '#' ||
    upper(lpad(to_hex(v_result_r), 2, '0')) ||
    upper(lpad(to_hex(v_result_g), 2, '0')) ||
    upper(lpad(to_hex(v_result_b), 2, '0'));
end;
$body$;

create or replace function public.odyssey_overlay_hp_color(
  p_current_hp integer,
  p_max_hp integer,
  p_armor integer default 0
)
returns text
language plpgsql
immutable
as $body$
declare
  v_current_hp integer := greatest(0, coalesce(p_current_hp, 0));
  v_max_hp integer := greatest(0, coalesce(p_max_hp, 0));
  v_armor integer := greatest(0, coalesce(p_armor, 0));
  v_ratio numeric;
begin
  if v_max_hp <= 0 then
    v_ratio := case when v_armor > 0 then 1 else 0 end;
  else
    v_ratio := greatest(0, least(1, v_current_hp::numeric / v_max_hp::numeric));
  end if;

  if v_ratio >= 0.75 then
    return public.odyssey_overlay_mix_hex_color('#FFF243', '#73FF5A', (v_ratio - 0.75) / 0.25);
  end if;
  if v_ratio >= 0.5 then
    return public.odyssey_overlay_mix_hex_color('#FFAF22', '#FFF243', (v_ratio - 0.5) / 0.25);
  end if;
  if v_ratio >= 0.25 then
    return public.odyssey_overlay_mix_hex_color('#AC0004', '#FFAF22', (v_ratio - 0.25) / 0.25);
  end if;
  return public.odyssey_overlay_mix_hex_color('#000000', '#AC0004', v_ratio / 0.25);
end;
$body$;

create or replace function public.odyssey_overlay_special_color(
  p_current_hp integer,
  p_max_hp integer,
  p_armor integer default 0
)
returns text
language plpgsql
immutable
as $body$
declare
  v_current_hp integer := greatest(0, coalesce(p_current_hp, 0));
  v_max_hp integer := greatest(0, coalesce(p_max_hp, 0));
  v_armor integer := greatest(0, coalesce(p_armor, 0));
  v_ratio numeric;
begin
  if v_max_hp > 0 then
    v_ratio := greatest(0, least(1, v_current_hp::numeric / v_max_hp::numeric));
  else
    v_ratio := case when v_current_hp > 0 or v_armor > 0 then 1 else 0 end;
  end if;

  return public.odyssey_overlay_mix_hex_color('#000000', '#57D8FF', v_ratio);
end;
$body$;

create or replace function public.odyssey_overlay_signature(
  p_body_summary jsonb,
  p_visual_version integer default 12
)
returns text
language plpgsql
immutable
as $body$
declare
  v_body_summary jsonb := case
    when jsonb_typeof(p_body_summary) = 'object' then p_body_summary
    else '{}'::jsonb
  end;
  v_visual_version integer := greatest(1, coalesce(p_visual_version, 12));
  v_parts text[] := array[]::text[];
  v_part_name text;
  v_part jsonb;
begin
  foreach v_part_name in array array['Head', 'L.Arm', 'R.Arm', 'Torso', 'L.Leg', 'R.Leg', 'Shield', 'Special']
  loop
    v_part := coalesce(v_body_summary->v_part_name, '{}'::jsonb);
    v_parts := array_append(
      v_parts,
      format(
        '%s:%s:%s:%s:%s:%s',
        v_part_name,
        greatest(0, coalesce((v_part->>'current_hp')::integer, (v_part->>'current')::integer, 0)),
        greatest(0, coalesce((v_part->>'max_hp')::integer, (v_part->>'max')::integer, 0)),
        greatest(0, coalesce((v_part->>'armor')::integer, 0)),
        greatest(0, coalesce((v_part->>'minor')::integer, 0)),
        greatest(0, coalesce((v_part->>'serious')::integer, 0))
      )
    );
  end loop;

  return format('semantic-v%s;%s', v_visual_version, array_to_string(v_parts, ';'));
end;
$body$;

create or replace function public.odyssey_build_overlay_manifest(
  p_body_summary jsonb,
  p_armor_total integer default 0,
  p_state_version integer default 0,
  p_visual_version integer default 12
)
returns jsonb
language plpgsql
immutable
as $body$
declare
  v_body_summary jsonb := case
    when jsonb_typeof(p_body_summary) = 'object' then p_body_summary
    else '{}'::jsonb
  end;
  v_visual_version integer := greatest(1, coalesce(p_visual_version, 12));
  v_state_version integer := greatest(0, coalesce(p_state_version, 0));
  v_armor_total integer := greatest(0, coalesce(p_armor_total, 0));
  v_head jsonb := coalesce(v_body_summary->'Head', '{}'::jsonb);
  v_l_arm jsonb := coalesce(v_body_summary->'L.Arm', '{}'::jsonb);
  v_r_arm jsonb := coalesce(v_body_summary->'R.Arm', '{}'::jsonb);
  v_torso jsonb := coalesce(v_body_summary->'Torso', '{}'::jsonb);
  v_l_leg jsonb := coalesce(v_body_summary->'L.Leg', '{}'::jsonb);
  v_r_leg jsonb := coalesce(v_body_summary->'R.Leg', '{}'::jsonb);
  v_shield jsonb := coalesce(v_body_summary->'Shield', '{}'::jsonb);
  v_special jsonb := coalesce(v_body_summary->'Special', '{}'::jsonb);
  v_signature text := public.odyssey_overlay_signature(v_body_summary, v_visual_version);
  v_special_visible boolean := false;
  v_shield_visible boolean := false;
begin
  v_special_visible :=
    greatest(0, coalesce((v_special->>'max_hp')::integer, (v_special->>'max')::integer, 0)) > 0
    or greatest(0, coalesce((v_special->>'current_hp')::integer, (v_special->>'current')::integer, 0)) > 0
    or greatest(0, coalesce((v_special->>'armor')::integer, 0)) > 0;

  v_shield_visible :=
    greatest(0, coalesce((v_shield->>'max_hp')::integer, (v_shield->>'max')::integer, 0)) > 0
    or greatest(0, coalesce((v_shield->>'current_hp')::integer, (v_shield->>'current')::integer, 0)) > 0
    or greatest(0, coalesce((v_shield->>'armor')::integer, 0)) > 0;

  return jsonb_build_object(
    'armorTotal', v_armor_total,
    'stateVersion', v_state_version,
    'visualVersion', v_visual_version,
    'signature', v_signature,
    'items', jsonb_build_array(
      jsonb_build_object(
        'kind', 'outer-base',
        'fillColor', '#000000',
        'visible', true
      ),
      jsonb_build_object(
        'kind', 'segment-Head',
        'part', 'Head',
        'fillColor', public.odyssey_overlay_hp_color((v_head->>'current_hp')::integer, (v_head->>'max_hp')::integer, (v_head->>'armor')::integer),
        'visible', true
      ),
      jsonb_build_object(
        'kind', 'segment-R.Arm',
        'part', 'R.Arm',
        'fillColor', public.odyssey_overlay_hp_color((v_r_arm->>'current_hp')::integer, (v_r_arm->>'max_hp')::integer, (v_r_arm->>'armor')::integer),
        'visible', true
      ),
      jsonb_build_object(
        'kind', 'segment-R.Leg',
        'part', 'R.Leg',
        'fillColor', public.odyssey_overlay_hp_color((v_r_leg->>'current_hp')::integer, (v_r_leg->>'max_hp')::integer, (v_r_leg->>'armor')::integer),
        'visible', true
      ),
      jsonb_build_object(
        'kind', 'segment-L.Leg',
        'part', 'L.Leg',
        'fillColor', public.odyssey_overlay_hp_color((v_l_leg->>'current_hp')::integer, (v_l_leg->>'max_hp')::integer, (v_l_leg->>'armor')::integer),
        'visible', true
      ),
      jsonb_build_object(
        'kind', 'segment-L.Arm',
        'part', 'L.Arm',
        'fillColor', public.odyssey_overlay_hp_color((v_l_arm->>'current_hp')::integer, (v_l_arm->>'max_hp')::integer, (v_l_arm->>'armor')::integer),
        'visible', true
      ),
      jsonb_build_object(
        'kind', 'torso-ring',
        'part', 'Torso',
        'fillColor', public.odyssey_overlay_hp_color((v_torso->>'current_hp')::integer, (v_torso->>'max_hp')::integer, (v_torso->>'armor')::integer),
        'visible', true
      ),
      jsonb_build_object(
        'kind', 'special-ring',
        'part', 'Special',
        'fillColor', public.odyssey_overlay_special_color((v_special->>'current_hp')::integer, (v_special->>'max_hp')::integer, (v_special->>'armor')::integer),
        'visible', v_special_visible
      ),
      jsonb_build_object(
        'kind', 'shield-ring',
        'part', 'Shield',
        'fillColor', public.odyssey_overlay_hp_color((v_shield->>'current_hp')::integer, (v_shield->>'max_hp')::integer, (v_shield->>'armor')::integer),
        'visible', v_shield_visible
      )
    )
  );
end;
$body$;

create or replace function public.recompute_odyssey_character_combat_state(p_character_id uuid)
returns jsonb
language plpgsql
as $body$
declare
  v_character record;
  v_body_summary jsonb := '{}'::jsonb;
  v_active_effects jsonb := '[]'::jsonb;
  v_active_penalties jsonb := '[]'::jsonb;
  v_overlay_lines text[] := array[]::text[];
  v_overlay_text text := '';
  v_overlay_data jsonb := '{}'::jsonb;
  v_overlay_manifest jsonb := '{}'::jsonb;
  v_armor_total integer := 0;
  v_state_version integer := 1;
  v_tracker_minor integer := 0;
  v_tracker_serious integer := 0;
  v_is_alive boolean := true;
  v_is_conscious boolean := true;
  v_head jsonb := '{}'::jsonb;
  v_l_arm jsonb := '{}'::jsonb;
  v_r_arm jsonb := '{}'::jsonb;
  v_torso jsonb := '{}'::jsonb;
  v_l_leg jsonb := '{}'::jsonb;
  v_r_leg jsonb := '{}'::jsonb;
  v_shield jsonb := '{}'::jsonb;
  v_special jsonb := '{}'::jsonb;
begin
  select *
  into v_character
  from public.odyssey_characters
  where id = p_character_id;

  if not found then
    raise exception 'Character % was not found', p_character_id;
  end if;

  select
    coalesce(
      jsonb_object_agg(
        b.part_key,
        jsonb_build_object(
          'current_hp', b.current_hp,
          'max_hp', b.max_hp,
          'armor', b.armor,
          'minor', b.minor,
          'serious', b.serious,
          'critical', greatest(0, coalesce(b.critical, greatest(0, b.max_hp - b.current_hp))),
          'max_critical', coalesce(nullif(b.max_critical, 0), b.max_hp),
          'destroyed', b.destroyed,
          'disabled', b.disabled,
          'notes', b.notes
        )
      ),
      '{}'::jsonb
    ),
    coalesce(sum(b.armor), 0)
  into v_body_summary, v_armor_total
  from public.odyssey_character_body_parts b
  where b.character_id = p_character_id;

  select
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'id', e.id,
          'effect_key', e.effect_key,
          'name', e.name,
          'description', e.description,
          'source', e.source,
          'source_character_id', e.source_character_id,
          'duration_type', e.duration_type,
          'rounds_left', e.rounds_left,
          'data', e.data,
          'created_by', e.created_by,
          'created_at', e.created_at
        )
        order by e.created_at desc
      ),
      '[]'::jsonb
    )
  into v_active_effects
  from public.odyssey_character_effects e
  where e.character_id = p_character_id
    and e.is_active = true;

  select
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'effect_id', e.id,
          'effect_key', e.effect_key,
          'effect_name', e.name,
          'kind', penalty->>'kind',
          'skill', penalty->>'skill',
          'part_key', penalty->>'part_key',
          'value', coalesce((penalty->>'value')::integer, 0)
        )
        order by e.created_at desc
      ),
      '[]'::jsonb
    )
  into v_active_penalties
  from public.odyssey_character_effects e
  join lateral jsonb_array_elements(
    case
      when jsonb_typeof(e.data->'penalties') = 'array' then e.data->'penalties'
      else '[]'::jsonb
    end
  ) as penalty on true
  where e.character_id = p_character_id
    and e.is_active = true;

  v_head := coalesce(v_body_summary->'Head', '{}'::jsonb);
  v_l_arm := coalesce(v_body_summary->'L.Arm', '{}'::jsonb);
  v_r_arm := coalesce(v_body_summary->'R.Arm', '{}'::jsonb);
  v_torso := coalesce(v_body_summary->'Torso', '{}'::jsonb);
  v_l_leg := coalesce(v_body_summary->'L.Leg', '{}'::jsonb);
  v_r_leg := coalesce(v_body_summary->'R.Leg', '{}'::jsonb);
  v_shield := coalesce(v_body_summary->'Shield', '{}'::jsonb);
  v_special := coalesce(v_body_summary->'Special', '{}'::jsonb);

  if coalesce((v_shield->>'max_hp')::integer, 0) > 0
     or coalesce((v_shield->>'current_hp')::integer, 0) > 0
     or coalesce((v_shield->>'armor')::integer, 0) > 0 then
    v_overlay_lines := array_append(
      v_overlay_lines,
      format(
        'Shield %s/%s(%s)',
        coalesce(v_shield->>'current_hp', '0'),
        coalesce(v_shield->>'max_hp', '0'),
        coalesce(v_shield->>'armor', '0')
      )
    );
  end if;

  if coalesce((v_special->>'max_hp')::integer, 0) > 0
     or coalesce((v_special->>'current_hp')::integer, 0) > 0
     or coalesce((v_special->>'armor')::integer, 0) > 0 then
    v_overlay_lines := array_append(
      v_overlay_lines,
      format(
        'Special %s/%s(%s)',
        coalesce(v_special->>'current_hp', '0'),
        coalesce(v_special->>'max_hp', '0'),
        coalesce(v_special->>'armor', '0')
      )
    );
  end if;

  v_overlay_lines := array_append(
    v_overlay_lines,
    format(
      'Head %s/%s(%s) | L.Arm %s/%s(%s) | R.Arm %s/%s(%s)',
      coalesce(v_head->>'current_hp', '0'),
      coalesce(v_head->>'max_hp', '0'),
      coalesce(v_head->>'armor', '0'),
      coalesce(v_l_arm->>'current_hp', '0'),
      coalesce(v_l_arm->>'max_hp', '0'),
      coalesce(v_l_arm->>'armor', '0'),
      coalesce(v_r_arm->>'current_hp', '0'),
      coalesce(v_r_arm->>'max_hp', '0'),
      coalesce(v_r_arm->>'armor', '0')
    )
  );

  v_overlay_lines := array_append(
    v_overlay_lines,
    format(
      'Torso %s/%s(%s) | L.Leg %s/%s(%s) | R.Leg %s/%s(%s)',
      coalesce(v_torso->>'current_hp', '0'),
      coalesce(v_torso->>'max_hp', '0'),
      coalesce(v_torso->>'armor', '0'),
      coalesce(v_l_leg->>'current_hp', '0'),
      coalesce(v_l_leg->>'max_hp', '0'),
      coalesce(v_l_leg->>'armor', '0'),
      coalesce(v_r_leg->>'current_hp', '0'),
      coalesce(v_r_leg->>'max_hp', '0'),
      coalesce(v_r_leg->>'armor', '0')
    )
  );

  v_overlay_text := array_to_string(v_overlay_lines, E'\n');
  v_tracker_minor := greatest(0, least(4, coalesce(v_character.tracker_minor, 0)));
  v_tracker_serious := greatest(0, least(2, coalesce(v_character.tracker_serious, 0)));

  v_is_alive :=
    greatest(
      coalesce((v_head->>'current_hp')::integer, 0) +
      coalesce((v_l_arm->>'current_hp')::integer, 0) +
      coalesce((v_r_arm->>'current_hp')::integer, 0) +
      coalesce((v_torso->>'current_hp')::integer, 0) +
      coalesce((v_l_leg->>'current_hp')::integer, 0) +
      coalesce((v_r_leg->>'current_hp')::integer, 0),
      0
    ) > 0;

  v_is_conscious :=
    coalesce((v_head->>'current_hp')::integer, 0) > 0
    and coalesce((v_torso->>'current_hp')::integer, 0) > 0;

  select coalesce(state_version, 0) + 1
  into v_state_version
  from public.odyssey_character_combat_state
  where character_id = p_character_id;

  v_state_version := greatest(1, coalesce(v_state_version, 1));
  v_overlay_manifest := public.odyssey_build_overlay_manifest(
    v_body_summary,
    v_armor_total,
    v_state_version,
    12
  );
  v_overlay_data := jsonb_build_object(
    'lines', to_jsonb(v_overlay_lines)
  ) || v_overlay_manifest;

  insert into public.odyssey_character_combat_state (
    character_id,
    campaign_id,
    room_id,
    body_summary,
    armor_summary,
    active_effects,
    active_penalties,
    overlay_text,
    overlay_data,
    tracker_minor,
    tracker_serious,
    is_alive,
    is_conscious,
    state_version
  )
  values (
    p_character_id,
    coalesce(v_character.campaign_id, ''),
    coalesce(v_character.room_id, ''),
    v_body_summary,
    jsonb_build_object(
      'total', v_armor_total,
      'parts', v_body_summary
    ),
    v_active_effects,
    v_active_penalties,
    v_overlay_text,
    v_overlay_data,
    v_tracker_minor,
    v_tracker_serious,
    v_is_alive,
    v_is_conscious,
    v_state_version
  )
  on conflict (character_id) do update
  set
    campaign_id = excluded.campaign_id,
    room_id = excluded.room_id,
    body_summary = excluded.body_summary,
    armor_summary = excluded.armor_summary,
    active_effects = excluded.active_effects,
    active_penalties = excluded.active_penalties,
    overlay_text = excluded.overlay_text,
    overlay_data = excluded.overlay_data,
    tracker_minor = excluded.tracker_minor,
    tracker_serious = excluded.tracker_serious,
    is_alive = excluded.is_alive,
    is_conscious = excluded.is_conscious,
    state_version = excluded.state_version
  returning state_version into v_state_version;

  update public.odyssey_characters
  set
    active_combat_state_version = v_state_version,
    updated_at = timezone('utc', now())
  where id = p_character_id;

  return jsonb_build_object(
    'character_id', v_character.id,
    'character_key', v_character.character_key,
    'campaign_id', v_character.campaign_id,
    'room_id', v_character.room_id,
    'state_version', v_state_version,
    'tracker_minor', v_tracker_minor,
    'tracker_serious', v_tracker_serious,
    'combat_state', jsonb_build_object(
      'body_summary', v_body_summary,
      'armor_summary', jsonb_build_object(
        'total', v_armor_total,
        'parts', v_body_summary
      ),
      'active_effects', v_active_effects,
      'active_penalties', v_active_penalties,
      'overlay_text', v_overlay_text,
      'overlay_data', v_overlay_data,
      'is_alive', v_is_alive,
      'is_conscious', v_is_conscious,
      'tracker_minor', v_tracker_minor,
      'tracker_serious', v_tracker_serious,
      'state_version', v_state_version
    )
  );
end;
$body$;


create table if not exists public.odyssey_debug_perf_log (
  id bigint generated by default as identity primary key,
  trace_id text not null default '',
  parent_id text not null default '',
  function_name text not null,
  span_name text not null,
  phase_name text not null default '',
  level text not null default 'info',
  duration_ms numeric(12,2) not null default 0,
  character_id uuid null,
  actor_character_id uuid null,
  target_character_id uuid null,
  character_key text not null default '',
  room_id text not null default '',
  scene_id text not null default '',
  metadata jsonb not null default '{}'::jsonb,
  error_code text not null default '',
  created_at timestamptz not null default timezone('utc', now())
);

create index if not exists odyssey_debug_perf_log_created_at_idx
  on public.odyssey_debug_perf_log (created_at desc, id desc);

create index if not exists odyssey_debug_perf_log_trace_id_idx
  on public.odyssey_debug_perf_log (trace_id, created_at desc);

create index if not exists odyssey_debug_perf_log_function_name_idx
  on public.odyssey_debug_perf_log (function_name, created_at desc);

create index if not exists odyssey_debug_perf_log_character_id_idx
  on public.odyssey_debug_perf_log (character_id, created_at desc);

alter table public.odyssey_debug_perf_log enable row level security;

drop policy if exists "odyssey_debug_perf_log_full_access" on public.odyssey_debug_perf_log;
create policy "odyssey_debug_perf_log_full_access"
on public.odyssey_debug_perf_log
for all
to anon, authenticated
using (true)
with check (true);

grant select, insert, delete on public.odyssey_debug_perf_log to anon, authenticated;

create or replace function public.odyssey_debug_perf(
  p_function_name text,
  p_span_name text,
  p_phase_name text default '',
  p_trace_id text default '',
  p_parent_id text default '',
  p_level text default 'info',
  p_duration_ms numeric default 0,
  p_character_id uuid default null,
  p_actor_character_id uuid default null,
  p_target_character_id uuid default null,
  p_character_key text default '',
  p_room_id text default '',
  p_scene_id text default '',
  p_metadata jsonb default '{}'::jsonb,
  p_error_code text default ''
)
returns void
language plpgsql
as $body$
begin
  insert into public.odyssey_debug_perf_log (
    trace_id,
    parent_id,
    function_name,
    span_name,
    phase_name,
    level,
    duration_ms,
    character_id,
    actor_character_id,
    target_character_id,
    character_key,
    room_id,
    scene_id,
    metadata,
    error_code
  )
  values (
    trim(coalesce(p_trace_id, '')),
    trim(coalesce(p_parent_id, '')),
    coalesce(nullif(trim(coalesce(p_function_name, '')), ''), 'unknown_function'),
    coalesce(nullif(trim(coalesce(p_span_name, '')), ''), 'unknown_span'),
    trim(coalesce(p_phase_name, '')),
    case lower(coalesce(p_level, 'info'))
      when 'error' then 'error'
      when 'warn' then 'warn'
      else 'info'
    end,
    greatest(0, coalesce(p_duration_ms, 0)),
    p_character_id,
    p_actor_character_id,
    p_target_character_id,
    trim(coalesce(p_character_key, '')),
    trim(coalesce(p_room_id, '')),
    trim(coalesce(p_scene_id, '')),
    case
      when jsonb_typeof(p_metadata) = 'object' then p_metadata
      when p_metadata is null then '{}'::jsonb
      else jsonb_build_object('value', p_metadata)
    end,
    trim(coalesce(p_error_code, ''))
  );
end;
$body$;

create or replace function public.get_odyssey_debug_perf_log(
  p_limit integer default 200,
  p_trace_id text default null
)
returns table (
  id bigint,
  trace_id text,
  parent_id text,
  function_name text,
  span_name text,
  phase_name text,
  level text,
  duration_ms numeric,
  character_id uuid,
  actor_character_id uuid,
  target_character_id uuid,
  character_key text,
  room_id text,
  scene_id text,
  metadata jsonb,
  error_code text,
  created_at timestamptz
)
language sql
as $body$
  select
    log.id,
    log.trace_id,
    log.parent_id,
    log.function_name,
    log.span_name,
    log.phase_name,
    log.level,
    log.duration_ms,
    log.character_id,
    log.actor_character_id,
    log.target_character_id,
    log.character_key,
    log.room_id,
    log.scene_id,
    log.metadata,
    log.error_code,
    log.created_at
  from public.odyssey_debug_perf_log log
  where (
    coalesce(nullif(trim(coalesce(p_trace_id, '')), ''), '') = ''
    or log.trace_id = trim(p_trace_id)
  )
  order by log.created_at desc, log.id desc
  limit greatest(1, least(coalesce(p_limit, 200), 500));
$body$;

grant execute on function public.odyssey_debug_perf(
  text,
  text,
  text,
  text,
  text,
  text,
  numeric,
  uuid,
  uuid,
  uuid,
  text,
  text,
  text,
  jsonb,
  text
) to anon, authenticated;

grant execute on function public.get_odyssey_debug_perf_log(integer, text) to anon, authenticated;

create or replace function public.upsert_odyssey_character_sheet(p_payload jsonb)
returns jsonb
language plpgsql
as $body$
declare
  v_trace_id text := trim(coalesce(p_payload->>'trace_id', ''));
  v_function_name constant text := 'upsert_odyssey_character_sheet';
  v_total_started_at timestamptz := clock_timestamp();
  v_phase_started_at timestamptz := clock_timestamp();
  v_duration_ms numeric(12,2) := 0;
  v_row_count integer := 0;
  v_character_key text := trim(coalesce(p_payload->>'character_key', ''));
  v_character_id uuid;
  v_character_bucket text := case lower(coalesce(p_payload->>'character_bucket', 'player'))
    when 'npc_template' then 'npc_template'
    when 'npc_active' then 'npc_active'
    else 'player'
  end;
  v_source_template_key text := trim(coalesce(p_payload->>'source_template_key', ''));
  v_enabled boolean := coalesce((p_payload->>'enabled')::boolean, true);
  v_tracker_minor integer := greatest(0, least(4, coalesce((p_payload->>'tracker_minor')::integer, 0)));
  v_tracker_serious integer := greatest(0, least(2, coalesce((p_payload->>'tracker_serious')::integer, 0)));
  v_owner_player_id text := coalesce(p_payload->>'owner_player_id', '');
  v_owner_player_name text := coalesce(p_payload->>'owner_player_name', '');
  v_campaign_id text := trim(coalesce(p_payload->>'campaign_id', ''));
  v_room_id text := trim(coalesce(p_payload->>'room_id', ''));
  v_resources jsonb := case
    when jsonb_typeof(p_payload->'resources') = 'object' then p_payload->'resources'
    else '{}'::jsonb
  end;
  v_result jsonb := '{}'::jsonb;
begin
  v_phase_started_at := clock_timestamp();
  if v_character_key = '' then
    raise exception 'character_key is required';
  end if;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'validate',
    p_phase_name => 'validate',
    p_trace_id => v_trace_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'character_bucket', v_character_bucket,
      'enabled', v_enabled
    )
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_characters (
    character_key,
    character_bucket,
    source_template_key,
    enabled,
    tracker_minor,
    tracker_serious,
    owner_player_id,
    owner_player_name,
    campaign_id,
    room_id,
    resources,
    is_deleted
  )
  values (
    v_character_key,
    v_character_bucket,
    v_source_template_key,
    v_enabled,
    v_tracker_minor,
    v_tracker_serious,
    v_owner_player_id,
    v_owner_player_name,
    v_campaign_id,
    v_room_id,
    v_resources,
    false
  )
  on conflict (character_key) do update
  set
    character_bucket = excluded.character_bucket,
    source_template_key = excluded.source_template_key,
    enabled = excluded.enabled,
    tracker_minor = excluded.tracker_minor,
    tracker_serious = excluded.tracker_serious,
    owner_player_id = excluded.owner_player_id,
    owner_player_name = excluded.owner_player_name,
    campaign_id = excluded.campaign_id,
    room_id = excluded.room_id,
    resources = excluded.resources,
    is_deleted = false
  returning id into v_character_id;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'upsert-character',
    p_phase_name => 'upsert-character',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'character_bucket', v_character_bucket,
      'tracker_minor', v_tracker_minor,
      'tracker_serious', v_tracker_serious
    )
  );

  v_phase_started_at := clock_timestamp();
  delete from public.odyssey_character_characteristics where character_id = v_character_id;
  delete from public.odyssey_character_skills where character_id = v_character_id;
  delete from public.odyssey_character_weapons where character_id = v_character_id;
  delete from public.odyssey_character_body_parts where character_id = v_character_id;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clear-child-records',
    p_phase_name => 'clear-child-records',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_characteristics (
    character_id,
    key,
    label,
    value,
    sort_order
  )
  select
    v_character_id,
    trim(coalesce(entry.value->>'key', '')),
    coalesce(nullif(trim(entry.value->>'label'), ''), trim(coalesce(entry.value->>'key', ''))),
    greatest(0, least(20, coalesce((entry.value->>'value')::integer, 0))),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'characteristics') = 'array' then p_payload->'characteristics'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality)
  where trim(coalesce(entry.value->>'key', '')) <> '';
  get diagnostics v_row_count = row_count;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'insert-characteristics',
    p_phase_name => 'insert-characteristics',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object('row_count', v_row_count)
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_skills (
    character_id,
    name,
    value,
    category,
    strength_bonus,
    sort_order
  )
  select
    v_character_id,
    trim(coalesce(entry.value->>'name', '')),
    greatest(0, least(10, coalesce((entry.value->>'value')::integer, 0))),
    case lower(coalesce(entry.value->>'category', 'applied'))
      when 'combat' then 'combat'
      when 'abilities' then 'abilities'
      else 'applied'
    end,
    coalesce((entry.value->>'strength_bonus')::boolean, false),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'skills') = 'array' then p_payload->'skills'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality)
  where trim(coalesce(entry.value->>'name', '')) <> '';
  get diagnostics v_row_count = row_count;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'insert-skills',
    p_phase_name => 'insert-skills',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object('row_count', v_row_count)
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_weapons (
    character_id,
    weapon_kind,
    name,
    damage,
    accuracy,
    ammo_current,
    ammo_max,
    sort_order
  )
  select
    v_character_id,
    case lower(coalesce(entry.value->>'weapon_kind', 'melee'))
      when 'ranged' then 'ranged'
      else 'melee'
    end,
    coalesce(nullif(trim(entry.value->>'name'), ''), 'Weapon'),
    greatest(-99, least(99, coalesce((entry.value->>'damage')::integer, 0))),
    greatest(-99, least(99, coalesce((entry.value->>'accuracy')::integer, 0))),
    greatest(0, coalesce((entry.value->>'ammoCurrent')::integer, (entry.value->>'ammo_current')::integer, 0)),
    greatest(0, coalesce((entry.value->>'ammoMax')::integer, (entry.value->>'ammo_max')::integer, 0)),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'weapons') = 'array' then p_payload->'weapons'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality);
  get diagnostics v_row_count = row_count;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'insert-weapons',
    p_phase_name => 'insert-weapons',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object('row_count', v_row_count)
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_body_parts (
    character_id,
    part_key,
    current_hp,
    max_hp,
    armor,
    minor,
    serious,
    critical,
    max_critical,
    destroyed,
    disabled,
    notes,
    sort_order
  )
  select
    v_character_id,
    trim(coalesce(entry.value->>'part_key', '')),
    greatest(0, coalesce((entry.value->>'current_hp')::integer, 0)),
    greatest(0, coalesce((entry.value->>'max_hp')::integer, 0)),
    greatest(0, coalesce((entry.value->>'armor')::integer, 0)),
    greatest(0, least(3, coalesce((entry.value->>'minor')::integer, 0))),
    greatest(0, least(1, coalesce((entry.value->>'serious')::integer, 0))),
    greatest(0, coalesce((entry.value->>'critical')::integer, 0)),
    greatest(0, coalesce((entry.value->>'max_critical')::integer, (entry.value->>'max_hp')::integer, 0)),
    coalesce((entry.value->>'destroyed')::boolean, false),
    coalesce((entry.value->>'disabled')::boolean, false),
    coalesce(entry.value->>'notes', ''),
    coalesce((entry.value->>'sort_order')::integer, entry.ordinality - 1)
  from jsonb_array_elements(
    case
      when jsonb_typeof(p_payload->'body_parts') = 'array' then p_payload->'body_parts'
      else '[]'::jsonb
    end
  ) with ordinality as entry(value, ordinality)
  where trim(coalesce(entry.value->>'part_key', '')) in ('Head', 'L.Arm', 'R.Arm', 'Torso', 'L.Leg', 'R.Leg', 'Shield', 'Special');
  get diagnostics v_row_count = row_count;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'insert-body-parts',
    p_phase_name => 'insert-body-parts',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object('row_count', v_row_count)
  );

  v_phase_started_at := clock_timestamp();
  perform public.recompute_odyssey_character_combat_state(v_character_id);
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'recompute-combat-state',
    p_phase_name => 'recompute-combat-state',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms
  );

  v_phase_started_at := clock_timestamp();
  v_result := public.get_odyssey_character_sheet(v_character_key);
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'return-character-sheet',
    p_phase_name => 'return-character-sheet',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms
  );

  v_duration_ms := (extract(epoch from clock_timestamp() - v_total_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'total',
    p_phase_name => 'total',
    p_trace_id => v_trace_id,
    p_character_id => v_character_id,
    p_character_key => v_character_key,
    p_room_id => v_room_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'characteristics_count', case when jsonb_typeof(p_payload->'characteristics') = 'array' then jsonb_array_length(p_payload->'characteristics') else 0 end,
      'skills_count', case when jsonb_typeof(p_payload->'skills') = 'array' then jsonb_array_length(p_payload->'skills') else 0 end,
      'weapons_count', case when jsonb_typeof(p_payload->'weapons') = 'array' then jsonb_array_length(p_payload->'weapons') else 0 end,
      'body_parts_count', case when jsonb_typeof(p_payload->'body_parts') = 'array' then jsonb_array_length(p_payload->'body_parts') else 0 end
    )
  );

  return v_result;
exception
  when others then
    perform public.odyssey_debug_perf(
      p_function_name => v_function_name,
      p_span_name => 'error',
      p_phase_name => 'error',
      p_trace_id => v_trace_id,
      p_character_id => v_character_id,
      p_character_key => v_character_key,
      p_room_id => v_room_id,
      p_level => 'error',
      p_duration_ms => (extract(epoch from clock_timestamp() - v_total_started_at) * 1000)::numeric(12,2),
      p_metadata => jsonb_build_object('message', sqlerrm),
      p_error_code => sqlstate
    );
    raise;
end;
$body$;

create or replace function public.apply_damage(p_payload jsonb)
returns jsonb
language plpgsql
as $body$
declare
  v_trace_id text := trim(coalesce(p_payload->>'trace_id', ''));
  v_function_name constant text := 'apply_damage';
  v_total_started_at timestamptz := clock_timestamp();
  v_phase_started_at timestamptz := clock_timestamp();
  v_duration_ms numeric(12,2) := 0;
  v_target_character_id uuid := nullif(trim(coalesce(p_payload->>'target_character_id', '')), '')::uuid;
  v_actor_character_id uuid := nullif(trim(coalesce(p_payload->>'actor_character_id', '')), '')::uuid;
  v_campaign_id text := trim(coalesce(p_payload->>'campaign_id', ''));
  v_room_id text := trim(coalesce(p_payload->>'room_id', ''));
  v_scene_id text := trim(coalesce(p_payload->>'scene_id', ''));
  v_encounter_id uuid := nullif(trim(coalesce(p_payload->>'encounter_id', '')), '')::uuid;
  v_target_part text := coalesce(nullif(trim(coalesce(p_payload->>'target_part', '')), ''), 'Torso');
  v_damage_kind text := lower(coalesce(p_payload->>'damage_kind', 'minor'));
  v_amount integer := greatest(0, coalesce((p_payload->>'amount')::integer, 1));
  v_created_by text := trim(coalesce(p_payload->>'created_by', ''));
  v_target_row public.odyssey_character_body_parts%rowtype;
  v_special_row public.odyssey_character_body_parts%rowtype;
  v_target_result jsonb := '{}'::jsonb;
  v_special_result jsonb := '{}'::jsonb;
  v_overflow_crit integer := 0;
  v_special_hp_loss integer := 0;
  v_special_crit_applied integer := 0;
  v_recomputed jsonb := '{}'::jsonb;
  v_message text := '';
  v_log_entry jsonb := '{}'::jsonb;
begin
  v_phase_started_at := clock_timestamp();
  if v_target_character_id is null then
    raise exception 'target_character_id is required';
  end if;

  if v_target_part not in ('Head', 'L.Arm', 'R.Arm', 'Torso', 'L.Leg', 'R.Leg', 'Shield', 'Special') then
    raise exception 'target_part % is invalid', v_target_part;
  end if;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'validate',
    p_phase_name => 'validate',
    p_trace_id => v_trace_id,
    p_target_character_id => v_target_character_id,
    p_actor_character_id => v_actor_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'target_part', v_target_part,
      'damage_kind', v_damage_kind,
      'amount', v_amount
    )
  );

  v_phase_started_at := clock_timestamp();
  select *
  into v_target_row
  from public.odyssey_character_body_parts
  where character_id = v_target_character_id
    and part_key = v_target_part;

  if not found then
    raise exception 'Target part % was not found for character %', v_target_part, v_target_character_id;
  end if;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'load-target-part',
    p_phase_name => 'load-target-part',
    p_trace_id => v_trace_id,
    p_target_character_id => v_target_character_id,
    p_actor_character_id => v_actor_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'target_part', v_target_part,
      'current_hp', v_target_row.current_hp,
      'armor', v_target_row.armor
    )
  );

  v_phase_started_at := clock_timestamp();
  select *
  into v_special_row
  from public.odyssey_character_body_parts
  where character_id = v_target_character_id
    and part_key = 'Special';
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'load-special-part',
    p_phase_name => 'load-special-part',
    p_trace_id => v_trace_id,
    p_target_character_id => v_target_character_id,
    p_actor_character_id => v_actor_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'special_found', found,
      'special_current_hp', coalesce(v_special_row.current_hp, 0),
      'special_max_hp', coalesce(v_special_row.max_hp, 0)
    )
  );

  if v_target_part <> 'Special'
     and found
     and v_special_row.max_hp > 0
     and v_special_row.current_hp > 0 then
    v_phase_started_at := clock_timestamp();
    v_special_result := public.odyssey_apply_part_damage(to_jsonb(v_special_row), v_damage_kind, v_amount);
    v_special_hp_loss := greatest(0, v_special_row.current_hp - coalesce((v_special_result->>'current_hp')::integer, 0));
    v_special_crit_applied := greatest(0, coalesce((v_special_result->>'crit_applied')::integer, 0));
    v_overflow_crit := greatest(0, v_special_crit_applied - v_special_hp_loss);

    update public.odyssey_character_body_parts
    set
      current_hp = coalesce((v_special_result->>'current_hp')::integer, current_hp),
      minor = coalesce((v_special_result->>'minor')::integer, minor),
      serious = coalesce((v_special_result->>'serious')::integer, serious),
      critical = coalesce((v_special_result->>'critical')::integer, critical),
      max_critical = coalesce((v_special_result->>'max_critical')::integer, max_critical),
      destroyed = coalesce((v_special_result->>'destroyed')::boolean, destroyed),
      disabled = coalesce((v_special_result->>'disabled')::boolean, disabled),
      updated_at = timezone('utc', now())
    where character_id = v_target_character_id
      and part_key = 'Special';
    v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
    perform public.odyssey_debug_perf(
      p_function_name => v_function_name,
      p_span_name => 'apply-special-part',
      p_phase_name => 'apply-special-part',
      p_trace_id => v_trace_id,
      p_target_character_id => v_target_character_id,
      p_actor_character_id => v_actor_character_id,
      p_room_id => v_room_id,
      p_scene_id => v_scene_id,
      p_duration_ms => v_duration_ms,
      p_metadata => jsonb_build_object(
        'special_hp_loss', v_special_hp_loss,
        'special_crit_applied', v_special_crit_applied,
        'overflow_crit', v_overflow_crit
      )
    );

    if v_overflow_crit > 0 then
      v_target_result := public.odyssey_apply_part_damage(to_jsonb(v_target_row), 'critical', v_overflow_crit);
    else
      v_target_result := to_jsonb(v_target_row) || jsonb_build_object('crit_applied', 0);
    end if;
  else
    v_phase_started_at := clock_timestamp();
    v_target_result := public.odyssey_apply_part_damage(to_jsonb(v_target_row), v_damage_kind, v_amount);
    v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
    perform public.odyssey_debug_perf(
      p_function_name => v_function_name,
      p_span_name => 'apply-target-part',
      p_phase_name => 'apply-target-part',
      p_trace_id => v_trace_id,
      p_target_character_id => v_target_character_id,
      p_actor_character_id => v_actor_character_id,
      p_room_id => v_room_id,
      p_scene_id => v_scene_id,
      p_duration_ms => v_duration_ms,
      p_metadata => jsonb_build_object(
        'target_part', v_target_part,
        'damage_kind', v_damage_kind,
        'amount', v_amount
      )
    );
  end if;

  v_phase_started_at := clock_timestamp();
  update public.odyssey_character_body_parts
  set
    current_hp = coalesce((v_target_result->>'current_hp')::integer, current_hp),
    minor = coalesce((v_target_result->>'minor')::integer, minor),
    serious = coalesce((v_target_result->>'serious')::integer, serious),
    critical = coalesce((v_target_result->>'critical')::integer, critical),
    max_critical = coalesce((v_target_result->>'max_critical')::integer, max_critical),
    destroyed = coalesce((v_target_result->>'destroyed')::boolean, destroyed),
    disabled = coalesce((v_target_result->>'disabled')::boolean, disabled),
    updated_at = timezone('utc', now())
  where character_id = v_target_character_id
    and part_key = v_target_part;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'persist-target-part',
    p_phase_name => 'persist-target-part',
    p_trace_id => v_trace_id,
    p_target_character_id => v_target_character_id,
    p_actor_character_id => v_actor_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'target_part', v_target_part,
      'current_hp', coalesce((v_target_result->>'current_hp')::integer, 0),
      'critical', coalesce((v_target_result->>'critical')::integer, 0)
    )
  );

  v_phase_started_at := clock_timestamp();
  v_recomputed := public.recompute_odyssey_character_combat_state(v_target_character_id);
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'recompute-combat-state',
    p_phase_name => 'recompute-combat-state',
    p_trace_id => v_trace_id,
    p_target_character_id => v_target_character_id,
    p_actor_character_id => v_actor_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms
  );

  v_message := format(
    'Damage applied to %s (%s x%s).',
    v_target_part,
    v_damage_kind,
    v_amount
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_combat_log (
    campaign_id,
    room_id,
    scene_id,
    encounter_id,
    actor_character_id,
    target_character_id,
    event_type,
    message,
    data,
    created_by
  )
  values (
    v_campaign_id,
    v_room_id,
    v_scene_id,
    v_encounter_id,
    v_actor_character_id,
    v_target_character_id,
    'damage',
    v_message,
    jsonb_build_object(
      'target_part', v_target_part,
      'damage_kind', v_damage_kind,
      'amount', v_amount,
      'attack_result', coalesce(p_payload->'attack_result', '{}'::jsonb)
    ),
    v_created_by
  )
  returning jsonb_build_object(
    'event_type', event_type,
    'message', message,
    'created_at', created_at,
    'target_character_id', target_character_id,
    'actor_character_id', actor_character_id
  ) into v_log_entry;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'write-combat-log',
    p_phase_name => 'write-combat-log',
    p_trace_id => v_trace_id,
    p_target_character_id => v_target_character_id,
    p_actor_character_id => v_actor_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms
  );

  v_duration_ms := (extract(epoch from clock_timestamp() - v_total_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'total',
    p_phase_name => 'total',
    p_trace_id => v_trace_id,
    p_target_character_id => v_target_character_id,
    p_actor_character_id => v_actor_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'target_part', v_target_part,
      'damage_kind', v_damage_kind,
      'amount', v_amount,
      'overflow_crit', v_overflow_crit
    )
  );

  return jsonb_build_object(
    'ok', true,
    'changed_character_ids', jsonb_build_array(v_target_character_id),
    'target_character_id', v_target_character_id,
    'combat_state', v_recomputed->'combat_state',
    'log_entry', v_log_entry
  );
exception
  when others then
    perform public.odyssey_debug_perf(
      p_function_name => v_function_name,
      p_span_name => 'error',
      p_phase_name => 'error',
      p_trace_id => v_trace_id,
      p_target_character_id => v_target_character_id,
      p_actor_character_id => v_actor_character_id,
      p_room_id => v_room_id,
      p_scene_id => v_scene_id,
      p_level => 'error',
      p_duration_ms => (extract(epoch from clock_timestamp() - v_total_started_at) * 1000)::numeric(12,2),
      p_metadata => jsonb_build_object(
        'message', sqlerrm,
        'target_part', v_target_part,
        'damage_kind', v_damage_kind,
        'amount', v_amount
      ),
      p_error_code => sqlstate
    );
    raise;
end;
$body$;

grant execute on function public.upsert_odyssey_character_sheet(jsonb) to anon, authenticated;
grant execute on function public.apply_damage(jsonb) to anon, authenticated;


create or replace function public.clone_odyssey_npc_active(p_payload jsonb)
returns jsonb
language plpgsql
as $body$
declare
  v_trace_id text := trim(coalesce(p_payload->>'trace_id', ''));
  v_function_name constant text := 'clone_odyssey_npc_active';
  v_total_started_at timestamptz := clock_timestamp();
  v_phase_started_at timestamptz := clock_timestamp();
  v_duration_ms numeric(12,2) := 0;
  v_source_character_id uuid := nullif(trim(coalesce(p_payload->>'source_character_id', '')), '')::uuid;
  v_source record;
  v_new_character_id uuid;
  v_new_character_key text := trim(coalesce(p_payload->>'new_character_key', ''));
  v_new_character_bucket text := case lower(coalesce(p_payload->>'new_character_bucket', 'npc_active'))
    when 'npc_active' then 'npc_active'
    else 'npc_active'
  end;
  v_source_template_key text := trim(coalesce(p_payload->>'source_template_key', ''));
  v_campaign_id text := trim(coalesce(p_payload->>'campaign_id', ''));
  v_room_id text := trim(coalesce(p_payload->>'room_id', ''));
  v_scene_id text := trim(coalesce(p_payload->>'scene_id', ''));
  v_token_id text := trim(coalesce(p_payload->>'token_id', ''));
  v_token_name text := trim(coalesce(p_payload->>'token_name', ''));
  v_token_layer text := trim(coalesce(p_payload->>'token_layer', 'CHARACTER'));
  v_owner_player_id text := trim(coalesce(p_payload->>'owner_player_id', ''));
  v_owner_player_name text := trim(coalesce(p_payload->>'owner_player_name', ''));
  v_recomputed jsonb := '{}'::jsonb;
  v_state_version integer := 0;
  v_token_link jsonb := '{}'::jsonb;
begin
  v_phase_started_at := clock_timestamp();
  if v_source_character_id is null then
    raise exception 'source_character_id is required';
  end if;
  if v_new_character_key = '' then
    raise exception 'new_character_key is required';
  end if;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.start',
    p_phase_name => 'clone_active_npc.start',
    p_trace_id => v_trace_id,
    p_character_id => v_source_character_id,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'new_character_key', v_new_character_key,
      'token_id', v_token_id
    )
  );

  v_phase_started_at := clock_timestamp();
  select *
  into v_source
  from public.odyssey_characters
  where id = v_source_character_id
    and is_deleted = false;

  if not found then
    raise exception 'Source character % was not found', v_source_character_id;
  end if;

  if v_source_template_key = '' then
    v_source_template_key := coalesce(nullif(v_source.source_template_key, ''), v_source.character_key, '');
  end if;
  if v_campaign_id = '' then
    v_campaign_id := coalesce(v_source.campaign_id, '');
  end if;
  if v_room_id = '' then
    v_room_id := coalesce(v_source.room_id, '');
  end if;
  if v_owner_player_id = '' then
    v_owner_player_id := coalesce(v_source.owner_player_id, '');
  end if;
  if v_owner_player_name = '' then
    v_owner_player_name := coalesce(v_source.owner_player_name, '');
  end if;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.load_source',
    p_phase_name => 'clone_active_npc.load_source',
    p_trace_id => v_trace_id,
    p_character_id => v_source_character_id,
    p_character_key => v_source.character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'source_character_bucket', v_source.character_bucket,
      'source_template_key', v_source_template_key
    )
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_characters (
    character_key,
    character_bucket,
    source_template_key,
    enabled,
    tracker_minor,
    tracker_serious,
    owner_player_id,
    owner_player_name,
    campaign_id,
    room_id,
    resources,
    active_combat_state_version,
    is_deleted
  )
  values (
    v_new_character_key,
    v_new_character_bucket,
    v_source_template_key,
    v_source.enabled,
    v_source.tracker_minor,
    v_source.tracker_serious,
    v_owner_player_id,
    v_owner_player_name,
    v_campaign_id,
    v_room_id,
    coalesce(v_source.resources, '{}'::jsonb),
    0,
    false
  )
  returning id into v_new_character_id;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.insert_character',
    p_phase_name => 'clone_active_npc.insert_character',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'source_character_id', v_source_character_id,
      'source_character_key', v_source.character_key
    )
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_characteristics (
    character_id,
    key,
    label,
    value,
    sort_order
  )
  select
    v_new_character_id,
    c.key,
    c.label,
    c.value,
    c.sort_order
  from public.odyssey_character_characteristics c
  where c.character_id = v_source_character_id;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.copy_characteristics',
    p_phase_name => 'clone_active_npc.copy_characteristics',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_skills (
    character_id,
    name,
    value,
    category,
    strength_bonus,
    sort_order
  )
  select
    v_new_character_id,
    s.name,
    s.value,
    s.category,
    s.strength_bonus,
    s.sort_order
  from public.odyssey_character_skills s
  where s.character_id = v_source_character_id;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.copy_skills',
    p_phase_name => 'clone_active_npc.copy_skills',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_weapons (
    character_id,
    weapon_kind,
    name,
    damage,
    accuracy,
    ammo_current,
    ammo_max,
    sort_order
  )
  select
    v_new_character_id,
    w.weapon_kind,
    w.name,
    w.damage,
    w.accuracy,
    w.ammo_current,
    w.ammo_max,
    w.sort_order
  from public.odyssey_character_weapons w
  where w.character_id = v_source_character_id;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.copy_weapons',
    p_phase_name => 'clone_active_npc.copy_weapons',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_character_body_parts (
    character_id,
    part_key,
    current_hp,
    max_hp,
    armor,
    minor,
    serious,
    critical,
    max_critical,
    destroyed,
    disabled,
    notes,
    sort_order
  )
  select
    v_new_character_id,
    b.part_key,
    b.current_hp,
    b.max_hp,
    b.armor,
    b.minor,
    b.serious,
    coalesce(b.critical, greatest(0, b.max_hp - b.current_hp)),
    coalesce(nullif(b.max_critical, 0), b.max_hp),
    b.destroyed,
    b.disabled,
    b.notes,
    b.sort_order
  from public.odyssey_character_body_parts b
  where b.character_id = v_source_character_id;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.copy_body_parts',
    p_phase_name => 'clone_active_npc.copy_body_parts',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms
  );

  v_phase_started_at := clock_timestamp();
  v_recomputed := public.recompute_odyssey_character_combat_state(v_new_character_id);
  v_state_version := greatest(0, coalesce((v_recomputed->>'state_version')::integer, 0));
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.recompute_combat_state',
    p_phase_name => 'clone_active_npc.recompute_combat_state',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms
  );

  v_phase_started_at := clock_timestamp();
  insert into public.odyssey_token_links (
    campaign_id,
    room_id,
    scene_id,
    token_id,
    character_id,
    character_key,
    token_name,
    token_layer,
    is_active,
    last_seen_at
  )
  values (
    v_campaign_id,
    v_room_id,
    v_scene_id,
    v_token_id,
    v_new_character_id,
    v_new_character_key,
    v_token_name,
    v_token_layer,
    true,
    timezone('utc', now())
  )
  on conflict (room_id, scene_id, token_id) do update
  set
    campaign_id = excluded.campaign_id,
    character_id = excluded.character_id,
    character_key = excluded.character_key,
    token_name = excluded.token_name,
    token_layer = excluded.token_layer,
    is_active = excluded.is_active,
    last_seen_at = excluded.last_seen_at;
  v_duration_ms := (extract(epoch from clock_timestamp() - v_phase_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.upsert_token_link',
    p_phase_name => 'clone_active_npc.upsert_token_link',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'token_id', v_token_id,
      'token_name', v_token_name
    )
  );

  v_token_link := jsonb_build_object(
    'linked', true,
    'character_id', v_new_character_id,
    'character_key', v_new_character_key,
    'character_bucket', v_new_character_bucket,
    'source_template_key', v_source_template_key,
    'campaign_id', v_campaign_id,
    'room_id', v_room_id,
    'scene_id', v_scene_id,
    'state_version', v_state_version,
    'owner_player_id', v_owner_player_id,
    'owner_player_name', v_owner_player_name
  );

  v_duration_ms := (extract(epoch from clock_timestamp() - v_total_started_at) * 1000)::numeric(12,2);
  perform public.odyssey_debug_perf(
    p_function_name => v_function_name,
    p_span_name => 'clone_active_npc.done',
    p_phase_name => 'clone_active_npc.done',
    p_trace_id => v_trace_id,
    p_character_id => v_new_character_id,
    p_character_key => v_new_character_key,
    p_room_id => v_room_id,
    p_scene_id => v_scene_id,
    p_duration_ms => v_duration_ms,
    p_metadata => jsonb_build_object(
      'source_character_id', v_source_character_id,
      'source_character_key', v_source.character_key,
      'token_id', v_token_id
    )
  );

  return jsonb_build_object(
    'ok', true,
    'source_character_id', v_source_character_id,
    'source_character_key', v_source.character_key,
    'character_id', v_new_character_id,
    'character_key', v_new_character_key,
    'campaign_id', v_campaign_id,
    'room_id', v_room_id,
    'combat_state', coalesce(v_recomputed->'combat_state', '{}'::jsonb),
    'token_link', v_token_link
  );
exception
  when others then
    perform public.odyssey_debug_perf(
      p_function_name => v_function_name,
      p_span_name => 'clone_active_npc.error',
      p_phase_name => 'clone_active_npc.error',
      p_trace_id => v_trace_id,
      p_character_id => v_new_character_id,
      p_character_key => v_new_character_key,
      p_room_id => v_room_id,
      p_scene_id => v_scene_id,
      p_level => 'error',
      p_duration_ms => (extract(epoch from clock_timestamp() - v_total_started_at) * 1000)::numeric(12,2),
      p_metadata => jsonb_build_object(
        'message', sqlerrm,
        'source_character_id', coalesce(v_source_character_id::text, ''),
        'token_id', v_token_id
      ),
      p_error_code => sqlstate
    );
    raise;
end;
$body$;

grant execute on function public.clone_odyssey_npc_active(jsonb) to anon, authenticated;


create extension if not exists pgcrypto;

drop function if exists public.get_odyssey_character_sheet(text);
drop function if exists public.upsert_odyssey_character_sheet(jsonb);
drop function if exists public.recompute_odyssey_character_combat_state(uuid);
drop function if exists public.apply_damage(jsonb);
drop function if exists public.heal_damage(jsonb);
drop function if exists public.add_effect(jsonb);
drop function if exists public.remove_effect(jsonb);
drop function if exists public.roll_initiative(jsonb);
drop function if exists public.advance_turn(jsonb);
drop function if exists public.clone_odyssey_npc_active(jsonb);
drop function if exists public.get_character_rule_sheet(uuid);
drop function if exists public.initialize_character_rule_defaults(uuid);

drop table if exists public.odyssey_character_perks cascade;
drop table if exists public.odyssey_perk_defs cascade;
drop table if exists public.odyssey_skill_level_requirements cascade;
drop table if exists public.odyssey_character_skills cascade;
drop table if exists public.odyssey_skill_defs cascade;
drop table if exists public.odyssey_character_attributes cascade;
drop table if exists public.odyssey_attribute_defs cascade;
drop table if exists public.odyssey_character_body_parts cascade;
drop table if exists public.odyssey_body_part_defs cascade;
drop table if exists public.odyssey_character_characteristics cascade;

create table if not exists public.odyssey_attribute_defs (
  id uuid primary key default gen_random_uuid(),
  code text not null unique,
  name text not null,
  default_value integer not null default 8 check (default_value >= 0),
  max_value integer not null default 15 check (max_value >= default_value),
  cost_per_level integer not null default 2 check (cost_per_level >= 0),
  description text,
  sort_order integer not null default 0,
  is_custom boolean not null default false,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.odyssey_character_attributes (
  id uuid primary key default gen_random_uuid(),
  character_id uuid not null references public.odyssey_characters(id) on delete cascade,
  attribute_def_id uuid not null references public.odyssey_attribute_defs(id) on delete cascade,
  value integer not null check (value >= 0),
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  unique (character_id, attribute_def_id)
);

create index if not exists odyssey_character_attributes_character_idx
  on public.odyssey_character_attributes (character_id);

create index if not exists odyssey_character_attributes_attribute_idx
  on public.odyssey_character_attributes (attribute_def_id);

create table if not exists public.odyssey_skill_defs (
  id uuid primary key default gen_random_uuid(),
  code text not null unique,
  name text not null,
  category text not null check (category in ('combat', 'applied', 'survival', 'vehicle', 'social', 'passive', 'psionic', 'custom')),
  max_level integer not null check (max_level in (1, 3, 5)),
  main_attribute_id uuid references public.odyssey_attribute_defs(id),
  secondary_attribute_id uuid references public.odyssey_attribute_defs(id),
  description text,
  tags jsonb not null default '[]'::jsonb check (jsonb_typeof(tags) = 'array'),
  is_custom boolean not null default false,
  sort_order integer not null default 0,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.odyssey_character_skills (
  id uuid primary key default gen_random_uuid(),
  character_id uuid not null references public.odyssey_characters(id) on delete cascade,
  skill_def_id uuid not null references public.odyssey_skill_defs(id) on delete cascade,
  level integer not null default 0 check (level >= 0),
  governing_attribute_def_id uuid references public.odyssey_attribute_defs(id) on delete set null,
  custom_name text,
  notes text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  unique (character_id, skill_def_id)
);

create index if not exists odyssey_character_skills_character_idx
  on public.odyssey_character_skills (character_id);

create index if not exists odyssey_character_skills_skill_idx
  on public.odyssey_character_skills (skill_def_id);

create index if not exists odyssey_character_skills_governing_attribute_idx
  on public.odyssey_character_skills (governing_attribute_def_id);

create table if not exists public.odyssey_skill_level_requirements (
  id uuid primary key default gen_random_uuid(),
  skill_def_id uuid not null references public.odyssey_skill_defs(id) on delete cascade,
  level integer not null check (level >= 0),
  main_attribute_required integer,
  secondary_attribute_required integer,
  requires_critical_successes boolean not null default false,
  notes text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  unique (skill_def_id, level)
);

create index if not exists odyssey_skill_level_requirements_skill_idx
  on public.odyssey_skill_level_requirements (skill_def_id);

create table if not exists public.odyssey_perk_defs (
  id uuid primary key default gen_random_uuid(),
  skill_def_id uuid references public.odyssey_skill_defs(id) on delete set null,
  code text not null unique,
  name text not null,
  required_skill_level integer not null default 0 check (required_skill_level >= 0),
  description text,
  effect_type text check (
    effect_type is null
    or effect_type in (
      'add_modifier',
      'remove_modifier',
      'ignore_penalty',
      'modify_fire_mode',
      'modify_range_penalty',
      'grant_advantage',
      'replace_defense_skill',
      'grant_reaction',
      'special_action'
    )
  ),
  effect_data jsonb not null default '{}'::jsonb,
  tags jsonb not null default '[]'::jsonb check (jsonb_typeof(tags) = 'array'),
  is_custom boolean not null default false,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.odyssey_character_perks (
  id uuid primary key default gen_random_uuid(),
  character_id uuid not null references public.odyssey_characters(id) on delete cascade,
  perk_def_id uuid not null references public.odyssey_perk_defs(id) on delete cascade,
  acquired_at timestamptz not null default timezone('utc', now()),
  notes text,
  unique (character_id, perk_def_id)
);

create index if not exists odyssey_character_perks_character_idx
  on public.odyssey_character_perks (character_id);

create index if not exists odyssey_character_perks_perk_idx
  on public.odyssey_character_perks (perk_def_id);

create table if not exists public.odyssey_body_part_defs (
  id uuid primary key default gen_random_uuid(),
  code text not null unique,
  name text not null,
  category text not null,
  default_max_critical integer not null default 1,
  default_armor_slot text,
  is_vital boolean not null default false,
  can_hold_weapon boolean not null default false,
  can_use_item boolean not null default false,
  can_be_targeted boolean not null default true,
  aim_difficulty integer not null default 0,
  serious_counts_as_critical boolean not null default false,
  sort_order integer not null default 0,
  tags jsonb not null default '[]'::jsonb check (jsonb_typeof(tags) = 'array'),
  is_custom boolean not null default false,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  check (default_max_critical >= 0)
);

create table if not exists public.odyssey_character_body_parts (
  id uuid primary key default gen_random_uuid(),
  character_id uuid not null references public.odyssey_characters(id) on delete cascade,
  body_part_def_id uuid references public.odyssey_body_part_defs(id) on delete set null,
  custom_name text,
  part_key text not null,
  max_critical integer not null default 1 check (max_critical >= 0),
  critical integer not null default 0 check (critical >= 0),
  serious integer not null default 0 check (serious >= 0),
  minor integer not null default 0 check (minor >= 0),
  armor_value integer not null default 0 check (armor_value >= 0),
  armor_item_id uuid,
  disabled boolean not null default false,
  destroyed boolean not null default false,
  sort_order integer not null default 0,
  notes text not null default '',
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  unique (character_id, part_key)
);

create index if not exists odyssey_character_body_parts_character_idx
  on public.odyssey_character_body_parts (character_id);

create index if not exists odyssey_character_body_parts_def_idx
  on public.odyssey_character_body_parts (body_part_def_id);

create index if not exists odyssey_character_body_parts_part_key_idx
  on public.odyssey_character_body_parts (part_key);

comment on column public.odyssey_perk_defs.effect_data is
  'Simple automatic effect payloads. Future Stage 2 range model uses distance bands clinch/short/medium/long where 1 grid cell equals 1 meter.';

comment on column public.odyssey_body_part_defs.aim_difficulty is
  'Positive aimed-shot penalty value. Example: 30 means -30 to aimed attack.';

comment on column public.odyssey_body_part_defs.default_max_critical is
  'Stage 1 seeded defaults currently use Head=1, Torso=3, Arms/Legs=2, Shield=1, Special=1. Later stages may modify character-specific capacity.';

