  can_be_targeted = excluded.can_be_targeted,
  aim_difficulty = excluded.aim_difficulty,
  serious_counts_as_critical = excluded.serious_counts_as_critical,
  sort_order = excluded.sort_order,
  tags = excluded.tags,
  is_custom = excluded.is_custom;


