    'Plasma Edge',
    'duration',
    'manual',
    'Temporarily overcharges a melee edge, adding damage and armor pierce for the next two attack attempts.',
    1,
    1,
    null,
    null,
    null,
    2,
    'small_energy_cell',
    '{
      "modifiers": [
        {
          "target": "damage",
