  caliber_id = excluded.caliber_id,
  range_profile_id = excluded.range_profile_id,
  accuracy_modifier = excluded.accuracy_modifier,
  base_melee_damage = excluded.base_melee_damage,
  attack_type = excluded.attack_type,
  is_default = excluded.is_default,
  data = excluded.data,
  tags = excluded.tags,
  sort_order = excluded.sort_order;

insert into public.odyssey_weapon_profile_fire_modes (
  profile_id,
  fire_mode_id,
  is_default,
  sort_order
)
values
  ((select id from public.odyssey_weapon_model_profiles where weapon_model_id = (select id from public.odyssey_weapon_model_defs where code = 'hybrid_rifle_shotgun') and code = 'rifle_mode'), (select id from public.odyssey_fire_mode_defs where code = 'single'), true, 10),
  ((select id from public.odyssey_weapon_model_profiles where weapon_model_id = (select id from public.odyssey_weapon_model_defs where code = 'hybrid_rifle_shotgun') and code = 'rifle_mode'), (select id from public.odyssey_fire_mode_defs where code = 'burst_3'), false, 20),
  ((select id from public.odyssey_weapon_model_profiles where weapon_model_id = (select id from public.odyssey_weapon_model_defs where code = 'hybrid_rifle_shotgun') and code = 'shotgun_mode'), (select id from public.odyssey_fire_mode_defs where code = 'single'), true, 10),
  ((select id from public.odyssey_weapon_model_profiles where weapon_model_id = (select id from public.odyssey_weapon_model_defs where code = 'hybrid_rifle_shotgun') and code = 'shotgun_mode'), (select id from public.odyssey_fire_mode_defs where code = 'double'), false, 20)
on conflict (profile_id, fire_mode_id) do update
set
  is_default = excluded.is_default,
  sort_order = excluded.sort_order;

insert into public.odyssey_weapon_profile_magazines (
  profile_id,
  magazine_def_id,
  is_default,
  sort_order
)
values
  ((select id from public.odyssey_weapon_model_profiles where weapon_model_id = (select id from public.odyssey_weapon_model_defs where code = 'hybrid_rifle_shotgun') and code = 'rifle_mode'), (select id from public.odyssey_magazine_defs where code = 'medium_rifle_magazine'), true, 10),
  ((select id from public.odyssey_weapon_model_profiles where weapon_model_id = (select id from public.odyssey_weapon_model_defs where code = 'hybrid_rifle_shotgun') and code = 'shotgun_mode'), (select id from public.odyssey_magazine_defs where code = 'shotgun_tube'), true, 10)
on conflict (profile_id, magazine_def_id) do update
set
  is_default = excluded.is_default,
  sort_order = excluded.sort_order;

insert into public.odyssey_weapon_model_features (
  weapon_model_id,
  feature_def_id,
  profile_id,
  is_enabled_by_default,
  data,
  sort_order
)
select
  wm.id,
  def.id,
  profile.id,
  true,
  '{}'::jsonb,
  sort_order_value
from (
  values
    ('combat_knife', 'plasma_edge', 'default', 10),
    ('shock_baton', 'stun_blast', 'default', 20),
    ('hybrid_rifle_shotgun', 'change_caliber', null, 30)
) seed(model_code, feature_code, profile_code, sort_order_value)
join public.odyssey_weapon_model_defs wm on wm.code = seed.model_code
join public.odyssey_weapon_feature_defs def on def.code = seed.feature_code
left join public.odyssey_weapon_model_profiles profile
  on profile.weapon_model_id = wm.id
 and profile.code = seed.profile_code
where not exists (
  select 1
  from public.odyssey_weapon_model_features existing
  where existing.weapon_model_id = wm.id
    and existing.feature_def_id = def.id
    and coalesce(existing.profile_id, '00000000-0000-0000-0000-000000000000'::uuid)
        = coalesce(profile.id, '00000000-0000-0000-0000-000000000000'::uuid)
);

select public.initialize_character_weapon_profile_states(w.id)
from public.odyssey_character_weapons w;

select public.initialize_character_weapon_feature_states(w.id)
from public.odyssey_character_weapons w;


create extension if not exists pgcrypto;

create table if not exists public.odyssey_item_defs (
  id uuid primary key default gen_random_uuid(),
  code text not null unique,
  name text not null,
  item_type text not null check (item_type in ('resource', 'consumable', 'medical', 'tool', 'quest', 'custom')),
  description text not null default '',
  is_stackable boolean not null default true,
  default_quantity integer not null default 1 check (default_quantity >= 0),
  max_stack integer null check (max_stack is null or max_stack >= 1),
  default_max_charges integer null check (default_max_charges is null or default_max_charges >= 0),
  default_current_charges integer null check (default_current_charges is null or default_current_charges >= 0),
  use_action_type text not null default 'none' check (use_action_type in ('none', 'consume', 'heal', 'reload_feature_resource', 'custom')),
  effect_data jsonb not null default '{}'::jsonb check (jsonb_typeof(effect_data) = 'object'),
  data jsonb not null default '{}'::jsonb check (jsonb_typeof(data) = 'object'),
  tags jsonb not null default '[]'::jsonb check (jsonb_typeof(tags) = 'array'),
  is_custom boolean not null default false,
  sort_order integer not null default 0,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.odyssey_character_items (
  id uuid primary key default gen_random_uuid(),
  character_id uuid not null references public.odyssey_characters(id) on delete cascade,
  item_def_id uuid not null references public.odyssey_item_defs(id) on delete cascade,
  custom_name text null,
  quantity integer not null default 1 check (quantity >= 0),
  current_charges integer null check (current_charges is null or current_charges >= 0),
  max_charges integer null check (max_charges is null or max_charges >= 0),
  location_data jsonb not null default '{}'::jsonb check (jsonb_typeof(location_data) = 'object'),
  data jsonb not null default '{}'::jsonb check (jsonb_typeof(data) = 'object'),
  notes text not null default '',
  sort_order integer not null default 0,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.odyssey_character_ammo_stock (
  id uuid primary key default gen_random_uuid(),
  character_id uuid not null references public.odyssey_characters(id) on delete cascade,
  display_name text not null,
  caliber_id uuid not null references public.odyssey_caliber_defs(id) on delete restrict,
  ammo_type_id uuid not null references public.odyssey_ammo_type_defs(id) on delete restrict,
  quantity integer not null default 0 check (quantity >= 0),
  location_data jsonb not null default '{}'::jsonb check (jsonb_typeof(location_data) = 'object'),
  data jsonb not null default '{}'::jsonb check (jsonb_typeof(data) = 'object'),
  notes text not null default '',
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  unique (character_id, caliber_id, ammo_type_id, display_name)
);

create index if not exists odyssey_item_defs_type_idx
  on public.odyssey_item_defs (item_type, sort_order, code);

create index if not exists odyssey_character_items_character_idx
  on public.odyssey_character_items (character_id, item_def_id, sort_order, created_at);

create index if not exists odyssey_character_ammo_stock_character_idx
  on public.odyssey_character_ammo_stock (character_id, caliber_id, ammo_type_id, created_at);

alter table public.odyssey_item_defs enable row level security;
alter table public.odyssey_character_items enable row level security;
alter table public.odyssey_character_ammo_stock enable row level security;

drop policy if exists "odyssey_item_defs_full_access" on public.odyssey_item_defs;
create policy "odyssey_item_defs_full_access"
on public.odyssey_item_defs
for all
to anon, authenticated
using (true)
with check (true);

drop policy if exists "odyssey_character_items_full_access" on public.odyssey_character_items;
create policy "odyssey_character_items_full_access"
on public.odyssey_character_items
for all
to anon, authenticated
using (true)
with check (true);

drop policy if exists "odyssey_character_ammo_stock_full_access" on public.odyssey_character_ammo_stock;
create policy "odyssey_character_ammo_stock_full_access"
on public.odyssey_character_ammo_stock
for all
to anon, authenticated
using (true)
with check (true);

grant select, insert, update, delete on public.odyssey_item_defs to anon, authenticated;
grant select, insert, update, delete on public.odyssey_character_items to anon, authenticated;
grant select, insert, update, delete on public.odyssey_character_ammo_stock to anon, authenticated;

drop trigger if exists odyssey_touch_updated_at_item_defs on public.odyssey_item_defs;
