grant execute on function public.odyssey_equipment_item_has_remaining_armor_capacity(integer, integer, integer, integer, integer, integer) to anon, authenticated;
grant execute on function public.odyssey_equipment_item_is_destroyed(integer, integer, integer, integer, integer, integer) to anon, authenticated;
grant execute on function public.odyssey_apply_equipment_damage_tier(uuid, text, integer) to anon, authenticated;


update public.odyssey_equipment_model_defs
set
  armor_max_minor = case
    when coalesce(armor_max_minor, 0) <= 0
      or armor_max_minor = coalesce(armor_max_critical, 0)
      then 3
    else armor_max_minor
  end,
  armor_max_serious = case
    when coalesce(armor_max_serious, 0) <= 0
      or armor_max_serious = coalesce(armor_max_critical, 0)
      then 1
    else armor_max_serious
  end
where item_type in ('armor', 'shield', 'special_protection', 'exoskeleton', 'closed_suit');

update public.odyssey_character_equipment_items e
set
  armor_max_minor = case
    when coalesce(e.armor_max_minor, 0) <= 0
      or e.armor_max_minor = coalesce(e.armor_max_critical, 0)
      then 3
    else e.armor_max_minor
  end,
  armor_max_serious = case
    when coalesce(e.armor_max_serious, 0) <= 0
      or e.armor_max_serious = coalesce(e.armor_max_critical, 0)
      then 1
    else e.armor_max_serious
  end,
  armor_minor = least(greatest(coalesce(e.armor_minor, 0), 0), 3),
  armor_serious = least(greatest(coalesce(e.armor_serious, 0), 0), 1),
  armor_destroyed = case
    when coalesce(e.armor_max_critical, 0) > 0
      and coalesce(e.armor_critical, 0) >= coalesce(e.armor_max_critical, 0)
      then true
    else false
  end
where exists (
  select 1
  from public.odyssey_equipment_model_defs m
  where m.id = e.equipment_model_id
    and m.item_type in ('armor', 'shield', 'special_protection', 'exoskeleton', 'closed_suit')
);

create or replace function public.get_character_armor_summary(
  p_character_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_character_exists boolean := false;
  v_total_equipped_armor_value integer := 0;
  v_class_def jsonb := '{}'::jsonb;
  v_required_skill_code text := null;
  v_has_required_skill boolean := false;
  v_penalty_profile text := 'none';
  v_penalty_profile_data jsonb := '{}'::jsonb;
  v_penalty_effect_data jsonb := '{}'::jsonb;
  v_head_protected boolean := false;
  v_torso_protected boolean := false;
  v_special_protection boolean := false;
  v_helpless_execution_protected boolean := false;
begin
  select exists(
    select 1
    from public.odyssey_characters c
    where c.id = p_character_id
      and coalesce(c.is_deleted, false) = false
  )
  into v_character_exists;

  if not v_character_exists then
    return jsonb_build_object(
      'ok', false,
      'error', 'CHARACTER_NOT_FOUND',
      'character_id', p_character_id
    );
  end if;

  select
    coalesce(sum(coalesce(e.armor_value, 0)), 0)
  into v_total_equipped_armor_value
  from public.odyssey_character_equipment_items e
  where e.character_id = p_character_id
    and e.is_equipped = true
    and e.equipped_body_part_id is not null;

  v_class_def := public.odyssey_get_armor_class_definition(v_total_equipped_armor_value);
  v_required_skill_code := nullif(trim(coalesce(v_class_def->>'required_skill_code', '')), '');

  if v_required_skill_code is not null then
    select exists(
      select 1
      from public.odyssey_character_skills s
      join public.odyssey_skill_defs d on d.id = s.skill_def_id
      where s.character_id = p_character_id
        and d.code = v_required_skill_code
        and coalesce(s.level, 0) >= 1
    )
    into v_has_required_skill;
  else
    v_has_required_skill := true;
  end if;

  if coalesce(v_class_def->>'code', 'none') = 'none' then
    v_penalty_profile := 'none';
    v_penalty_profile_data := '{}'::jsonb;
  elsif v_has_required_skill then
    v_penalty_profile := 'trained';
    v_penalty_profile_data := coalesce(v_class_def->'trained_penalties', '{}'::jsonb);
  else
    v_penalty_profile := 'untrained';
    v_penalty_profile_data := coalesce(v_class_def->'untrained_penalties', '{}'::jsonb);
  end if;

  v_penalty_effect_data := public.odyssey_build_armor_penalty_effect_data(v_penalty_profile_data);

  with equipped_items as (
    select
      case
        when jsonb_typeof(e.data->'flags') = 'object' then coalesce(m.flags, '{}'::jsonb) || (e.data->'flags')
        else coalesce(m.flags, '{}'::jsonb)
      end as effective_flags,
      public.odyssey_resolve_body_part_code(b.part_key, d.code) as body_part_code
    from public.odyssey_character_equipment_items e
    join public.odyssey_equipment_model_defs m on m.id = e.equipment_model_id
    join public.odyssey_character_body_parts b on b.id = e.equipped_body_part_id
    left join public.odyssey_body_part_defs d on d.id = b.body_part_def_id
    where e.character_id = p_character_id
      and e.is_equipped = true
      and e.equipped_body_part_id is not null
  )
  select
    coalesce(bool_or(body_part_code = 'head'), false),
    coalesce(bool_or(body_part_code = 'torso'), false),
    coalesce(
      bool_or(
        lower(coalesce(effective_flags->>'protects_helpless_execution', 'false')) in ('true', '1', 'yes', 'on')
      ),
      false
    )
  into
    v_head_protected,
    v_torso_protected,
    v_special_protection
  from equipped_items;

  v_helpless_execution_protected :=
    coalesce(v_class_def->>'code', 'none') in ('medium', 'heavy', 'superheavy')
    and (
      (v_head_protected and v_torso_protected)
      or v_special_protection
    );

  return jsonb_build_object(
    'ok', true,
    'character_id', p_character_id,
    'total_equipped_armor_value', v_total_equipped_armor_value,
    'armor_class', coalesce(v_class_def->>'code', 'none'),
    'required_skill_code', v_required_skill_code,
    'has_required_skill', v_has_required_skill,
    'penalty_profile', v_penalty_profile,
    'head_protected', v_head_protected,
    'torso_protected', v_torso_protected,
    'special_protection', v_special_protection,
    'helpless_execution_protected', v_helpless_execution_protected,
    'penalty_effect_data', v_penalty_effect_data,
    'class_definition', v_class_def
  );
end;
$$;

create or replace function public.odyssey_apply_equipment_damage_tier(
  p_body_part_id uuid,
  p_damage_tier text,
  p_delta integer
)
returns jsonb
language plpgsql
as $$
declare
  v_damage_tier text := lower(trim(coalesce(p_damage_tier, '')));
  v_item record;
  v_body_part record;
  v_requested integer := greatest(coalesce(p_delta, 0), 0);
  v_remaining integer := greatest(coalesce(p_delta, 0), 0);
  v_absorbed integer := 0;
  v_absorb integer := 0;
  v_capacity integer := 0;
  v_updates jsonb := '[]'::jsonb;
  v_items_changed boolean := false;
  v_new_armor_minor integer := 0;
  v_new_armor_serious integer := 0;
  v_new_armor_critical integer := 0;
  v_new_armor_destroyed boolean := false;
  v_minor_progress integer := 0;
  v_serious_progress integer := 0;
begin
  if v_damage_tier not in ('minor', 'serious', 'critical') then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_DAMAGE_TIER',
      'message', 'damage_tier must be minor, serious, or critical.',
      'damage_tier', v_damage_tier,
      'absorbed', 0,
      'remaining', v_requested,
      'updated_items', '[]'::jsonb,
      'items_changed', false,
      'body_part', null
    );
  end if;

  if v_requested <= 0 then
    return jsonb_build_object(
      'ok', true,
      'damage_tier', v_damage_tier,
      'absorbed', 0,
      'remaining', 0,
      'updated_items', '[]'::jsonb,
      'items_changed', false,
      'body_part', null
    );
  end if;

  select
    b.id,
    b.character_id
  into v_body_part
  from public.odyssey_character_body_parts b
  where b.id = p_body_part_id
  for update of b;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'BODY_PART_NOT_FOUND',
      'message', 'Body part was not found.',
      'damage_tier', v_damage_tier,
      'absorbed', 0,
      'remaining', v_requested,
      'updated_items', '[]'::jsonb,
      'items_changed', false,
      'body_part', null
    );
  end if;

  for v_item in
    select
      e.id,
      e.armor_minor,
      e.armor_max_minor,
      e.armor_serious,
      e.armor_max_serious,
      e.armor_critical,
      e.armor_max_critical,
      e.armor_destroyed,
      e.sort_order,
      e.created_at,
      coalesce(nullif(trim(e.custom_name), ''), m.name) as item_name
    from public.odyssey_character_equipment_items e
    join public.odyssey_equipment_model_defs m on m.id = e.equipment_model_id
    where e.equipped_body_part_id = p_body_part_id
      and e.is_equipped = true
    order by e.sort_order, e.created_at, e.id
    for update of e
  loop
    exit when v_remaining <= 0;

    v_minor_progress := greatest(coalesce(v_item.armor_minor, 0), 0)
      + (greatest(coalesce(v_item.armor_serious, 0), 0) * 4);
    v_new_armor_critical := greatest(coalesce(v_item.armor_critical, 0), 0)
      + floor(v_minor_progress::numeric / 8::numeric)::integer;
    v_minor_progress := mod(v_minor_progress, 8);
    v_new_armor_serious := floor(v_minor_progress::numeric / 4::numeric)::integer;
    v_new_armor_minor := mod(v_minor_progress, 4);

    if coalesce(v_item.armor_max_critical, 0) > 0
      and v_new_armor_critical >= coalesce(v_item.armor_max_critical, 0) then
      v_new_armor_critical := coalesce(v_item.armor_max_critical, 0);
      v_new_armor_serious := 0;
      v_new_armor_minor := 0;
    end if;

    if coalesce(v_item.armor_destroyed, false)
      or coalesce(v_item.armor_max_critical, 0) <= coalesce(v_new_armor_critical, 0) then
      continue;
    end if;

    if v_damage_tier = 'minor' then
      v_capacity := greatest(
        ((coalesce(v_item.armor_max_critical, 0) - coalesce(v_new_armor_critical, 0)) * 8)
          - (coalesce(v_new_armor_minor, 0) + (coalesce(v_new_armor_serious, 0) * 4)),
        0
      );

      if v_capacity <= 0 then
        continue;
      end if;

      v_absorb := least(v_remaining, v_capacity);
      v_minor_progress := coalesce(v_new_armor_minor, 0) + (coalesce(v_new_armor_serious, 0) * 4) + v_absorb;
      v_new_armor_critical := coalesce(v_new_armor_critical, 0)
        + floor(v_minor_progress::numeric / 8::numeric)::integer;
      v_minor_progress := mod(v_minor_progress, 8);
      v_new_armor_serious := floor(v_minor_progress::numeric / 4::numeric)::integer;
      v_new_armor_minor := mod(v_minor_progress, 4);
    elsif v_damage_tier = 'serious' then
      v_capacity := greatest(
        ((coalesce(v_item.armor_max_critical, 0) - coalesce(v_new_armor_critical, 0)) * 2)
          - coalesce(v_new_armor_serious, 0),
        0
      );

      if v_capacity <= 0 then
        continue;
      end if;

      v_absorb := least(v_remaining, v_capacity);
      v_serious_progress := coalesce(v_new_armor_serious, 0) + v_absorb;
      v_new_armor_critical := coalesce(v_new_armor_critical, 0)
        + floor(v_serious_progress::numeric / 2::numeric)::integer;
      v_new_armor_serious := mod(v_serious_progress, 2);
    else
      v_capacity := greatest(coalesce(v_item.armor_max_critical, 0) - coalesce(v_new_armor_critical, 0), 0);

      if v_capacity <= 0 then
        continue;
      end if;

      v_absorb := least(v_remaining, v_capacity);
      v_new_armor_critical := coalesce(v_new_armor_critical, 0) + v_absorb;
    end if;

    if v_absorb <= 0 then
      continue;
    end if;

    v_new_armor_destroyed := case
      when coalesce(v_item.armor_max_critical, 0) > 0
        and v_new_armor_critical >= coalesce(v_item.armor_max_critical, 0)
        then true
      else false
    end;

    if v_new_armor_destroyed then
      v_new_armor_serious := 0;
      v_new_armor_minor := 0;
    end if;

    update public.odyssey_character_equipment_items
    set
      armor_minor = v_new_armor_minor,
      armor_serious = v_new_armor_serious,
      armor_critical = v_new_armor_critical,
      armor_destroyed = v_new_armor_destroyed,
      updated_at = timezone('utc', now())
    where id = v_item.id;

    v_updates := v_updates || jsonb_build_array(
      jsonb_build_object(
        'id', v_item.id,
        'name', v_item.item_name,
        'armor_minor', v_new_armor_minor,
        'armor_max_minor', coalesce(v_item.armor_max_minor, 3),
        'armor_serious', v_new_armor_serious,
        'armor_max_serious', coalesce(v_item.armor_max_serious, 1),
        'armor_critical', v_new_armor_critical,
        'armor_max_critical', coalesce(v_item.armor_max_critical, 0),
        'armor_destroyed', v_new_armor_destroyed
      ) || case
        when v_damage_tier = 'minor' then jsonb_build_object('absorbed_minor', v_absorb)
        when v_damage_tier = 'serious' then jsonb_build_object('absorbed_serious', v_absorb)
        else jsonb_build_object('absorbed_critical', v_absorb)
      end
    );

    v_absorbed := v_absorbed + v_absorb;
    v_remaining := v_remaining - v_absorb;
    v_items_changed := true;
  end loop;

  return jsonb_build_object(
    'ok', true,
    'damage_tier', v_damage_tier,
    'absorbed', v_absorbed,
    'remaining', greatest(v_requested - v_absorbed, 0),
    'updated_items', v_updates,
    'items_changed', v_items_changed,
    'body_part',
      jsonb_build_object(
        'id', v_body_part.id,
        'character_id', v_body_part.character_id,
        'absorbed_by_items', v_absorbed
      )
  );
end;
$$;

do $$
declare
  v_function_def text := null;
begin
  select pg_get_functiondef(p.oid)
  into v_function_def
  from pg_proc p
  join pg_namespace n on n.oid = p.pronamespace
  where n.nspname = 'public'
    and p.proname = 'recompute_character_armor'
    and pg_get_function_identity_arguments(p.oid) = 'p_character_id uuid';

  if v_function_def is null then
    raise exception 'Function public.recompute_character_armor(uuid) was not found.';
  end if;

  if position($needle$coalesce(
        sum(
          case
            when public.odyssey_equipment_item_has_remaining_armor_capacity(
              e.armor_minor,
              e.armor_max_minor,
              e.armor_serious,
              e.armor_max_serious,
              e.armor_critical,
              e.armor_max_critical
            ) then coalesce(e.armor_value, 0)
            else 0
          end
        ),
        0
      )::integer as equipped_armor_value,$needle$ in v_function_def) = 0 then
    raise exception 'Could not find equipped_armor_value block in public.recompute_character_armor(uuid).';
  end if;

  v_function_def := replace(
    v_function_def,
    $old$coalesce(
        sum(
          case
            when public.odyssey_equipment_item_has_remaining_armor_capacity(
              e.armor_minor,
              e.armor_max_minor,
              e.armor_serious,
              e.armor_max_serious,
              e.armor_critical,
              e.armor_max_critical
            ) then coalesce(e.armor_value, 0)
            else 0
          end
        ),
        0
      )::integer as equipped_armor_value,$old$,
    $new$coalesce(sum(coalesce(e.armor_value, 0)), 0)::integer as equipped_armor_value,$new$
  );

  execute v_function_def;
end;
$$;

do $$
declare
  v_function_def text := null;
begin
  select pg_get_functiondef(p.oid)
  into v_function_def
  from pg_proc p
  join pg_namespace n on n.oid = p.pronamespace
  where n.nspname = 'public'
    and p.proname = 'get_character_equipment'
    and pg_get_function_identity_arguments(p.oid) = 'p_character_id uuid';

  if v_function_def is null then
    raise exception 'Function public.get_character_equipment(uuid) was not found.';
  end if;

  if position($needle$'equipped_armor_value_total', coalesce((sum(coalesce((item_payload->>'armor_value')::integer, 0)) filter (where is_equipped and has_body_part and has_remaining_armor_capacity))::integer, 0),$needle$ in v_function_def) = 0 then
    raise exception 'Could not find equipped_armor_value_total block in public.get_character_equipment(uuid).';
  end if;

  v_function_def := replace(
    v_function_def,
    $old$'equipped_armor_value_total', coalesce((sum(coalesce((item_payload->>'armor_value')::integer, 0)) filter (where is_equipped and has_body_part and has_remaining_armor_capacity))::integer, 0),$old$,
    $new$'equipped_armor_value_total', coalesce((sum(coalesce((item_payload->>'armor_value')::integer, 0)) filter (where is_equipped and has_body_part))::integer, 0),$new$
  );

  execute v_function_def;
end;
$$;

do $$
begin
  perform public.recompute_character_armor(c.id)
  from public.odyssey_characters c
  where coalesce(c.is_deleted, false) = false;

  perform public.odyssey_refresh_character_combat_state(c.id)
  from public.odyssey_characters c
  where coalesce(c.is_deleted, false) = false;
end;
$$;


create or replace function public.odyssey_merge_runtime_data(
  p_base jsonb,
  p_override jsonb
)
returns jsonb
language sql
immutable
as $$
  with normalized as (
    select
      coalesce(case when jsonb_typeof(p_base) = 'object' then p_base else '{}'::jsonb end, '{}'::jsonb) as base_data,
      coalesce(case when jsonb_typeof(p_override) = 'object' then p_override else '{}'::jsonb end, '{}'::jsonb) as override_data
  )
  select jsonb_set(
    jsonb_set(
      jsonb_set(
        jsonb_set(
          ((base_data - 'modifiers' - 'flags' - 'on_hit' - 'conditions') || (override_data - 'modifiers' - 'flags' - 'on_hit' - 'conditions')),
          '{modifiers}',
          case
            when jsonb_typeof(base_data->'modifiers') = 'array'
              and jsonb_typeof(override_data->'modifiers') = 'array'
              then (base_data->'modifiers') || (override_data->'modifiers')
            when jsonb_typeof(override_data->'modifiers') = 'array'
              then override_data->'modifiers'
            when jsonb_typeof(base_data->'modifiers') = 'array'
              then base_data->'modifiers'
            else '[]'::jsonb
          end,
          true
        ),
        '{on_hit}',
        case
          when jsonb_typeof(base_data->'on_hit') = 'array'
            and jsonb_typeof(override_data->'on_hit') = 'array'
            then (base_data->'on_hit') || (override_data->'on_hit')
          when jsonb_typeof(override_data->'on_hit') = 'array'
            then override_data->'on_hit'
          when jsonb_typeof(base_data->'on_hit') = 'array'
            then base_data->'on_hit'
          else '[]'::jsonb
        end,
        true
      ),
      '{flags}',
      case
        when jsonb_typeof(base_data->'flags') = 'object'
          or jsonb_typeof(override_data->'flags') = 'object'
          then coalesce(base_data->'flags', '{}'::jsonb) || coalesce(override_data->'flags', '{}'::jsonb)
        else '{}'::jsonb
      end,
      true
    ),
    '{conditions}',
    case
      when jsonb_typeof(base_data->'conditions') = 'object'
        or jsonb_typeof(override_data->'conditions') = 'object'
        then coalesce(base_data->'conditions', '{}'::jsonb) || coalesce(override_data->'conditions', '{}'::jsonb)
      else '{}'::jsonb
    end,
    true
  )
  from normalized;
$$;

alter table public.odyssey_item_defs
  drop constraint if exists odyssey_item_defs_use_action_type_check;

alter table public.odyssey_item_defs
  add constraint odyssey_item_defs_use_action_type_check
  check (use_action_type in ('none', 'consume', 'heal', 'reload_feature_resource', 'manual', 'custom'));

create or replace function public.odyssey_consume_character_ability_cost(
  p_character_ability_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_ability record;
  v_effective_level integer := 0;
  v_level record;
  v_pool record;
  v_sync jsonb := '{}'::jsonb;
  v_item_result jsonb := '{}'::jsonb;
  v_runtime_data jsonb := '{}'::jsonb;
  v_reload_config jsonb := '{}'::jsonb;
  v_reload_mode text := '';
  v_reload_item_code text := null;
  v_item_cost_per_reload integer := 1;
  v_charges_before integer := 0;
  v_charges_after integer := 0;
begin
  select
    ability.id,
    ability.character_id,
    ability.ability_def_id,
    ability.current_cooldown_rounds,
    ability.current_charges,
    ability.max_charges,
    ability.data as state_data,
    def.code as ability_code,
    def.name as ability_name,
    def.resource_mode,
    def.resource_pool_code,
    def.resource_item_code,
    def.data as definition_data
  into v_ability
  from public.odyssey_character_abilities ability
  join public.odyssey_ability_defs def on def.id = ability.ability_def_id
  where ability.id = p_character_ability_id
    and ability.is_enabled = true
  for update of ability;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_NOT_FOUND',
      'character_ability_id', p_character_ability_id
    );
  end if;

  if coalesce(v_ability.current_cooldown_rounds, 0) > 0 then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_ON_COOLDOWN',
      'character_ability_id', p_character_ability_id,
      'cooldown_rounds_left', v_ability.current_cooldown_rounds
    );
  end if;

  v_effective_level := public.odyssey_get_character_ability_effective_level(p_character_ability_id);

  select *
  into v_level
  from public.odyssey_ability_level_defs level_data
  where level_data.ability_def_id = v_ability.ability_def_id
    and level_data.ability_level <= v_effective_level
  order by level_data.ability_level desc
  limit 1;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_LEVEL_NOT_AVAILABLE',
      'character_ability_id', p_character_ability_id,
      'effective_level', v_effective_level
    );
  end if;

  v_runtime_data := public.odyssey_merge_runtime_data(
    public.odyssey_merge_runtime_data(
      coalesce(v_ability.definition_data, '{}'::jsonb),
      coalesce(v_ability.state_data, '{}'::jsonb)
    ),
    coalesce(v_level.data, '{}'::jsonb)
  );

  if jsonb_typeof(v_runtime_data->'reload') = 'object' then
    v_reload_config := v_runtime_data->'reload';
    v_reload_mode := lower(trim(coalesce(v_reload_config->>'mode', '')));
    v_reload_item_code := lower(trim(coalesce(
      nullif(v_reload_config->>'item_code', ''),
      nullif(v_ability.resource_item_code, ''),
      ''
    )));

    if coalesce(v_reload_config->>'item_cost_per_reload', '') ~ '^-?[0-9]+$' then
      v_item_cost_per_reload := greatest((v_reload_config->>'item_cost_per_reload')::integer, 1);
    else
      v_item_cost_per_reload := 1;
    end if;
  end if;

  if v_reload_mode in ('reset', 'per_charge') then
    if v_ability.current_charges is null or v_ability.max_charges is null then
      return jsonb_build_object(
        'ok', false,
        'error', 'ABILITY_CHARGE_STATE_NOT_CONFIGURED',
        'character_ability_id', p_character_ability_id
      );
    end if;

    if coalesce(v_ability.current_charges, 0) <= 0 then
      return jsonb_build_object(
        'ok', false,
        'error', 'ABILITY_NOT_LOADED',
        'character_ability_id', p_character_ability_id,
        'reload_mode', v_reload_mode,
        'charges',
          jsonb_build_object(
            'before', coalesce(v_ability.current_charges, 0),
            'after', coalesce(v_ability.current_charges, 0),
            'max', coalesce(v_ability.max_charges, 0)
          )
      );
    end if;

    v_charges_before := coalesce(v_ability.current_charges, 0);
    v_charges_after := greatest(v_charges_before - 1, 0);

    update public.odyssey_character_abilities
    set current_charges = v_charges_after
    where id = p_character_ability_id;

    return jsonb_build_object(
      'ok', true,
      'character_ability_id', p_character_ability_id,
      'resource_mode', 'internal_charge',
      'resource_consumed', true,
      'resource_cost', 1,
      'charges',
        jsonb_build_object(
          'before', v_charges_before,
          'after', v_charges_after,
          'max', coalesce(v_ability.max_charges, 0),
          'consumed', 1
        ),
      'resource',
        jsonb_build_object(
          'type', 'internal_charge',
          'reload_mode', v_reload_mode,
          'item_code', nullif(v_reload_item_code, ''),
          'item_cost_per_reload', v_item_cost_per_reload
        )
    );
  end if;

  if coalesce(v_level.resource_cost, 0) <= 0 or v_ability.resource_mode in ('none', 'cooldown', 'custom') then
    return jsonb_build_object(
      'ok', true,
      'character_ability_id', p_character_ability_id,
      'resource_mode', v_ability.resource_mode,
      'resource_cost', coalesce(v_level.resource_cost, 0),
      'resource_consumed', false
    );
  end if;

  if v_ability.resource_mode = 'pool' then
    v_sync := public.odyssey_sync_character_resource_pools(v_ability.character_id);

    select
      p.id,
      p.current_value,
      p.max_value,
      d.code,
      d.name
    into v_pool
    from public.odyssey_character_resource_pools p
    join public.odyssey_resource_pool_defs d on d.id = p.resource_pool_def_id
    where p.character_id = v_ability.character_id
      and d.code = v_ability.resource_pool_code
    for update of p;

    if not found then
      return jsonb_build_object(
        'ok', false,
        'error', 'RESOURCE_POOL_NOT_FOUND',
        'character_ability_id', p_character_ability_id,
        'resource_pool_code', v_ability.resource_pool_code,
        'sync', v_sync
      );
    end if;

    if coalesce(v_pool.current_value, 0) < coalesce(v_level.resource_cost, 0) then
      return jsonb_build_object(
        'ok', false,
        'error', 'NO_ENERGY',
        'character_ability_id', p_character_ability_id,
        'resource_pool_code', v_pool.code,
        'required', v_level.resource_cost,
        'available', coalesce(v_pool.current_value, 0)
      );
    end if;

    update public.odyssey_character_resource_pools
    set current_value = greatest(current_value - coalesce(v_level.resource_cost, 0), 0)
    where id = v_pool.id;

    return jsonb_build_object(
      'ok', true,
      'character_ability_id', p_character_ability_id,
      'resource_mode', v_ability.resource_mode,
      'resource_consumed', true,
      'resource_cost', coalesce(v_level.resource_cost, 0),
      'resource_pool',
        jsonb_build_object(
          'id', v_pool.id,
          'code', v_pool.code,
          'name', v_pool.name,
          'before', coalesce(v_pool.current_value, 0),
          'after', greatest(coalesce(v_pool.current_value, 0) - coalesce(v_level.resource_cost, 0), 0),
          'max', coalesce(v_pool.max_value, 0)
        )
    );
  end if;

  if v_ability.resource_mode = 'item' then
    if nullif(trim(coalesce(v_ability.resource_item_code, '')), '') is null then
      return jsonb_build_object(
        'ok', false,
        'error', 'RESOURCE_ITEM_CODE_REQUIRED',
        'character_ability_id', p_character_ability_id
      );
    end if;

    v_item_result := public.remove_character_item_quantity(
      v_ability.character_id,
      v_ability.resource_item_code,
      coalesce(v_level.resource_cost, 0)
    );

    if coalesce((v_item_result->>'ok')::boolean, false) = false then
      return jsonb_build_object(
        'ok', false,
        'error', 'RESOURCE_ITEM_NOT_AVAILABLE',
        'character_ability_id', p_character_ability_id,
        'resource_item_code', v_ability.resource_item_code,
        'details', v_item_result
      );
    end if;

    return jsonb_build_object(
      'ok', true,
      'character_ability_id', p_character_ability_id,
      'resource_mode', v_ability.resource_mode,
      'resource_consumed', true,
      'resource_cost', coalesce(v_level.resource_cost, 0),
      'item', v_item_result
    );
  end if;

  return jsonb_build_object(
    'ok', true,
    'character_ability_id', p_character_ability_id,
    'resource_mode', v_ability.resource_mode,
    'resource_cost', coalesce(v_level.resource_cost, 0),
    'resource_consumed', false
  );
end;
$$;

create or replace function public.reload_feature_resource(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_feature_instance_type text := lower(trim(coalesce(p_payload->>'feature_instance_type', '')));
  v_feature_instance_id uuid := public.odyssey_try_parse_uuid(p_payload->>'feature_instance_id');
  v_quantity_text text := nullif(trim(coalesce(p_payload->>'quantity', '')), '');
  v_requested_quantity integer := 1;
  v_reload_mode text := '';
  v_reload_config jsonb := '{}'::jsonb;
  v_item_code text := '';
  v_item_cost_per_reload integer := 1;
  v_inventory_before integer := 0;
  v_inventory_after integer := 0;
  v_quantity_spent integer := 0;
  v_loaded_quantity integer := 0;
  v_item_result jsonb := '{}'::jsonb;
  v_feature record;
  v_ability record;
  v_runtime_data jsonb := '{}'::jsonb;
  v_free_slots integer := 0;
  v_charges_before integer := 0;
  v_charges_after integer := 0;
begin
  if v_feature_instance_type not in ('weapon_feature', 'character_ability') then
    return jsonb_build_object(
      'ok', false,
      'error', 'FEATURE_INSTANCE_TYPE_NOT_SUPPORTED',
      'message', 'feature_instance_type must be weapon_feature or character_ability.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  if v_feature_instance_id is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_PAYLOAD',
      'message', 'feature_instance_id is required and must be a valid UUID.',
      'feature_instance_type', v_feature_instance_type
    );
  end if;

  if v_quantity_text is not null then
    if v_quantity_text !~ '^[0-9]+$' then
      return jsonb_build_object(
        'ok', false,
        'error', 'INVALID_RELOAD_QUANTITY',
        'message', 'quantity must be a positive integer.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    v_requested_quantity := v_quantity_text::integer;
  end if;

  if v_requested_quantity <= 0 then
    return jsonb_build_object(
      'ok', false,
      'error', 'INVALID_RELOAD_QUANTITY',
      'message', 'quantity must be a positive integer.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  if v_feature_instance_type = 'weapon_feature' then
    select
      s.id,
      s.character_weapon_id,
      s.is_active,
      s.is_enabled,
      s.current_charges,
      s.max_charges,
      s.recharge_rounds_left,
      s.cooldown_rounds_left,
      s.active_rounds_left,
      s.active_uses_left,
      s.requires_reload,
      s.data as state_data,
      w.character_id,
      def.code as feature_code,
      def.name as feature_name,
      def.requires_reload_item_code,
      public.odyssey_merge_runtime_data(
        public.odyssey_merge_runtime_data(def.data, coalesce(link.data, '{}'::jsonb)),
        s.data
      ) as merged_data
    into v_feature
    from public.odyssey_character_weapon_feature_states s
    join public.odyssey_character_weapons w on w.id = s.character_weapon_id
    join public.odyssey_weapon_feature_defs def on def.id = s.feature_def_id
    left join public.odyssey_weapon_model_features link
      on link.weapon_model_id = w.weapon_model_id
     and link.feature_def_id = s.feature_def_id
     and coalesce(link.profile_id, '00000000-0000-0000-0000-000000000000'::uuid)
         = coalesce(s.profile_id, '00000000-0000-0000-0000-000000000000'::uuid)
    where s.id = v_feature_instance_id
    for update of s;

    if not found then
      return jsonb_build_object(
        'ok', false,
        'error', 'FEATURE_INSTANCE_NOT_FOUND',
        'message', 'Weapon feature instance was not found.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    if not coalesce(v_feature.is_enabled, true) then
      return jsonb_build_object(
        'ok', false,
        'error', 'FEATURE_DISABLED',
        'message', 'Feature instance is disabled.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    if jsonb_typeof(v_feature.merged_data->'reload') = 'object' then
      v_reload_config := v_feature.merged_data->'reload';
      v_reload_mode := lower(trim(coalesce(v_reload_config->>'mode', '')));
      v_item_code := lower(trim(coalesce(
        nullif(v_reload_config->>'item_code', ''),
        nullif(v_feature.requires_reload_item_code, ''),
        ''
      )));
      if coalesce(v_reload_config->>'item_cost_per_reload', '') ~ '^-?[0-9]+$' then
        v_item_cost_per_reload := greatest((v_reload_config->>'item_cost_per_reload')::integer, 1);
      end if;
    else
      v_reload_mode := case
        when nullif(trim(coalesce(v_feature.requires_reload_item_code, '')), '') is not null then 'reset'
        else ''
      end;
      v_item_code := lower(trim(coalesce(v_feature.requires_reload_item_code, '')));
    end if;

    if v_reload_mode = '' then
      return jsonb_build_object(
        'ok', false,
        'error', 'FEATURE_NOT_RELOADABLE',
        'message', 'Feature does not define reload configuration.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    if v_reload_mode not in ('reset', 'per_charge') then
      return jsonb_build_object(
        'ok', false,
        'error', 'RELOAD_MODE_NOT_SUPPORTED',
        'message', 'reload.mode must be reset or per_charge.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id,
        'reload_mode', v_reload_mode
      );
    end if;

    if v_item_code = '' then
      return jsonb_build_object(
        'ok', false,
        'error', 'FEATURE_NOT_RELOADABLE',
        'message', 'Reloadable feature is missing reload item_code.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id,
        'reload_mode', v_reload_mode
      );
    end if;

    v_charges_before := coalesce(v_feature.current_charges, 0);

    if v_reload_mode = 'reset' then
      if not coalesce(v_feature.requires_reload, false) then
        return jsonb_build_object(
          'ok', false,
          'error', 'FEATURE_DOES_NOT_REQUIRE_RELOAD',
          'message', 'Feature does not currently require reload.',
          'feature_instance_type', v_feature_instance_type,
          'feature_instance_id', v_feature_instance_id
        );
      end if;

      if v_feature.max_charges is null then
        return jsonb_build_object(
          'ok', false,
          'error', 'NO_CHARGE_CAPACITY',
          'message', 'Feature does not expose max_charges for reset reload.',
          'feature_instance_type', v_feature_instance_type,
          'feature_instance_id', v_feature_instance_id
        );
      end if;

      v_quantity_spent := v_item_cost_per_reload;
      v_loaded_quantity := 1;
      v_charges_after := coalesce(v_feature.max_charges, 0);
    else
      if v_feature.current_charges is null or v_feature.max_charges is null then
        return jsonb_build_object(
          'ok', false,
          'error', 'NO_CHARGE_CAPACITY',
          'message', 'Feature does not expose current_charges/max_charges for per_charge reload.',
          'feature_instance_type', v_feature_instance_type,
          'feature_instance_id', v_feature_instance_id
        );
      end if;

      v_free_slots := greatest(coalesce(v_feature.max_charges, 0) - coalesce(v_feature.current_charges, 0), 0);
      if v_free_slots <= 0 then
        return jsonb_build_object(
          'ok', false,
          'error', 'NO_CHARGE_CAPACITY',
          'message', 'Feature charges are already full.',
          'feature_instance_type', v_feature_instance_type,
          'feature_instance_id', v_feature_instance_id
        );
      end if;

      v_loaded_quantity := least(v_requested_quantity, v_free_slots);
      v_quantity_spent := v_loaded_quantity * v_item_cost_per_reload;
      v_charges_after := coalesce(v_feature.current_charges, 0) + v_loaded_quantity;
    end if;

    v_inventory_before := public.get_character_item_quantity(v_feature.character_id, v_item_code);
    if v_inventory_before <= 0 then
      return jsonb_build_object(
        'ok', false,
        'error', 'NO_RESOURCE_ITEM',
        'message', 'Character does not have the required reload item.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    if v_inventory_before < v_quantity_spent then
      return jsonb_build_object(
        'ok', false,
        'error', 'INSUFFICIENT_RESOURCE_ITEM',
        'message', 'Character does not have enough reload items.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    v_item_result := public.remove_character_item_quantity(
      v_feature.character_id,
      v_item_code,
      v_quantity_spent
    );

    if coalesce((v_item_result->>'ok')::boolean, false) = false then
      return jsonb_build_object(
        'ok', false,
        'error',
          case
            when coalesce(v_item_result->>'error', '') = 'NOT_ENOUGH_ITEMS' then 'INSUFFICIENT_RESOURCE_ITEM'
            else 'NO_RESOURCE_ITEM'
          end,
        'message', 'Character does not have the required reload item.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    v_inventory_after := coalesce((v_item_result->>'remaining_quantity')::integer, greatest(v_inventory_before - v_quantity_spent, 0));

    if v_reload_mode = 'reset' then
      update public.odyssey_character_weapon_feature_states
      set
        is_active = false,
        current_charges = max_charges,
        recharge_rounds_left = null,
        cooldown_rounds_left = null,
        active_rounds_left = null,
        active_uses_left = null,
        requires_reload = false
      where id = v_feature.id;
    else
      update public.odyssey_character_weapon_feature_states
      set
        current_charges = least(coalesce(max_charges, current_charges), coalesce(current_charges, 0) + v_loaded_quantity),
        requires_reload = false
      where id = v_feature.id;
    end if;

    return jsonb_build_object(
      'ok', true,
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id,
      'character_id', v_feature.character_id,
      'reload_mode', v_reload_mode,
      'feature_code', v_feature.feature_code,
      'resource',
        jsonb_build_object(
          'item_code', v_item_code,
          'quantity_spent', v_quantity_spent,
          'inventory_before', v_inventory_before,
          'inventory_after', v_inventory_after
        ),
      'charges',
        jsonb_build_object(
          'before', v_charges_before,
          'after', v_charges_after,
          'max', coalesce(v_feature.max_charges, v_charges_after),
          'loaded', v_loaded_quantity
        ),
      'feature_state',
        jsonb_build_object(
          'requires_reload', false,
          'is_active', case when v_reload_mode = 'reset' then false else coalesce(v_feature.is_active, false) end,
          'active_uses_left', case when v_reload_mode = 'reset' then null else v_feature.active_uses_left end,
          'cooldown_rounds_left', case when v_reload_mode = 'reset' then null else v_feature.cooldown_rounds_left end,
          'recharge_rounds_left', case when v_reload_mode = 'reset' then null else v_feature.recharge_rounds_left end
        )
    );
  end if;

  select
    ability.id,
    ability.character_id,
    ability.ability_def_id,
    ability.is_enabled,
    ability.current_cooldown_rounds,
    ability.current_charges,
    ability.max_charges,
    ability.data as state_data,
    def.code as ability_code,
    def.name as ability_name,
    def.resource_item_code,
    def.data as definition_data,
    level.data as level_data
  into v_ability
  from public.odyssey_character_abilities ability
  join public.odyssey_ability_defs def on def.id = ability.ability_def_id
  left join lateral (
    select level_entry.*
    from public.odyssey_ability_level_defs level_entry
    where level_entry.ability_def_id = def.id
      and level_entry.ability_level <= public.odyssey_get_character_ability_effective_level(ability.id)
    order by level_entry.ability_level desc
    limit 1
  ) level on true
  where ability.id = v_feature_instance_id
  for update of ability;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'FEATURE_INSTANCE_NOT_FOUND',
      'message', 'Character ability instance was not found.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  if not coalesce(v_ability.is_enabled, true) then
    return jsonb_build_object(
      'ok', false,
      'error', 'FEATURE_DISABLED',
      'message', 'Feature instance is disabled.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  v_runtime_data := public.odyssey_merge_runtime_data(
    public.odyssey_merge_runtime_data(
      coalesce(v_ability.definition_data, '{}'::jsonb),
      coalesce(v_ability.state_data, '{}'::jsonb)
    ),
    coalesce(v_ability.level_data, '{}'::jsonb)
  );

  if jsonb_typeof(v_runtime_data->'reload') = 'object' then
    v_reload_config := v_runtime_data->'reload';
    v_reload_mode := lower(trim(coalesce(v_reload_config->>'mode', '')));
    v_item_code := lower(trim(coalesce(
      nullif(v_reload_config->>'item_code', ''),
      nullif(v_ability.resource_item_code, ''),
      ''
    )));
    if coalesce(v_reload_config->>'item_cost_per_reload', '') ~ '^-?[0-9]+$' then
      v_item_cost_per_reload := greatest((v_reload_config->>'item_cost_per_reload')::integer, 1);
    else
      v_item_cost_per_reload := 1;
    end if;
  end if;

  if v_reload_mode = '' then
    return jsonb_build_object(
      'ok', false,
      'error', 'FEATURE_NOT_RELOADABLE',
      'message', 'Ability does not define reload configuration.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  if v_reload_mode not in ('reset', 'per_charge') then
    return jsonb_build_object(
      'ok', false,
      'error', 'RELOAD_MODE_NOT_SUPPORTED',
      'message', 'reload.mode must be reset or per_charge.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id,
      'reload_mode', v_reload_mode
    );
  end if;

  if v_item_code = '' then
    return jsonb_build_object(
      'ok', false,
      'error', 'FEATURE_NOT_RELOADABLE',
      'message', 'Reloadable ability is missing reload item_code.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id,
      'reload_mode', v_reload_mode
    );
  end if;

  if v_ability.current_charges is null or v_ability.max_charges is null then
    return jsonb_build_object(
      'ok', false,
      'error', 'NO_CHARGE_CAPACITY',
      'message', 'Ability does not expose current_charges/max_charges.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  v_charges_before := coalesce(v_ability.current_charges, 0);

  if v_reload_mode = 'reset' then
    if v_charges_before >= coalesce(v_ability.max_charges, 0) then
      return jsonb_build_object(
        'ok', false,
        'error', 'FEATURE_DOES_NOT_REQUIRE_RELOAD',
        'message', 'Ability charges are already full.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    v_loaded_quantity := greatest(coalesce(v_ability.max_charges, 0) - v_charges_before, 0);
    v_quantity_spent := v_item_cost_per_reload;
    v_charges_after := coalesce(v_ability.max_charges, v_charges_before);
  else
    v_free_slots := greatest(coalesce(v_ability.max_charges, 0) - v_charges_before, 0);
    if v_free_slots <= 0 then
      return jsonb_build_object(
        'ok', false,
        'error', 'NO_CHARGE_CAPACITY',
        'message', 'Ability charges are already full.',
        'feature_instance_type', v_feature_instance_type,
        'feature_instance_id', v_feature_instance_id
      );
    end if;

    v_loaded_quantity := least(v_requested_quantity, v_free_slots);
    v_quantity_spent := v_loaded_quantity * v_item_cost_per_reload;
    v_charges_after := v_charges_before + v_loaded_quantity;
  end if;

  v_inventory_before := public.get_character_item_quantity(v_ability.character_id, v_item_code);
  if v_inventory_before <= 0 then
    return jsonb_build_object(
      'ok', false,
      'error', 'NO_RESOURCE_ITEM',
      'message', 'Character does not have the required reload item.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  if v_inventory_before < v_quantity_spent then
    return jsonb_build_object(
      'ok', false,
      'error', 'INSUFFICIENT_RESOURCE_ITEM',
      'message', 'Character does not have enough reload items.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  v_item_result := public.remove_character_item_quantity(
    v_ability.character_id,
    v_item_code,
    v_quantity_spent
  );

  if coalesce((v_item_result->>'ok')::boolean, false) = false then
    return jsonb_build_object(
      'ok', false,
      'error',
        case
          when coalesce(v_item_result->>'error', '') = 'NOT_ENOUGH_ITEMS' then 'INSUFFICIENT_RESOURCE_ITEM'
          else 'NO_RESOURCE_ITEM'
        end,
      'message', 'Character does not have the required reload item.',
      'feature_instance_type', v_feature_instance_type,
      'feature_instance_id', v_feature_instance_id
    );
  end if;

  v_inventory_after := coalesce((v_item_result->>'remaining_quantity')::integer, greatest(v_inventory_before - v_quantity_spent, 0));

  update public.odyssey_character_abilities
  set
    current_charges = v_charges_after,
    current_cooldown_rounds = case when v_reload_mode = 'reset' then 0 else current_cooldown_rounds end
  where id = v_ability.id;

  return jsonb_build_object(
    'ok', true,
    'feature_instance_type', v_feature_instance_type,
    'feature_instance_id', v_feature_instance_id,
    'character_id', v_ability.character_id,
    'reload_mode', v_reload_mode,
    'ability_code', v_ability.ability_code,
    'resource',
      jsonb_build_object(
        'item_code', v_item_code,
        'quantity_spent', v_quantity_spent,
        'inventory_before', v_inventory_before,
        'inventory_after', v_inventory_after
      ),
    'charges',
      jsonb_build_object(
        'before', v_charges_before,
        'after', v_charges_after,
        'max', coalesce(v_ability.max_charges, v_charges_after),
        'loaded', v_loaded_quantity
      ),
    'feature_state',
      jsonb_build_object(
        'requires_reload', false,
        'is_active', false,
        'active_uses_left', null,
        'cooldown_rounds_left', case when v_reload_mode = 'reset' then 0 else coalesce(v_ability.current_cooldown_rounds, 0) end,
        'recharge_rounds_left', null
      )
  );
end;
$$;

drop function if exists public.reload_feature_resource(uuid);

grant execute on function public.odyssey_merge_runtime_data(jsonb, jsonb) to anon, authenticated;
grant execute on function public.odyssey_consume_character_ability_cost(uuid) to anon, authenticated;
grant execute on function public.reload_feature_resource(jsonb) to anon, authenticated;


create or replace function public.odyssey_collect_runtime_attack_modifiers(
  p_runtime_data jsonb,
  p_attack_type text
)
returns jsonb
language plpgsql
immutable
as $$
declare
  v_data jsonb := case
    when jsonb_typeof(p_runtime_data) = 'object' then p_runtime_data
    else '{}'::jsonb
  end;
  v_attack_type text := lower(trim(coalesce(p_attack_type, '')));
  v_condition_attack_type text := lower(trim(coalesce(v_data->'conditions'->>'attack_type', '')));
  v_attack_accuracy integer := 0;
  v_damage integer := 0;
  v_armor_pierce integer := 0;
  v_aim_difficulty integer := 0;
  v_range integer := 0;
  v_skip_damage boolean := false;
  v_on_hit jsonb := '[]'::jsonb;
  v_entry jsonb;
begin
  if v_condition_attack_type <> '' and v_condition_attack_type <> v_attack_type then
    return jsonb_build_object(
      'applied', false,
      'attack_accuracy', 0,
      'damage', 0,
      'armor_pierce', 0,
      'aim_difficulty', 0,
      'range', 0,
      'skip_damage', false,
      'on_hit', '[]'::jsonb
    );
  end if;

  for v_entry in
    select value
    from jsonb_array_elements(
      case
        when jsonb_typeof(v_data->'modifiers') = 'array' then v_data->'modifiers'
        else '[]'::jsonb
      end
    )
  loop
    case lower(trim(coalesce(v_entry->>'target', '')))
      when 'attack_accuracy' then
        v_attack_accuracy := v_attack_accuracy + coalesce(nullif(trim(coalesce(v_entry->>'value', '')), '')::integer, 0);
      when 'damage' then
        v_damage := v_damage + coalesce(nullif(trim(coalesce(v_entry->>'value', '')), '')::integer, 0);
      when 'armor_pierce' then
        v_armor_pierce := v_armor_pierce + coalesce(nullif(trim(coalesce(v_entry->>'value', '')), '')::integer, 0);
      when 'aim_difficulty' then
        v_aim_difficulty := v_aim_difficulty + coalesce(nullif(trim(coalesce(v_entry->>'value', '')), '')::integer, 0);
      when 'range' then
        v_range := v_range + coalesce(nullif(trim(coalesce(v_entry->>'value', '')), '')::integer, 0);
      else
        null;
    end case;
  end loop;

  if coalesce(v_data->>'skip_damage', 'false') in ('true', '1', 'yes', 'on') then
    v_skip_damage := true;
  end if;

  if jsonb_typeof(v_data->'on_hit') = 'array' then
    v_on_hit := v_data->'on_hit';
  end if;

  return jsonb_build_object(
    'applied', true,
    'attack_accuracy', v_attack_accuracy,
    'damage', v_damage,
    'armor_pierce', v_armor_pierce,
    'aim_difficulty', v_aim_difficulty,
    'range', v_range,
    'skip_damage', v_skip_damage,
    'on_hit', v_on_hit
  );
end;
$$;

do $$
declare
  v_function_def text;
begin
  select pg_get_functiondef(p.oid)
  into v_function_def
  from pg_proc p
  join pg_namespace n on n.oid = p.pronamespace
  where n.nspname = 'public'
    and p.proname = 'odyssey_perform_weapon_attack'
    and pg_get_function_identity_arguments(p.oid) = 'p_payload jsonb';

  if v_function_def is null then
    raise exception 'Function public.odyssey_perform_weapon_attack(jsonb) was not found.';
  end if;

  if position('v_armor_pierce := greatest(v_armor_pierce + v_feature_armor_pierce_modifier, 0);' in v_function_def) > 0 then
    v_function_def := replace(
      v_function_def,
      'v_armor_pierce := greatest(v_armor_pierce + v_feature_armor_pierce_modifier, 0);',
      'v_armor_pierce := coalesce(v_armor_pierce, 0) + v_feature_armor_pierce_modifier;'
    );
  end if;

  if position($needle$v_effective_armor := case
      when v_attack_type = 'ranged' then greatest(v_raw_armor_value - v_armor_pierce, 0)
      else v_raw_armor_value
    end;$needle$ in v_function_def) > 0 then
    v_function_def := replace(
      v_function_def,
      $old$v_effective_armor := case
      when v_attack_type = 'ranged' then greatest(v_raw_armor_value - v_armor_pierce, 0)
      else v_raw_armor_value
    end;$old$,
      $new$v_effective_armor := greatest(v_raw_armor_value - v_armor_pierce, 0);$new$
    );
  elsif position($needle$if v_attack_type = 'ranged' then
      v_effective_armor := greatest(v_raw_armor_value - v_armor_pierce, 0);
    else
      v_effective_armor := v_raw_armor_value;
    end if;$needle$ in v_function_def) > 0 then
    v_function_def := replace(
      v_function_def,
      $old$if v_attack_type = 'ranged' then
      v_effective_armor := greatest(v_raw_armor_value - v_armor_pierce, 0);
    else
      v_effective_armor := v_raw_armor_value;
    end if;$old$,
      $new$v_effective_armor := greatest(v_raw_armor_value - v_armor_pierce, 0);$new$
    );
  end if;

  if position('case when v_attack_type = ''ranged'' then v_armor_pierce else 0 end' in v_function_def) > 0 then
    v_function_def := replace(
      v_function_def,
      'case when v_attack_type = ''ranged'' then v_armor_pierce else 0 end',
