  if position(''pending_saves'', v_pending_saves' in v_function_def) = 0 then
    v_function_def := replace(
      v_function_def,
      '''resource'', v_resource_result,
    ''expired_attack_effects'', v_expired_attack_effects',
      '''resource'', v_resource_result,
    ''pending_saves'', v_pending_saves,
