create or replace function public.get_creator_reference_data()
returns jsonb
language sql
stable
as $$
  select jsonb_build_object(
    'ok', true,
    'attributes',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', a.id,
              'code', a.code,
              'name', a.name
            )
            order by a.sort_order, a.name, a.code
          )
          from public.odyssey_attribute_defs a
        ),
        '[]'::jsonb
      ),
    'skills',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', s.id,
              'code', s.code,
              'name', s.name,
              'category', s.category
            )
            order by s.category, s.sort_order, s.name, s.code
          )
          from public.odyssey_skill_defs s
        ),
        '[]'::jsonb
      ),
    'skill_categories',
      jsonb_build_array(
        'combat',
        'applied',
        'survival',
        'vehicle',
        'social',
        'passive',
        'psionic',
        'abilities',
        'custom'
      ),
    'calibers',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', c.id,
              'code', c.code,
              'name', c.name,
              'base_damage_per_round', c.base_damage_per_round
            )
            order by c.sort_order, c.name, c.code
          )
          from public.odyssey_caliber_defs c
        ),
        '[]'::jsonb
      ),
    'weapon_classes',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', wc.id,
              'code', wc.code,
              'name', wc.name
            )
            order by wc.sort_order, wc.name, wc.code
          )
          from public.odyssey_weapon_class_defs wc
        ),
        '[]'::jsonb
      ),
    'range_profiles',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', rp.id,
              'code', rp.code,
              'name', rp.name
            )
            order by rp.sort_order, rp.name, rp.code
          )
          from public.odyssey_range_profile_defs rp
        ),
        '[]'::jsonb
      ),
    'fire_modes',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', fm.id,
              'code', fm.code,
              'name', fm.name,
              'accuracy_modifier', fm.accuracy_modifier
            )
            order by fm.sort_order, fm.name, fm.code
          )
          from public.odyssey_fire_mode_defs fm
        ),
        '[]'::jsonb
      ),
    'magazine_definitions',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', m.id,
              'code', m.code,
              'name', m.name,
              'capacity', m.capacity,
              'caliber_id', m.caliber_id,
              'caliber_code', caliber.code,
              'caliber_name', caliber.name
            )
            order by m.sort_order, m.name, m.code
          )
          from public.odyssey_magazine_defs m
          join public.odyssey_caliber_defs caliber on caliber.id = m.caliber_id
        ),
        '[]'::jsonb
      ),
    'body_part_definitions',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', b.id,
              'code', b.code,
              'name', b.name,
              'category', b.category,
              'can_be_targeted', b.can_be_targeted
            )
            order by b.sort_order, b.name, b.code
          )
          from public.odyssey_body_part_defs b
        ),
        '[]'::jsonb
      ),
    'resource_pools',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', rp.id,
              'code', rp.code,
              'name', rp.name
            )
            order by rp.sort_order, rp.name, rp.code
          )
          from public.odyssey_resource_pool_defs rp
        ),
        '[]'::jsonb
      ),
    'abilities',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', a.id,
              'code', a.code,
              'name', a.name,
              'ability_kind', a.ability_kind,
              'source_type', a.source_type
            )
            order by a.sort_order, a.name, a.code
          )
          from public.odyssey_ability_defs a
        ),
        '[]'::jsonb
      ),
    'weapon_feature_definitions',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', f.id,
              'code', f.code,
              'name', f.name,
              'feature_type', f.feature_type,
              'activation_type', f.activation_type
            )
            order by f.sort_order, f.name, f.code
          )
          from public.odyssey_weapon_feature_defs f
        ),
        '[]'::jsonb
      ),
    'armor_classes',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', a.id,
              'code', a.code,
              'name', a.name,
              'min_total_armor', a.min_total_armor,
              'max_total_armor', a.max_total_armor
            )
            order by a.sort_order, a.min_total_armor, a.code
          )
          from public.odyssey_armor_class_defs a
        ),
        '[]'::jsonb
      ),
    'equipment_item_types',
      jsonb_build_array(
        'armor',
        'shield',
        'implant',
        'prosthetic',
        'device',
        'exoskeleton',
        'closed_suit'
      )
  );
$$;

create or replace function public.odyssey_creator_build_skill_bundle(
  p_skill_def_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_skill jsonb := null;
  v_level_requirements jsonb := '[]'::jsonb;
begin
  select jsonb_build_object(
    'id', d.id,
    'code', d.code,
    'name', d.name,
    'category', d.category,
    'max_level', d.max_level,
    'main_attribute_id', d.main_attribute_id,
    'main_attribute_code', main_attr.code,
    'main_attribute_name', main_attr.name,
    'secondary_attribute_id', d.secondary_attribute_id,
    'secondary_attribute_code', secondary_attr.code,
    'secondary_attribute_name', secondary_attr.name,
    'description', coalesce(d.description, ''),
    'tags', coalesce(d.tags, '[]'::jsonb),
    'is_custom', d.is_custom,
    'sort_order', d.sort_order,
    'created_at', d.created_at,
    'updated_at', d.updated_at
  )
  into v_skill
  from public.odyssey_skill_defs d
  left join public.odyssey_attribute_defs main_attr on main_attr.id = d.main_attribute_id
  left join public.odyssey_attribute_defs secondary_attr on secondary_attr.id = d.secondary_attribute_id
  where d.id = p_skill_def_id;

  if v_skill is null then
    return public.odyssey_creator_error(
      'SKILL_DEF_NOT_FOUND',
      'Skill definition was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown skill definition id.'))
    );
  end if;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'id', req.id,
        'level', req.level,
        'main_attribute_required', req.main_attribute_required,
        'secondary_attribute_required', req.secondary_attribute_required,
        'requires_critical_successes', req.requires_critical_successes,
        'notes', coalesce(req.notes, ''),
        'created_at', req.created_at,
        'updated_at', req.updated_at
      )
      order by req.level, req.id
    ),
    '[]'::jsonb
  )
  into v_level_requirements
  from public.odyssey_skill_level_requirements req
  where req.skill_def_id = p_skill_def_id;

  return jsonb_build_object(
    'ok', true,
    'skill', v_skill,
    'level_requirements', v_level_requirements
  );
end;
$$;

create or replace function public.creator_list_skills(
  p_search text default null,
  p_categories jsonb default null
)
returns jsonb
language sql
stable
as $$
  with search_input as (
    select nullif(trim(coalesce(p_search, '')), '') as search_text
  ),
  requested_categories as (
    select lower(trim(value)) as category
    from jsonb_array_elements_text(
      case
        when jsonb_typeof(p_categories) = 'array' then p_categories
        else '[]'::jsonb
      end
    ) value
    where lower(trim(value)) in ('combat', 'applied', 'survival', 'vehicle', 'social', 'passive', 'psionic', 'abilities', 'custom')
  ),
  filtered as (
    select
      d.id,
      d.code,
      d.name,
      d.category,
      d.max_level,
      d.sort_order,
      d.main_attribute_id,
      main_attr.code as main_attribute_code,
      main_attr.name as main_attribute_name,
      d.secondary_attribute_id,
      secondary_attr.code as secondary_attribute_code,
      secondary_attr.name as secondary_attribute_name,
      coalesce(d.tags, '[]'::jsonb) as tags
    from public.odyssey_skill_defs d
    left join public.odyssey_attribute_defs main_attr on main_attr.id = d.main_attribute_id
    left join public.odyssey_attribute_defs secondary_attr on secondary_attr.id = d.secondary_attribute_id
    cross join search_input
    where (
      not exists (select 1 from requested_categories)
      or d.category in (select category from requested_categories)
    )
      and (
        search_input.search_text is null
        or d.code ilike '%' || search_input.search_text || '%'
        or d.name ilike '%' || search_input.search_text || '%'
        or d.category ilike '%' || search_input.search_text || '%'
        or coalesce(main_attr.name, '') ilike '%' || search_input.search_text || '%'
        or coalesce(secondary_attr.name, '') ilike '%' || search_input.search_text || '%'
        or d.tags::text ilike '%' || search_input.search_text || '%'
      )
  )
  select jsonb_build_object(
    'ok', true,
    'items',
      coalesce(
        jsonb_agg(
          jsonb_build_object(
            'id', id,
            'code', code,
            'name', name,
            'category', category,
            'max_level', max_level,
            'main_attribute_id', main_attribute_id,
            'main_attribute_code', main_attribute_code,
            'main_attribute_name', main_attribute_name,
            'secondary_attribute_id', secondary_attribute_id,
            'secondary_attribute_code', secondary_attribute_code,
            'secondary_attribute_name', secondary_attribute_name,
            'tags', tags
          )
          order by category, sort_order, name, code
        ),
        '[]'::jsonb
      )
  )
  from filtered;
$$;

create or replace function public.creator_get_skill(
  p_skill_def_id uuid
)
returns jsonb
language sql
stable
as $$
  select public.odyssey_creator_build_skill_bundle(p_skill_def_id);
$$;

create or replace function public.creator_upsert_skill(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := public.odyssey_creator_normalize_json_object(p_payload);
  v_id uuid := nullif(trim(coalesce(v_payload->>'id', '')), '')::uuid;
  v_code text := public.odyssey_creator_normalize_code(v_payload->>'code');
  v_name text := trim(coalesce(v_payload->>'name', ''));
  v_category text := lower(trim(coalesce(v_payload->>'category', 'applied')));
  v_max_level integer := coalesce(nullif(trim(coalesce(v_payload->>'max_level', '')), '')::integer, 5);
  v_main_attribute_id uuid := nullif(trim(coalesce(v_payload->>'main_attribute_id', '')), '')::uuid;
  v_secondary_attribute_id uuid := nullif(trim(coalesce(v_payload->>'secondary_attribute_id', '')), '')::uuid;
  v_description text := coalesce(v_payload->>'description', '');
  v_tags jsonb := public.odyssey_creator_normalize_text_array(v_payload->'tags');
  v_sort_order integer := coalesce(nullif(trim(coalesce(v_payload->>'sort_order', '')), '')::integer, 0);
  v_entity_id uuid := null;
  v_result jsonb := '{}'::jsonb;
begin
  if v_code = '' or not public.odyssey_creator_is_valid_code(v_code) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'code must match ^[a-z][a-z0-9_]*$.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Use lowercase snake_case starting with a letter.'))
    );
  end if;

  if v_name = '' then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'name is required.',
      jsonb_build_array(jsonb_build_object('field', 'name', 'message', 'Name cannot be empty.'))
    );
  end if;

  if v_category not in ('combat', 'applied', 'survival', 'vehicle', 'social', 'passive', 'psionic', 'abilities', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'category is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'category', 'message', 'Unsupported skill category.'))
    );
  end if;

  if v_max_level not in (1, 3, 5) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'max_level must be 1, 3, or 5.',
      jsonb_build_array(jsonb_build_object('field', 'max_level', 'message', 'Use one of: 1, 3, 5.'))
    );
  end if;

  if v_main_attribute_id is not null and not exists (
    select 1
    from public.odyssey_attribute_defs attr
    where attr.id = v_main_attribute_id
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'main_attribute_id references an unknown attribute.',
      jsonb_build_array(jsonb_build_object('field', 'main_attribute_id', 'message', 'Unknown attribute id.'))
    );
  end if;

  if v_secondary_attribute_id is not null and not exists (
    select 1
    from public.odyssey_attribute_defs attr
    where attr.id = v_secondary_attribute_id
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'secondary_attribute_id references an unknown attribute.',
      jsonb_build_array(jsonb_build_object('field', 'secondary_attribute_id', 'message', 'Unknown attribute id.'))
    );
  end if;

  if v_id is not null then
    select d.id
    into v_entity_id
    from public.odyssey_skill_defs d
    where d.id = v_id;

    if v_entity_id is null then
      return public.odyssey_creator_error(
        'SKILL_DEF_NOT_FOUND',
        'Skill definition was not found for update.',
        jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown skill definition id.'))
      );
    end if;
  else
    select d.id
    into v_entity_id
    from public.odyssey_skill_defs d
    where d.code = v_code
    limit 1;
  end if;

  if exists (
    select 1
    from public.odyssey_skill_defs d
    where d.code = v_code
      and d.id <> coalesce(v_entity_id, '00000000-0000-0000-0000-000000000000'::uuid)
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'Skill code must be unique.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Duplicate skill code.'))
    );
  end if;

  if v_entity_id is null then
    insert into public.odyssey_skill_defs (
      code,
      name,
      category,
      max_level,
      main_attribute_id,
      secondary_attribute_id,
      description,
      tags,
      is_custom,
      sort_order
    )
    values (
      v_code,
      v_name,
      v_category,
      v_max_level,
      v_main_attribute_id,
      v_secondary_attribute_id,
      nullif(v_description, ''),
      v_tags,
      true,
      v_sort_order
    )
    returning id into v_entity_id;
  else
    update public.odyssey_skill_defs
    set
      code = v_code,
      name = v_name,
      category = v_category,
      max_level = v_max_level,
      main_attribute_id = v_main_attribute_id,
      secondary_attribute_id = v_secondary_attribute_id,
      description = nullif(v_description, ''),
      tags = v_tags,
      sort_order = v_sort_order
    where id = v_entity_id;
  end if;

  v_result := public.creator_get_skill(v_entity_id);

  return jsonb_build_object(
    'ok', true,
    'entity_id', v_entity_id,
    'entity', v_result,
    'warnings', '[]'::jsonb
  );
end;
$$;

create or replace function public.creator_delete_skill(
  p_skill_def_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_skill public.odyssey_skill_defs%rowtype;
  v_character_skill_count integer := 0;
  v_weapon_model_count integer := 0;
  v_weapon_profile_count integer := 0;
  v_perk_count integer := 0;
  v_ability_count integer := 0;
  v_details jsonb := '[]'::jsonb;
begin
  select *
  into v_skill
  from public.odyssey_skill_defs d
  where d.id = p_skill_def_id;

  if not found then
    return public.odyssey_creator_error(
      'SKILL_DEF_NOT_FOUND',
      'Skill definition was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown skill definition id.'))
    );
  end if;

  select count(*)::integer into v_character_skill_count
  from public.odyssey_character_skills s
  where s.skill_def_id = p_skill_def_id;

  select count(*)::integer into v_weapon_model_count
  from public.odyssey_weapon_model_defs w
  where w.linked_skill_id = p_skill_def_id;

  select count(*)::integer into v_weapon_profile_count
  from public.odyssey_weapon_model_profiles p
  where p.linked_skill_id = p_skill_def_id;

  select count(*)::integer into v_perk_count
  from public.odyssey_perk_defs p
  where p.skill_def_id = p_skill_def_id;

  select count(*)::integer into v_ability_count
  from public.odyssey_ability_defs a
  where a.linked_skill_id = p_skill_def_id;

  select coalesce(jsonb_agg(item), '[]'::jsonb)
  into v_details
  from (
    select jsonb_build_object('field', 'character_skills', 'count', v_character_skill_count, 'message', 'Skill is assigned to one or more characters.') as item
    where v_character_skill_count > 0
    union all
    select jsonb_build_object('field', 'weapon_models', 'count', v_weapon_model_count, 'message', 'Skill is used by one or more weapon models.') as item
    where v_weapon_model_count > 0
    union all
    select jsonb_build_object('field', 'weapon_profiles', 'count', v_weapon_profile_count, 'message', 'Skill is used by one or more weapon profiles.') as item
    where v_weapon_profile_count > 0
    union all
    select jsonb_build_object('field', 'perks', 'count', v_perk_count, 'message', 'Skill is referenced by one or more perks.') as item
    where v_perk_count > 0
    union all
    select jsonb_build_object('field', 'abilities', 'count', v_ability_count, 'message', 'Skill is referenced by one or more abilities.') as item
    where v_ability_count > 0
  ) dependency_rows;

  if v_details <> '[]'::jsonb then
    return public.odyssey_creator_error(
      'SKILL_DEF_IN_USE',
      'Skill definition is still referenced and cannot be deleted.',
      v_details
    );
  end if;

  delete from public.odyssey_skill_defs d
  where d.id = p_skill_def_id;

  return jsonb_build_object(
    'ok', true,
    'deleted_id', p_skill_def_id,
    'deleted_code', v_skill.code
  );
end;
$$;

create or replace function public.odyssey_creator_build_equipment_catalog_bundle(
  p_equipment_model_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_model jsonb := null;
  v_ability_links jsonb := '[]'::jsonb;
begin
  select jsonb_build_object(
    'id', m.id,
    'code', m.code,
    'name', m.name,
    'item_type', m.item_type,
    'description', m.description,
    'armor_value', m.armor_value,
    'armor_max_minor', m.armor_max_minor,
    'armor_max_serious', m.armor_max_serious,
    'armor_max_critical', m.armor_max_critical,
    'default_body_part_code', m.default_body_part_code,
    'can_equip', m.can_equip,
    'can_equip_to_body_part', m.can_equip_to_body_part,
    'effect_data', coalesce(m.effect_data, '{}'::jsonb),
    'flags', coalesce(m.flags, '{}'::jsonb),
    'tags', coalesce(m.tags, '[]'::jsonb),
    'is_custom', m.is_custom,
    'sort_order', m.sort_order,
    'created_at', m.created_at,
    'updated_at', m.updated_at
  )
  into v_model
  from public.odyssey_equipment_model_defs m
  where m.id = p_equipment_model_id
    and m.item_type in ('armor', 'shield', 'implant', 'prosthetic', 'device', 'exoskeleton', 'closed_suit');

  if v_model is null then
    return public.odyssey_creator_error(
      'EQUIPMENT_MODEL_NOT_FOUND',
      'Equipment model was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown equipment model id.'))
    );
  end if;

  select coalesce(
    jsonb_agg(item order by sort_order, ability_name, ability_code),
    '[]'::jsonb
  )
  into v_ability_links
  from (
    select
      link.sort_order,
      ability.name as ability_name,
      ability.code as ability_code,
      jsonb_build_object(
        'id', link.id,
        'ability_def_id', link.ability_def_id,
        'ability_code', ability.code,
        'ability_name', ability.name,
        'ability_kind', ability.ability_kind,
        'source_type', ability.source_type,
        'grant_mode', link.grant_mode,
        'is_enabled', link.is_enabled,
        'sort_order', link.sort_order,
        'data', coalesce(link.data, '{}'::jsonb)
      ) as item
    from public.odyssey_equipment_model_abilities link
    join public.odyssey_ability_defs ability on ability.id = link.ability_def_id
    where link.equipment_model_id = p_equipment_model_id
  ) rows;

  return jsonb_build_object(
    'ok', true,
    'equipment_model', v_model,
    'ability_links', v_ability_links
  );
end;
$$;

create or replace function public.creator_list_equipment_models(
  p_search text default null,
  p_item_types jsonb default null
)
returns jsonb
language sql
stable
as $$
  with search_input as (
    select nullif(trim(coalesce(p_search, '')), '') as search_text
  ),
  requested_item_types as (
    select lower(trim(value)) as item_type
    from jsonb_array_elements_text(
      case
        when jsonb_typeof(p_item_types) = 'array' then p_item_types
        else '[]'::jsonb
      end
    ) value
    where lower(trim(value)) in ('armor', 'shield', 'implant', 'prosthetic', 'device', 'exoskeleton', 'closed_suit')
  ),
  filtered as (
    select
      model.id,
      model.code,
      model.name,
      model.sort_order,
      model.item_type,
      model.armor_value,
      model.armor_max_minor,
      model.armor_max_serious,
      model.armor_max_critical,
      model.default_body_part_code,
      model.can_equip,
      model.can_equip_to_body_part,
      coalesce(model.tags, '[]'::jsonb) as tags
    from public.odyssey_equipment_model_defs model
    cross join search_input
    where (
      (not exists (select 1 from requested_item_types)
        and model.item_type in ('armor', 'shield', 'implant', 'prosthetic', 'device', 'exoskeleton', 'closed_suit'))
      or model.item_type in (select item_type from requested_item_types)
    )
      and (
        search_input.search_text is null
        or model.code ilike '%' || search_input.search_text || '%'
        or model.name ilike '%' || search_input.search_text || '%'
        or model.item_type ilike '%' || search_input.search_text || '%'
        or model.tags::text ilike '%' || search_input.search_text || '%'
      )
  )
  select jsonb_build_object(
    'ok', true,
    'items',
      coalesce(
        jsonb_agg(
          jsonb_build_object(
            'id', id,
            'code', code,
            'name', name,
            'item_type', item_type,
            'armor_value', armor_value,
            'armor_max_minor', armor_max_minor,
            'armor_max_serious', armor_max_serious,
            'armor_max_critical', armor_max_critical,
            'default_body_part_code', default_body_part_code,
            'can_equip', can_equip,
            'can_equip_to_body_part', can_equip_to_body_part,
            'tags', tags
          )
          order by item_type, sort_order, name, code
        ),
        '[]'::jsonb
      )
  )
  from filtered;
$$;

create or replace function public.creator_get_equipment_model(
  p_equipment_model_id uuid
)
returns jsonb
language sql
stable
as $$
  select public.odyssey_creator_build_equipment_catalog_bundle(p_equipment_model_id);
$$;

create or replace function public.creator_upsert_equipment_model(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := public.odyssey_creator_normalize_json_object(p_payload);
  v_id uuid := nullif(trim(coalesce(v_payload->>'id', '')), '')::uuid;
  v_code text := public.odyssey_creator_normalize_code(v_payload->>'code');
  v_name text := trim(coalesce(v_payload->>'name', ''));
  v_item_type text := lower(trim(coalesce(v_payload->>'item_type', 'armor')));
  v_description text := coalesce(v_payload->>'description', '');
  v_armor_value integer := coalesce(nullif(trim(coalesce(v_payload->>'armor_value', '')), '')::integer, 0);
  v_armor_max_minor integer := coalesce(nullif(trim(coalesce(v_payload->>'armor_max_minor', '')), '')::integer, 0);
  v_armor_max_serious integer := coalesce(nullif(trim(coalesce(v_payload->>'armor_max_serious', '')), '')::integer, 0);
  v_armor_max_critical integer := coalesce(nullif(trim(coalesce(v_payload->>'armor_max_critical', '')), '')::integer, 0);
  v_default_body_part_code text := nullif(lower(trim(coalesce(v_payload->>'default_body_part_code', ''))), '');
  v_can_equip boolean := coalesce(nullif(trim(coalesce(v_payload->>'can_equip', '')), '')::boolean, true);
  v_can_equip_to_body_part boolean := coalesce(nullif(trim(coalesce(v_payload->>'can_equip_to_body_part', '')), '')::boolean, true);
  v_effect_data jsonb := public.odyssey_creator_normalize_json_object(v_payload->'effect_data');
  v_flags jsonb := public.odyssey_creator_normalize_json_object(v_payload->'flags');
  v_tags jsonb := public.odyssey_creator_normalize_text_array(v_payload->'tags');
  v_sort_order integer := coalesce(nullif(trim(coalesce(v_payload->>'sort_order', '')), '')::integer, 0);
  v_ability_links jsonb := public.odyssey_creator_normalize_json_array(v_payload->'ability_links');
  v_entity_id uuid := null;
  v_existing_item_type text := null;
  v_result jsonb := '{}'::jsonb;
  v_processed_link_ids uuid[] := '{}'::uuid[];
  v_entry jsonb := '{}'::jsonb;
  v_ability_id uuid := null;
  v_link_id uuid := null;
  v_grant_mode text := '';
  v_is_enabled boolean := true;
  v_link_sort integer := 0;
  v_link_data jsonb := '{}'::jsonb;
begin
  if v_item_type not in ('armor', 'shield', 'implant', 'prosthetic', 'device', 'exoskeleton', 'closed_suit') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'item_type is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'item_type', 'message', 'Unsupported equipment item_type.'))
    );
  end if;

  if v_code = '' or not public.odyssey_creator_is_valid_code(v_code) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'code must match ^[a-z][a-z0-9_]*$.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Use lowercase snake_case starting with a letter.'))
    );
  end if;

  if v_name = '' then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'name is required.',
      jsonb_build_array(jsonb_build_object('field', 'name', 'message', 'Name cannot be empty.'))
    );
  end if;

  if v_armor_value < 0
    or v_armor_max_minor < 0
    or v_armor_max_serious < 0
    or v_armor_max_critical < 0 then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'armor_value and armor tier caps must be >= 0.',
      jsonb_build_array(jsonb_build_object('field', 'armor_value', 'message', 'Values cannot be negative.'))
    );
  end if;

  if v_default_body_part_code is not null and not exists (
    select 1
    from public.odyssey_body_part_defs body_part
    where body_part.code = v_default_body_part_code
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'default_body_part_code references an unknown body part.',
      jsonb_build_array(jsonb_build_object('field', 'default_body_part_code', 'message', 'Unknown body part code.'))
    );
  end if;

  if v_id is not null then
    select model.id, model.item_type
    into v_entity_id, v_existing_item_type
    from public.odyssey_equipment_model_defs model
    where model.id = v_id;

    if v_entity_id is null then
      return public.odyssey_creator_error(
        'EQUIPMENT_MODEL_NOT_FOUND',
        'Equipment model was not found for update.',
        jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown equipment model id.'))
      );
    end if;
  else
    select model.id, model.item_type
    into v_entity_id, v_existing_item_type
    from public.odyssey_equipment_model_defs model
    where model.code = v_code
    limit 1;
  end if;

  if v_entity_id is not null and v_existing_item_type not in ('armor', 'shield', 'implant', 'prosthetic', 'device', 'exoskeleton', 'closed_suit') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'The selected equipment model belongs to another module.',
      jsonb_build_array(jsonb_build_object('field', 'item_type', 'message', 'This equipment model cannot be edited by the equipment creator.'))
    );
  end if;

  if exists (
    select 1
    from public.odyssey_equipment_model_defs model
    where model.code = v_code
      and model.id <> coalesce(v_entity_id, '00000000-0000-0000-0000-000000000000'::uuid)
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'Equipment model code must be unique.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Duplicate equipment model code.'))
    );
  end if;

  if v_entity_id is null then
    insert into public.odyssey_equipment_model_defs (
      code,
      name,
      item_type,
      description,
      armor_value,
      armor_max_minor,
      armor_max_serious,
      armor_max_critical,
      default_body_part_code,
      can_equip,
      can_equip_to_body_part,
      effect_data,
      flags,
      tags,
      is_custom,
      sort_order
    )
    values (
      v_code,
      v_name,
      v_item_type,
      v_description,
      v_armor_value,
      v_armor_max_minor,
      v_armor_max_serious,
      v_armor_max_critical,
      v_default_body_part_code,
      v_can_equip,
      v_can_equip_to_body_part,
      v_effect_data,
      v_flags,
      v_tags,
      true,
      v_sort_order
    )
    returning id into v_entity_id;
  else
    update public.odyssey_equipment_model_defs
    set
      code = v_code,
      name = v_name,
      item_type = v_item_type,
      description = v_description,
      armor_value = v_armor_value,
      armor_max_minor = v_armor_max_minor,
      armor_max_serious = v_armor_max_serious,
      armor_max_critical = v_armor_max_critical,
      default_body_part_code = v_default_body_part_code,
      can_equip = v_can_equip,
      can_equip_to_body_part = v_can_equip_to_body_part,
      effect_data = v_effect_data,
      flags = v_flags,
      tags = v_tags,
      sort_order = v_sort_order
    where id = v_entity_id;
  end if;

  for v_entry in
    select value
    from jsonb_array_elements(v_ability_links)
  loop
    v_link_id := nullif(trim(coalesce(v_entry->>'id', '')), '')::uuid;
    v_ability_id := nullif(trim(coalesce(v_entry->>'ability_def_id', '')), '')::uuid;
    v_grant_mode := lower(trim(coalesce(v_entry->>'grant_mode', 'grant')));
    v_is_enabled := coalesce(nullif(trim(coalesce(v_entry->>'is_enabled', '')), '')::boolean, true);
    v_link_sort := coalesce(nullif(trim(coalesce(v_entry->>'sort_order', '')), '')::integer, 0);
    v_link_data := public.odyssey_creator_normalize_json_object(v_entry->'data');

    if v_ability_id is null or not exists (
      select 1
      from public.odyssey_ability_defs ability
      where ability.id = v_ability_id
    ) then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'ability_links references an unknown ability.',
        jsonb_build_array(jsonb_build_object('field', 'ability_links', 'message', 'Unknown ability_def_id.'))
      );
    end if;

    if v_grant_mode not in ('grant', 'available', 'passive', 'activated') then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'ability_links grant_mode is invalid.',
        jsonb_build_array(jsonb_build_object('field', 'ability_links', 'message', 'grant_mode must be grant, available, passive, or activated.'))
      );
    end if;

    select link.id
    into v_link_id
    from public.odyssey_equipment_model_abilities link
    where link.equipment_model_id = v_entity_id
      and link.ability_def_id = v_ability_id
    for update;

    if v_link_id is null then
      insert into public.odyssey_equipment_model_abilities (
        equipment_model_id,
        ability_def_id,
        grant_mode,
        is_enabled,
        sort_order,
        data
      )
      values (
        v_entity_id,
        v_ability_id,
        v_grant_mode,
        v_is_enabled,
        v_link_sort,
        v_link_data
      )
      returning id into v_link_id;
    else
      update public.odyssey_equipment_model_abilities
      set
        grant_mode = v_grant_mode,
        is_enabled = v_is_enabled,
        sort_order = v_link_sort,
        data = v_link_data
      where id = v_link_id;
    end if;

    v_processed_link_ids := array_append(v_processed_link_ids, v_link_id);
  end loop;

  delete from public.odyssey_equipment_model_abilities
  where equipment_model_id = v_entity_id
    and not (id = any(v_processed_link_ids));

  v_result := public.creator_get_equipment_model(v_entity_id);

  return jsonb_build_object(
    'ok', true,
    'entity_id', v_entity_id,
    'entity', v_result,
    'warnings', '[]'::jsonb
  );
end;
$$;

create or replace function public.creator_delete_equipment_model(
  p_equipment_model_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_model public.odyssey_equipment_model_defs%rowtype;
  v_character_item_count integer := 0;
  v_details jsonb := '[]'::jsonb;
begin
  select *
  into v_model
  from public.odyssey_equipment_model_defs model
  where model.id = p_equipment_model_id
    and model.item_type in ('armor', 'shield', 'implant', 'prosthetic', 'device', 'exoskeleton', 'closed_suit');

  if not found then
    return public.odyssey_creator_error(
      'EQUIPMENT_MODEL_NOT_FOUND',
      'Equipment model was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown equipment model id.'))
    );
  end if;

  select count(*)::integer
  into v_character_item_count
  from public.odyssey_character_equipment_items item
  where item.equipment_model_id = p_equipment_model_id;

  select coalesce(jsonb_agg(item), '[]'::jsonb)
  into v_details
  from (
    select jsonb_build_object('field', 'character_equipment_items', 'count', v_character_item_count, 'message', 'Equipment model is assigned to one or more character equipment items.') as item
    where v_character_item_count > 0
  ) dependency_rows;

  if v_details <> '[]'::jsonb then
    return public.odyssey_creator_error(
      'EQUIPMENT_MODEL_IN_USE',
      'Equipment model is still referenced and cannot be deleted.',
      v_details
    );
  end if;

  delete from public.odyssey_equipment_model_defs model
  where model.id = p_equipment_model_id;

  return jsonb_build_object(
    'ok', true,
    'deleted_id', p_equipment_model_id,
    'deleted_code', v_model.code,
    'deleted_item_type', v_model.item_type
  );
end;
$$;

grant execute on function public.odyssey_creator_build_skill_bundle(uuid) to anon, authenticated;
grant execute on function public.creator_list_skills(text, jsonb) to anon, authenticated;
grant execute on function public.creator_get_skill(uuid) to anon, authenticated;
grant execute on function public.creator_upsert_skill(jsonb) to anon, authenticated;
grant execute on function public.creator_delete_skill(uuid) to anon, authenticated;
grant execute on function public.odyssey_creator_build_equipment_catalog_bundle(uuid) to anon, authenticated;
grant execute on function public.creator_list_equipment_models(text, jsonb) to anon, authenticated;
grant execute on function public.creator_get_equipment_model(uuid) to anon, authenticated;
grant execute on function public.creator_upsert_equipment_model(jsonb) to anon, authenticated;
grant execute on function public.creator_delete_equipment_model(uuid) to anon, authenticated;

alter table public.odyssey_effect_defs
  drop constraint if exists odyssey_effect_defs_category_check;

alter table public.odyssey_effect_defs
  add constraint odyssey_effect_defs_category_check
  check (
    category in (
      'buff',
      'debuff',
      'condition',
      'combat',
      'psionic',
      'equipment',
      'weapon',
      'armor',
      'narrative',
      'custom',
      'recovery',
      'damage',
      'utility'
    )
  );

create or replace function public.odyssey_creator_build_effect_bundle(
  p_effect_def_id uuid
)
returns jsonb
language plpgsql
stable
as $$
declare
  v_effect jsonb := null;
begin
  select jsonb_build_object(
    'id', d.id,
    'code', d.code,
    'name', d.name,
    'category', d.category,
    'description', coalesce(d.description, ''),
    'default_duration_type', d.default_duration_type,
    'default_rounds', d.default_rounds,
    'stacking_mode', d.stacking_mode,
    'is_negative', d.is_negative,
    'is_narrative', d.is_narrative,
    'data', coalesce(d.data, '{}'::jsonb),
    'tags', coalesce(d.tags, '[]'::jsonb),
    'is_custom', d.is_custom,
    'sort_order', d.sort_order,
    'created_at', d.created_at,
    'updated_at', d.updated_at
  )
  into v_effect
  from public.odyssey_effect_defs d
  where d.id = p_effect_def_id;

  if v_effect is null then
    return public.odyssey_creator_error(
      'EFFECT_DEF_NOT_FOUND',
      'Effect definition was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown effect definition id.'))
    );
  end if;

  return jsonb_build_object(
    'ok', true,
    'effect', v_effect
  );
end;
$$;

create or replace function public.creator_list_effects(
  p_search text default null,
  p_categories jsonb default null
)
returns jsonb
language sql
stable
as $$
  with search_input as (
    select nullif(trim(coalesce(p_search, '')), '') as search_text
  ),
  requested_categories as (
    select lower(trim(value)) as category
    from jsonb_array_elements_text(
      case
        when jsonb_typeof(p_categories) = 'array' then p_categories
        else '[]'::jsonb
      end
    ) value
    where trim(value) <> ''
  ),
  filtered as (
    select
      d.id,
      d.code,
      d.name,
      d.category,
      d.description,
      d.default_duration_type,
      d.default_rounds,
      d.stacking_mode,
      d.is_negative,
      d.is_narrative,
      d.tags,
      d.is_custom,
      d.sort_order,
      d.created_at,
      d.updated_at
    from public.odyssey_effect_defs d
    cross join search_input s
    where (
      s.search_text is null
      or d.code ilike '%' || s.search_text || '%'
      or d.name ilike '%' || s.search_text || '%'
      or coalesce(d.description, '') ilike '%' || s.search_text || '%'
      or exists (
        select 1
        from jsonb_array_elements_text(coalesce(d.tags, '[]'::jsonb)) tag(value)
        where tag.value ilike '%' || s.search_text || '%'
      )
    )
    and (
      not exists (select 1 from requested_categories)
      or lower(d.category) in (select category from requested_categories)
    )
  )
  select jsonb_build_object(
    'ok', true,
    'items',
      coalesce(
        (
          select jsonb_agg(
            jsonb_build_object(
              'id', f.id,
              'code', f.code,
              'name', f.name,
              'category', f.category,
              'description', coalesce(f.description, ''),
              'default_duration_type', f.default_duration_type,
              'default_rounds', f.default_rounds,
              'stacking_mode', f.stacking_mode,
              'is_negative', f.is_negative,
              'is_narrative', f.is_narrative,
              'tags', coalesce(f.tags, '[]'::jsonb),
              'is_custom', f.is_custom,
              'sort_order', f.sort_order,
              'created_at', f.created_at,
              'updated_at', f.updated_at
            )
            order by f.sort_order, f.name, f.code
          )
          from filtered f
        ),
        '[]'::jsonb
      )
  );
$$;

create or replace function public.creator_get_effect(
  p_effect_def_id uuid
)
returns jsonb
language sql
stable
as $$
  select public.odyssey_creator_build_effect_bundle(p_effect_def_id);
$$;

create or replace function public.creator_upsert_effect(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := public.odyssey_creator_normalize_json_object(p_payload);
  v_id uuid := nullif(trim(coalesce(v_payload->>'id', '')), '')::uuid;
  v_code text := public.odyssey_creator_normalize_code(v_payload->>'code');
  v_name text := trim(coalesce(v_payload->>'name', ''));
  v_category text := lower(trim(coalesce(v_payload->>'category', 'utility')));
  v_description text := coalesce(v_payload->>'description', '');
  v_default_duration_type text := lower(trim(coalesce(v_payload->>'default_duration_type', 'manual')));
  v_default_rounds integer := nullif(trim(coalesce(v_payload->>'default_rounds', '')), '')::integer;
  v_stacking_mode text := lower(trim(coalesce(v_payload->>'stacking_mode', 'replace')));
  v_is_negative boolean := coalesce(nullif(trim(coalesce(v_payload->>'is_negative', '')), '')::boolean, false);
  v_is_narrative boolean := coalesce(nullif(trim(coalesce(v_payload->>'is_narrative', '')), '')::boolean, false);
  v_data jsonb := public.odyssey_creator_normalize_json_object(v_payload->'data');
  v_tags jsonb := public.odyssey_creator_normalize_text_array(v_payload->'tags');
  v_sort_order integer := coalesce(nullif(trim(coalesce(v_payload->>'sort_order', '')), '')::integer, 0);
  v_effect_payload jsonb := public.odyssey_creator_normalize_json_object(v_data->'payload');
  v_scale jsonb := public.odyssey_creator_normalize_json_object(v_effect_payload->'scale');
  v_effect_type text := lower(trim(coalesce(v_effect_payload->>'type', '')));
  v_target_scope text := lower(trim(coalesce(v_effect_payload->>'target_scope', '')));
  v_tick_phase text := lower(trim(coalesce(v_effect_payload->>'tick_phase', '')));
  v_scale_metric text := lower(trim(coalesce(v_scale->>'metric', '')));
  v_resource_pool_id uuid := nullif(trim(coalesce(v_effect_payload->>'resource_pool_id', '')), '')::uuid;
  v_scale_base integer := coalesce(nullif(trim(coalesce(v_scale->>'base', '')), '')::integer, 0);
  v_scale_per_level integer := coalesce(nullif(trim(coalesce(v_scale->>'per_level', '')), '')::integer, 0);
  v_restore_disabled boolean := coalesce(nullif(trim(coalesce(v_effect_payload->>'restore_disabled', '')), '')::boolean, false);
  v_entity_id uuid := null;
  v_result jsonb := '{}'::jsonb;
begin
  if v_code = '' or not public.odyssey_creator_is_valid_code(v_code) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'code must match ^[a-z][a-z0-9_]*$.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Use lowercase snake_case starting with a letter.'))
    );
  end if;

  if v_name = '' then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'name is required.',
      jsonb_build_array(jsonb_build_object('field', 'name', 'message', 'Name cannot be empty.'))
    );
  end if;

  if v_category not in (
    'buff',
    'debuff',
    'condition',
    'combat',
    'psionic',
    'equipment',
    'weapon',
    'armor',
    'narrative',
    'custom',
    'recovery',
    'damage',
    'utility'
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'category is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'category', 'message', 'Unsupported effect category.'))
    );
  end if;

  if v_default_duration_type not in ('manual', 'rounds', 'until_turn_start', 'until_turn_end', 'scene', 'until_used') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'default_duration_type is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'default_duration_type', 'message', 'Unsupported duration type.'))
    );
  end if;

  if v_default_duration_type = 'rounds' and coalesce(v_default_rounds, 0) < 1 then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'default_rounds must be at least 1 when duration type is rounds.',
      jsonb_build_array(jsonb_build_object('field', 'default_rounds', 'message', 'Use a positive round count.'))
    );
  end if;

  if v_stacking_mode not in ('replace', 'stack', 'highest', 'lowest', 'unique') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'stacking_mode is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'stacking_mode', 'message', 'Unsupported stacking mode.'))
    );
  end if;

  if v_effect_type <> '' and v_effect_type not in (
    'modifiers_flags',
    'periodic_damage',
    'periodic_heal',
    'body_part_heal',
    'armor_repair',
    'resource_restore',
    'custom'
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'effect payload type is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'data.payload.type', 'message', 'Unsupported effect payload type.'))
    );
  end if;

  if v_target_scope <> '' and v_target_scope not in ('character', 'selected_body_part', 'selected_armor_item') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'target_scope is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'data.payload.target_scope', 'message', 'Unsupported target scope.'))
    );
  end if;

  if v_tick_phase <> '' and v_tick_phase not in ('turn_start', 'turn_end') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'tick_phase is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'data.payload.tick_phase', 'message', 'Unsupported tick phase.'))
    );
  end if;

  if v_scale_metric <> '' and v_scale_metric not in ('points', 'hp', 'minor', 'serious', 'critical') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'scale.metric is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'data.payload.scale.metric', 'message', 'Unsupported scale metric.'))
    );
  end if;

  if v_resource_pool_id is not null and not exists (
    select 1
    from public.odyssey_resource_pool_defs pool
    where pool.id = v_resource_pool_id
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'resource_pool_id references an unknown resource pool.',
      jsonb_build_array(jsonb_build_object('field', 'data.payload.resource_pool_id', 'message', 'Unknown resource pool id.'))
    );
  end if;

  if v_id is not null then
    select d.id
    into v_entity_id
    from public.odyssey_effect_defs d
    where d.id = v_id;

    if v_entity_id is null then
      return public.odyssey_creator_error(
        'EFFECT_DEF_NOT_FOUND',
        'Effect definition was not found for update.',
        jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown effect definition id.'))
      );
    end if;
  else
    select d.id
    into v_entity_id
    from public.odyssey_effect_defs d
    where d.code = v_code
    limit 1;
  end if;

  if exists (
    select 1
    from public.odyssey_effect_defs d
    where d.code = v_code
      and d.id <> coalesce(v_entity_id, '00000000-0000-0000-0000-000000000000'::uuid)
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'Effect code must be unique.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Duplicate effect code.'))
    );
  end if;

  if v_effect_type = '' or v_effect_type = 'modifiers_flags' then
    v_data := v_data - 'payload';
  else
    v_effect_payload := (v_effect_payload - 'type' - 'target_scope' - 'scale' - 'tick_phase' - 'resource_pool_id' - 'restore_disabled')
      || jsonb_build_object(
        'type', v_effect_type,
        'target_scope', case when v_target_scope <> '' then v_target_scope else 'character' end
      );

    if v_effect_type in ('periodic_damage', 'periodic_heal', 'body_part_heal', 'armor_repair', 'resource_restore') then
      v_effect_payload := v_effect_payload || jsonb_build_object(
        'scale',
        jsonb_build_object(
          'base', v_scale_base,
          'per_level', v_scale_per_level,
          'metric',
            case
              when v_scale_metric <> '' then v_scale_metric
              when v_effect_type = 'resource_restore' then 'points'
              when v_effect_type in ('periodic_heal', 'body_part_heal') then 'hp'
              when v_effect_type = 'armor_repair' then 'critical'
              else 'minor'
            end
        )
      );
    end if;

    if v_effect_type in ('periodic_damage', 'periodic_heal') then
      v_effect_payload := v_effect_payload || jsonb_build_object(
        'tick_phase',
        case when v_tick_phase <> '' then v_tick_phase else 'turn_end' end
      );
    end if;

    if v_effect_type = 'resource_restore' then
      v_effect_payload := v_effect_payload || jsonb_build_object('resource_pool_id', v_resource_pool_id);
    end if;

    if v_effect_type = 'body_part_heal' then
      v_effect_payload := v_effect_payload || jsonb_build_object('restore_disabled', v_restore_disabled);
    end if;

    v_data := jsonb_set(v_data, '{payload}', v_effect_payload, true);
  end if;

  if v_entity_id is null then
    insert into public.odyssey_effect_defs (
      code,
      name,
      category,
      description,
      default_duration_type,
      default_rounds,
      stacking_mode,
      is_negative,
      is_narrative,
      data,
      tags,
      is_custom,
      sort_order
    )
    values (
      v_code,
      v_name,
      v_category,
      nullif(v_description, ''),
      v_default_duration_type,
      case when v_default_duration_type = 'rounds' then v_default_rounds else null end,
      v_stacking_mode,
      v_is_negative,
      v_is_narrative,
      v_data,
      v_tags,
      true,
      v_sort_order
    )
    returning id into v_entity_id;
  else
    update public.odyssey_effect_defs
    set
      code = v_code,
      name = v_name,
      category = v_category,
      description = nullif(v_description, ''),
      default_duration_type = v_default_duration_type,
      default_rounds = case when v_default_duration_type = 'rounds' then v_default_rounds else null end,
      stacking_mode = v_stacking_mode,
      is_negative = v_is_negative,
      is_narrative = v_is_narrative,
      data = v_data,
      tags = v_tags,
      sort_order = v_sort_order
    where id = v_entity_id;
  end if;

  v_result := public.creator_get_effect(v_entity_id);

  return jsonb_build_object(
    'ok', true,
    'entity_id', v_entity_id,
    'entity', v_result,
    'warnings', '[]'::jsonb
  );
end;
$$;

create or replace function public.creator_delete_effect(
  p_effect_def_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_id uuid := p_effect_def_id;
begin
  if v_id is null then
    return public.odyssey_creator_error(
      'EFFECT_DEF_NOT_FOUND',
      'Effect definition id is required.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Provide a valid effect definition id.'))
    );
  end if;

  if not exists (
    select 1
    from public.odyssey_effect_defs d
    where d.id = v_id
  ) then
    return public.odyssey_creator_error(
      'EFFECT_DEF_NOT_FOUND',
      'Effect definition was not found for deletion.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown effect definition id.'))
    );
  end if;

  delete from public.odyssey_effect_defs d
  where d.id = v_id;

  return jsonb_build_object(
    'ok', true,
    'deleted_id', v_id
  );
end;
$$;

grant execute on function public.odyssey_creator_build_effect_bundle(uuid) to anon, authenticated;
grant execute on function public.creator_list_effects(text, jsonb) to anon, authenticated;
grant execute on function public.creator_get_effect(uuid) to anon, authenticated;
grant execute on function public.creator_upsert_effect(jsonb) to anon, authenticated;
grant execute on function public.creator_delete_effect(uuid) to anon, authenticated;

drop function if exists public.creator_list_armor_models(text);
drop function if exists public.creator_get_armor_model(uuid);
drop function if exists public.creator_upsert_armor_model(jsonb);
drop function if exists public.odyssey_creator_build_equipment_model_bundle(uuid);

do $$
declare
  v_constraint_name text;
begin
  select conname
  into v_constraint_name
  from pg_constraint
  where conrelid = 'public.odyssey_ability_defs'::regclass
    and contype = 'c'
    and pg_get_constraintdef(oid) ilike '%ability_kind%';

  if v_constraint_name is not null then
    execute format(
      'alter table public.odyssey_ability_defs drop constraint %I',
      v_constraint_name
    );
  end if;
end;
$$;

alter table public.odyssey_ability_defs
  add constraint odyssey_ability_defs_ability_kind_check
  check (ability_kind in ('attack', 'buff', 'support', 'defense', 'passive', 'utility', 'narrative', 'custom'));

create or replace function public.creator_upsert_ability(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := public.odyssey_creator_normalize_json_object(p_payload);
  v_id uuid := nullif(trim(coalesce(v_payload->>'id', '')), '')::uuid;
  v_code text := public.odyssey_creator_normalize_code(v_payload->>'code');
  v_name text := trim(coalesce(v_payload->>'name', ''));
  v_ability_kind text := lower(trim(coalesce(v_payload->>'ability_kind', 'custom')));
  v_source_type text := lower(trim(coalesce(v_payload->>'source_type', 'custom')));
  v_activation_type text := lower(trim(coalesce(v_payload->>'activation_type', 'manual')));
  v_target_type text := lower(trim(coalesce(v_payload->>'target_type', 'self')));
  v_effect_mode text := lower(trim(coalesce(v_payload->>'effect_mode', 'narrative')));
  v_attack_type text := nullif(lower(trim(coalesce(v_payload->>'attack_type', ''))), '');
  v_linked_skill_id uuid := nullif(trim(coalesce(v_payload->>'linked_skill_id', '')), '')::uuid;
  v_resource_mode text := lower(trim(coalesce(v_payload->>'resource_mode', 'none')));
  v_resource_pool_code text := nullif(public.odyssey_creator_normalize_code(v_payload->>'resource_pool_code'), '');
  v_resource_item_code text := nullif(public.odyssey_creator_normalize_code(v_payload->>'resource_item_code'), '');
  v_description text := coalesce(v_payload->>'description', '');
  v_data jsonb := public.odyssey_creator_normalize_json_object(v_payload->'data');
  v_effect_data jsonb := public.odyssey_creator_normalize_json_object(v_payload->'effect_data');
  v_tags jsonb := public.odyssey_creator_normalize_text_array(v_payload->'tags');
  v_sort_order integer := coalesce(nullif(trim(coalesce(v_payload->>'sort_order', '')), '')::integer, 0);
  v_levels jsonb := public.odyssey_creator_normalize_json_array(v_payload->'levels');
  v_effect_links_raw jsonb := public.odyssey_creator_normalize_json_array(
    coalesce(v_payload->'effect_links', v_data->'effect_links')
  );
  v_effect_links jsonb := '[]'::jsonb;
  v_entity_id uuid := null;
  v_result jsonb := '{}'::jsonb;
  v_processed_level_ids uuid[] := '{}'::uuid[];
  v_seen_levels integer[] := '{}'::integer[];
  v_seen_effect_ids uuid[] := '{}'::uuid[];
  v_entry jsonb := '{}'::jsonb;
  v_level_id uuid := null;
  v_ability_level integer := 0;
  v_resource_cost integer := 0;
  v_cooldown_rounds integer := null;
  v_range_profile_id uuid := null;
  v_attack_accuracy_bonus integer := 0;
  v_attack_damage_bonus integer := 0;
  v_attack_armor_pierce integer := 0;
  v_ignore_armor boolean := false;
  v_special_armor_value integer := null;
  v_special_max_critical integer := null;
  v_duration_rounds integer := null;
  v_level_data jsonb := '{}'::jsonb;
  v_level_effect_data jsonb := '{}'::jsonb;
  v_effect_def_id uuid := null;
  v_range_data jsonb := public.odyssey_creator_normalize_json_object(v_data->'range');
  v_range_mode text := lower(trim(coalesce(v_range_data->>'mode', '')));
  v_max_distance_m integer := nullif(trim(coalesce(v_range_data->>'max_distance_m', '')), '')::integer;
begin
  if v_code = '' or not public.odyssey_creator_is_valid_code(v_code) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'code must match ^[a-z][a-z0-9_]*$.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Use lowercase snake_case starting with a letter.'))
    );
  end if;

  if v_name = '' then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'name is required.',
      jsonb_build_array(jsonb_build_object('field', 'name', 'message', 'Name cannot be empty.'))
    );
  end if;

  if v_ability_kind not in ('attack', 'buff', 'support', 'defense', 'passive', 'utility', 'narrative', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'ability_kind is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'ability_kind', 'message', 'Unsupported ability_kind value.'))
    );
  end if;

  if v_source_type not in ('psionic', 'implant', 'prosthetic', 'equipment', 'item', 'innate', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'source_type is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'source_type', 'message', 'Unsupported source_type value.'))
    );
  end if;

  if v_activation_type not in ('manual', 'passive', 'on_attack', 'on_hit', 'always', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'activation_type is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'activation_type', 'message', 'Unsupported activation_type value.'))
    );
  end if;

  if v_target_type not in ('self', 'character', 'body_part', 'none', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'target_type is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'target_type', 'message', 'Unsupported target_type value.'))
    );
  end if;

  if v_effect_mode not in ('attack', 'apply_effect', 'grant_special', 'narrative', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'effect_mode is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'effect_mode', 'message', 'Unsupported effect_mode value.'))
    );
  end if;

  if v_attack_type is not null and v_attack_type not in ('ranged', 'melee', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'attack_type is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'attack_type', 'message', 'Unsupported attack_type value.'))
    );
  end if;

  if v_linked_skill_id is not null and not exists (
    select 1
    from public.odyssey_skill_defs skill
    where skill.id = v_linked_skill_id
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'linked_skill_id references an unknown skill.',
      jsonb_build_array(jsonb_build_object('field', 'linked_skill_id', 'message', 'Unknown linked skill id.'))
    );
  end if;

  if v_resource_mode not in ('none', 'pool', 'item', 'cooldown', 'custom') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'resource_mode is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'resource_mode', 'message', 'Unsupported resource_mode value.'))
    );
  end if;

  if v_resource_pool_code is not null and not exists (
    select 1
    from public.odyssey_resource_pool_defs pool
    where pool.code = v_resource_pool_code
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'resource_pool_code references an unknown resource pool.',
      jsonb_build_array(jsonb_build_object('field', 'resource_pool_code', 'message', 'Unknown resource pool code.'))
    );
  end if;

  if v_resource_item_code is not null and not exists (
    select 1
    from public.odyssey_item_defs item_def
    where item_def.code = v_resource_item_code
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'resource_item_code references an unknown item.',
      jsonb_build_array(jsonb_build_object('field', 'resource_item_code', 'message', 'Unknown item definition code.'))
    );
  end if;

  if v_range_mode <> '' and v_range_mode not in ('none', 'limited') then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'range.mode is invalid.',
      jsonb_build_array(jsonb_build_object('field', 'data.range.mode', 'message', 'Use none or limited.'))
    );
  end if;

  if v_range_mode = 'limited' and coalesce(v_max_distance_m, 0) < 1 then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'range.max_distance_m must be >= 1 when range mode is limited.',
      jsonb_build_array(jsonb_build_object('field', 'data.range.max_distance_m', 'message', 'Provide a positive max distance.'))
    );
  end if;

  if jsonb_array_length(v_levels) = 0 then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'At least one ability level is required.',
      jsonb_build_array(jsonb_build_object('field', 'levels', 'message', 'Provide at least one level entry.'))
    );
  end if;

  for v_entry in
    select value
    from jsonb_array_elements(v_effect_links_raw)
  loop
    v_effect_def_id := nullif(trim(coalesce(v_entry->>'effect_def_id', v_entry->>'id', '')), '')::uuid;
    if v_effect_def_id is null or not exists (
      select 1
      from public.odyssey_effect_defs effect_def
      where effect_def.id = v_effect_def_id
    ) then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'effect_links contain an unknown effect template.',
        jsonb_build_array(jsonb_build_object('field', 'effect_links', 'message', 'Unknown effect_def_id.'))
      );
    end if;

    if v_effect_def_id = any(v_seen_effect_ids) then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'effect_links must not contain duplicates.',
        jsonb_build_array(jsonb_build_object('field', 'effect_links', 'message', 'Duplicate effect_def_id found.'))
      );
    end if;

    v_seen_effect_ids := array_append(v_seen_effect_ids, v_effect_def_id);
    v_effect_links := v_effect_links || jsonb_build_array(
      jsonb_build_object(
        'effect_def_id', v_effect_def_id,
        'sort_order', coalesce(nullif(trim(coalesce(v_entry->>'sort_order', '')), '')::integer, jsonb_array_length(v_effect_links))
      )
    );
  end loop;

  v_data := jsonb_set(
    v_data - 'effect_links',
    '{effect_links}',
    coalesce(v_effect_links, '[]'::jsonb),
    true
  );

  for v_entry in
    select value
    from jsonb_array_elements(v_levels)
  loop
    v_ability_level := coalesce(nullif(trim(coalesce(v_entry->>'ability_level', '')), '')::integer, 0);
    if v_ability_level < 1 or v_ability_level > 5 then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'ability_level must be between 1 and 5.',
        jsonb_build_array(jsonb_build_object('field', 'levels', 'message', 'Each ability level must be between 1 and 5.'))
      );
    end if;

    if v_ability_level = any(v_seen_levels) then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'ability_level values must be unique per ability.',
        jsonb_build_array(jsonb_build_object('field', 'levels', 'message', 'Duplicate ability_level value found.'))
      );
    end if;

    v_seen_levels := array_append(v_seen_levels, v_ability_level);

    v_resource_cost := coalesce(nullif(trim(coalesce(v_entry->>'resource_cost', '')), '')::integer, 0);
    if v_resource_cost < 0 then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'resource_cost must be >= 0.',
        jsonb_build_array(jsonb_build_object('field', 'levels', 'message', 'resource_cost cannot be negative.'))
      );
    end if;

    v_range_profile_id := nullif(trim(coalesce(v_entry->>'range_profile_id', '')), '')::uuid;
    if v_range_profile_id is not null and not exists (
      select 1 from public.odyssey_range_profile_defs where id = v_range_profile_id
    ) then
      return public.odyssey_creator_error(
        'VALIDATION_ERROR',
        'range_profile_id references an unknown range profile.',
        jsonb_build_array(jsonb_build_object('field', 'levels', 'message', 'Unknown range_profile_id.'))
      );
    end if;
  end loop;

  if v_id is not null then
    select ability.id
    into v_entity_id
    from public.odyssey_ability_defs ability
    where ability.id = v_id;

    if v_entity_id is null then
      return public.odyssey_creator_error(
        'ABILITY_NOT_FOUND',
        'Ability definition was not found for update.',
        jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown ability definition id.'))
      );
    end if;
  else
    select ability.id
    into v_entity_id
    from public.odyssey_ability_defs ability
    where ability.code = v_code
    limit 1;
  end if;

  if exists (
    select 1
    from public.odyssey_ability_defs ability
    where ability.code = v_code
      and ability.id <> coalesce(v_entity_id, '00000000-0000-0000-0000-000000000000'::uuid)
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'Ability code must be unique.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Duplicate ability code.'))
    );
  end if;

  if v_entity_id is null then
    insert into public.odyssey_ability_defs (
      code,
      name,
      ability_kind,
      source_type,
      activation_type,
      target_type,
      effect_mode,
      attack_type,
      linked_skill_id,
      resource_mode,
      resource_pool_code,
      resource_item_code,
      description,
      data,
      effect_data,
      tags,
      is_custom,
      sort_order
    )
    values (
      v_code,
      v_name,
      v_ability_kind,
      v_source_type,
      v_activation_type,
      v_target_type,
      v_effect_mode,
      v_attack_type,
      v_linked_skill_id,
      v_resource_mode,
      v_resource_pool_code,
      v_resource_item_code,
      v_description,
      v_data,
      v_effect_data,
      v_tags,
      true,
      v_sort_order
    )
    returning id into v_entity_id;
  else
    update public.odyssey_ability_defs
    set
      code = v_code,
      name = v_name,
      ability_kind = v_ability_kind,
      source_type = v_source_type,
      activation_type = v_activation_type,
      target_type = v_target_type,
      effect_mode = v_effect_mode,
      attack_type = v_attack_type,
      linked_skill_id = v_linked_skill_id,
      resource_mode = v_resource_mode,
      resource_pool_code = v_resource_pool_code,
      resource_item_code = v_resource_item_code,
      description = v_description,
      data = v_data,
      effect_data = v_effect_data,
      tags = v_tags,
      sort_order = v_sort_order
    where id = v_entity_id;
  end if;

  for v_entry in
    select value
    from jsonb_array_elements(v_levels)
  loop
    v_level_id := nullif(trim(coalesce(v_entry->>'id', '')), '')::uuid;
    v_ability_level := coalesce(nullif(trim(coalesce(v_entry->>'ability_level', '')), '')::integer, 0);
    v_resource_cost := coalesce(nullif(trim(coalesce(v_entry->>'resource_cost', '')), '')::integer, 0);
    v_cooldown_rounds := nullif(trim(coalesce(v_entry->>'cooldown_rounds', '')), '')::integer;
    v_range_profile_id := nullif(trim(coalesce(v_entry->>'range_profile_id', '')), '')::uuid;
    v_attack_accuracy_bonus := coalesce(nullif(trim(coalesce(v_entry->>'attack_accuracy_bonus', '')), '')::integer, 0);
    v_attack_damage_bonus := coalesce(nullif(trim(coalesce(v_entry->>'attack_damage_bonus', '')), '')::integer, 0);
    v_attack_armor_pierce := coalesce(nullif(trim(coalesce(v_entry->>'attack_armor_pierce', '')), '')::integer, 0);
    v_ignore_armor := coalesce(nullif(trim(coalesce(v_entry->>'ignore_armor', '')), '')::boolean, false);
    v_special_armor_value := nullif(trim(coalesce(v_entry->>'special_armor_value', '')), '')::integer;
    v_special_max_critical := nullif(trim(coalesce(v_entry->>'special_max_critical', '')), '')::integer;
    v_duration_rounds := nullif(trim(coalesce(v_entry->>'duration_rounds', '')), '')::integer;
    v_level_data := public.odyssey_creator_normalize_json_object(v_entry->'data');
    v_level_effect_data := public.odyssey_creator_normalize_json_object(v_entry->'effect_data');

    if v_level_id is not null then
      if not exists (
        select 1
        from public.odyssey_ability_level_defs level
        where level.id = v_level_id
          and level.ability_def_id = v_entity_id
      ) then
        return public.odyssey_creator_error(
          'VALIDATION_ERROR',
          'Level id does not belong to this ability.',
          jsonb_build_array(jsonb_build_object('field', 'levels', 'message', 'Invalid level id for this ability.'))
        );
      end if;

      update public.odyssey_ability_level_defs
      set
        ability_level = v_ability_level,
        resource_cost = v_resource_cost,
        cooldown_rounds = v_cooldown_rounds,
        range_profile_id = v_range_profile_id,
        attack_accuracy_bonus = v_attack_accuracy_bonus,
        attack_damage_bonus = v_attack_damage_bonus,
        attack_armor_pierce = v_attack_armor_pierce,
        ignore_armor = v_ignore_armor,
        special_armor_value = v_special_armor_value,
        special_max_critical = v_special_max_critical,
        duration_rounds = v_duration_rounds,
        data = v_level_data,
        effect_data = v_level_effect_data
      where id = v_level_id;
    else
      select level.id
      into v_level_id
      from public.odyssey_ability_level_defs level
      where level.ability_def_id = v_entity_id
        and level.ability_level = v_ability_level
      limit 1;

      if v_level_id is null then
        insert into public.odyssey_ability_level_defs (
          ability_def_id,
          ability_level,
          resource_cost,
          cooldown_rounds,
          range_profile_id,
          attack_accuracy_bonus,
          attack_damage_bonus,
          attack_armor_pierce,
          ignore_armor,
          special_armor_value,
          special_max_critical,
          duration_rounds,
          data,
          effect_data
        )
        values (
          v_entity_id,
          v_ability_level,
          v_resource_cost,
          v_cooldown_rounds,
          v_range_profile_id,
          v_attack_accuracy_bonus,
          v_attack_damage_bonus,
          v_attack_armor_pierce,
          v_ignore_armor,
          v_special_armor_value,
          v_special_max_critical,
          v_duration_rounds,
          v_level_data,
          v_level_effect_data
        )
        returning id into v_level_id;
      else
        update public.odyssey_ability_level_defs
        set
          resource_cost = v_resource_cost,
          cooldown_rounds = v_cooldown_rounds,
          range_profile_id = v_range_profile_id,
          attack_accuracy_bonus = v_attack_accuracy_bonus,
          attack_damage_bonus = v_attack_damage_bonus,
          attack_armor_pierce = v_attack_armor_pierce,
          ignore_armor = v_ignore_armor,
          special_armor_value = v_special_armor_value,
          special_max_critical = v_special_max_critical,
          duration_rounds = v_duration_rounds,
          data = v_level_data,
          effect_data = v_level_effect_data
        where id = v_level_id;
      end if;
    end if;

    v_processed_level_ids := array_append(v_processed_level_ids, v_level_id);
  end loop;

  delete from public.odyssey_ability_level_defs
  where ability_def_id = v_entity_id
    and not (id = any(v_processed_level_ids));

  v_result := public.creator_get_ability(v_entity_id);

  return jsonb_build_object(
    'ok', true,
    'entity_id', v_entity_id,
    'entity', v_result,
    'warnings', '[]'::jsonb
  );
end;
$$;

create or replace function public.creator_delete_ability(
  p_ability_def_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_ability public.odyssey_ability_defs%rowtype;
  v_character_ability_count integer := 0;
  v_weapon_link_count integer := 0;
  v_equipment_link_count integer := 0;
  v_item_link_count integer := 0;
  v_details jsonb := '[]'::jsonb;
begin
  select *
  into v_ability
  from public.odyssey_ability_defs ability
  where ability.id = p_ability_def_id;

  if not found then
    return public.odyssey_creator_error(
      'ABILITY_NOT_FOUND',
      'Ability definition was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown ability definition id.'))
    );
  end if;

  select count(*)::integer into v_character_ability_count
  from public.odyssey_character_abilities ability
  where ability.ability_def_id = p_ability_def_id;

  select count(*)::integer into v_weapon_link_count
  from public.odyssey_weapon_model_abilities link
  where link.ability_def_id = p_ability_def_id;

  select count(*)::integer into v_equipment_link_count
  from public.odyssey_equipment_model_abilities link
  where link.ability_def_id = p_ability_def_id;

  select count(*)::integer into v_item_link_count
  from public.odyssey_item_def_abilities link
  where link.ability_def_id = p_ability_def_id;

  select coalesce(jsonb_agg(item), '[]'::jsonb)
  into v_details
  from (
    select jsonb_build_object('field', 'character_abilities', 'count', v_character_ability_count, 'message', 'Ability is assigned to one or more characters.') as item
    where v_character_ability_count > 0
    union all
    select jsonb_build_object('field', 'weapon_links', 'count', v_weapon_link_count, 'message', 'Ability is linked to one or more weapon models.') as item
    where v_weapon_link_count > 0
    union all
    select jsonb_build_object('field', 'equipment_links', 'count', v_equipment_link_count, 'message', 'Ability is linked to one or more equipment models.') as item
    where v_equipment_link_count > 0
    union all
    select jsonb_build_object('field', 'item_links', 'count', v_item_link_count, 'message', 'Ability is linked to one or more item definitions.') as item
    where v_item_link_count > 0
  ) dependency_rows;

  if v_details <> '[]'::jsonb then
    return public.odyssey_creator_error(
      'ABILITY_DEF_IN_USE',
      'Ability definition is still referenced and cannot be deleted.',
      v_details
    );
  end if;

  delete from public.odyssey_ability_defs ability
  where ability.id = p_ability_def_id;

  return jsonb_build_object(
    'ok', true,
    'deleted_id', p_ability_def_id,
    'deleted_code', v_ability.code
  );
end;
$$;

create or replace function public.use_ability(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_character_ability_id uuid := nullif(trim(coalesce(p_payload->>'character_ability_id', '')), '')::uuid;
  v_character_id uuid := nullif(trim(coalesce(p_payload->>'character_id', '')), '')::uuid;
  v_ability_code text := lower(trim(coalesce(p_payload->>'ability_code', '')));
  v_target_character_id uuid := nullif(trim(coalesce(p_payload->>'target_character_id', '')), '')::uuid;
  v_target_body_part_id uuid := nullif(trim(coalesce(p_payload->>'target_body_part_id', '')), '')::uuid;
  v_target_armor_item_id uuid := nullif(trim(coalesce(p_payload->>'target_armor_item_id', '')), '')::uuid;
  v_scene_id text := coalesce(nullif(trim(coalesce(p_payload->>'scene_id', '')), ''), '');
  v_created_by text := coalesce(nullif(trim(coalesce(p_payload->>'created_by', '')), ''), '');
  v_encounter_id uuid := nullif(trim(coalesce(p_payload->>'encounter_id', '')), '')::uuid;
  v_ability record;
  v_level record;
  v_effective_level integer := 0;
  v_target_part record;
  v_resource_result jsonb := '{}'::jsonb;
  v_effect_result jsonb := '{}'::jsonb;
  v_effect_results jsonb := '[]'::jsonb;
  v_merged_ability_data jsonb := '{}'::jsonb;
  v_effect_payload_data jsonb := '{}'::jsonb;
  v_effect_code text := '';
  v_effect_links jsonb := '[]'::jsonb;
  v_effect_link jsonb := '{}'::jsonb;
  v_link_data jsonb := '{}'::jsonb;
  v_link_effect_code text := '';
  v_link_effect_id uuid := null;
  v_effect_instance_data jsonb := '{}'::jsonb;
  v_effect_context jsonb := '{}'::jsonb;
  v_refresh jsonb := '{}'::jsonb;
  v_log_id uuid := null;
  v_log_data jsonb := '{}'::jsonb;
  v_message text := '';
begin
  if v_character_ability_id is null then
    if v_character_id is null or v_ability_code = '' then
      return jsonb_build_object(
        'ok', false,
        'error', 'ABILITY_NOT_FOUND',
        'message', 'character_ability_id or character_id + ability_code is required.'
      );
    end if;

    select ability.id
    into v_character_ability_id
    from public.odyssey_character_abilities ability
    join public.odyssey_ability_defs def on def.id = ability.ability_def_id
    where ability.character_id = v_character_id
      and def.code = v_ability_code
      and ability.is_enabled = true
    order by ability.sort_order, ability.created_at, ability.id
    limit 1;
  end if;

  select
    ability.*,
    def.code as ability_code,
    def.name as ability_name,
    def.ability_kind,
    def.source_type,
    def.activation_type,
    def.target_type,
    def.effect_mode,
    def.attack_type,
    def.resource_mode,
    def.resource_pool_code,
    def.resource_item_code,
    def.description as ability_description,
    def.effect_data as def_effect_data,
    def.data as def_data
  into v_ability
  from public.odyssey_character_abilities ability
  join public.odyssey_ability_defs def on def.id = ability.ability_def_id
  where ability.id = v_character_ability_id
    and ability.is_enabled = true
  for update of ability;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_NOT_FOUND',
      'character_ability_id', v_character_ability_id
    );
  end if;

  v_character_id := v_ability.character_id;
  v_effective_level := public.odyssey_get_character_ability_effective_level(v_character_ability_id);

  select *
  into v_level
  from public.odyssey_ability_level_defs level_data
  where level_data.ability_def_id = v_ability.ability_def_id
    and level_data.ability_level <= v_effective_level
  order by level_data.ability_level desc
  limit 1;

  if not found then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_LEVEL_NOT_AVAILABLE',
      'character_ability_id', v_character_ability_id,
      'effective_level', v_effective_level
    );
  end if;

  v_merged_ability_data :=
    coalesce(v_ability.def_data, '{}'::jsonb)
    || coalesce(v_ability.data, '{}'::jsonb)
    || coalesce(v_level.data, '{}'::jsonb);

  v_effect_payload_data := public.odyssey_merge_effect_data(
    public.odyssey_merge_effect_data(
      coalesce(v_ability.def_effect_data, '{}'::jsonb),
      case
        when jsonb_typeof(v_ability.data->'effect_data') = 'object' then v_ability.data->'effect_data'
        else '{}'::jsonb
      end
    ),
    coalesce(v_level.effect_data, '{}'::jsonb)
  );

  v_effect_code := lower(trim(coalesce(
    nullif(v_merged_ability_data->>'effect_code', ''),
    nullif(v_effect_payload_data->>'effect_code', ''),
    ''
  )));

  if jsonb_typeof(v_merged_ability_data->'effect_links') = 'array' then
    v_effect_links := v_merged_ability_data->'effect_links';
  end if;

  if v_ability.ability_kind = 'attack' or v_ability.effect_mode = 'attack' then
    return jsonb_build_object(
      'ok', false,
      'error', 'ABILITY_REQUIRES_ATTACK_RESOLUTION',
      'message', 'Attack abilities must be resolved through perform_attack.',
      'character_ability_id', v_character_ability_id
    );
  end if;

  if v_ability.target_type = 'self' then
    v_target_character_id := v_character_id;
  elsif v_target_character_id is null then
    v_target_character_id := v_character_id;
  end if;

  v_resource_result := public.odyssey_consume_character_ability_cost(v_character_ability_id);
  if coalesce((v_resource_result->>'ok')::boolean, false) = false then
    return v_resource_result;
  end if;

  if coalesce(v_level.cooldown_rounds, 0) > 0 then
    update public.odyssey_character_abilities
    set current_cooldown_rounds = v_level.cooldown_rounds
    where id = v_character_ability_id;
  end if;

  v_effect_context := jsonb_strip_nulls(
    jsonb_build_object(
      'selected_body_part_id', case when v_target_body_part_id is not null then v_target_body_part_id::text else null end,
      'selected_armor_item_id', case when v_target_armor_item_id is not null then v_target_armor_item_id::text else null end
    )
  );

  if v_ability.effect_mode = 'apply_effect' then
    if jsonb_typeof(v_effect_links) = 'array' and jsonb_array_length(v_effect_links) > 0 then
      for v_effect_link in
        select value
        from jsonb_array_elements(v_effect_links)
        order by coalesce(nullif(value->>'sort_order', '')::integer, 0)
      loop
        v_link_effect_code := lower(trim(coalesce(v_effect_link->>'effect_code', '')));
        v_link_effect_id := nullif(trim(coalesce(v_effect_link->>'effect_def_id', '')), '')::uuid;
        if v_link_effect_code = '' and v_link_effect_id is not null then
          select effect_def.code
          into v_link_effect_code
          from public.odyssey_effect_defs effect_def
          where effect_def.id = v_link_effect_id;
        end if;

        if v_link_effect_code = '' then
          return jsonb_build_object(
            'ok', false,
            'error', 'ABILITY_EFFECT_NOT_CONFIGURED',
            'message', 'One of the linked effects is missing effect_def_id/effect_code.',
            'character_ability_id', v_character_ability_id
          );
        end if;

        v_link_data := case
          when jsonb_typeof(v_effect_link->'data') = 'object' then v_effect_link->'data'
          else '{}'::jsonb
        end;
        v_effect_instance_data := public.odyssey_merge_effect_data(v_effect_payload_data, v_link_data);
        if v_effect_context <> '{}'::jsonb then
          v_effect_instance_data := public.odyssey_merge_effect_data(
            v_effect_instance_data,
            jsonb_build_object('context', v_effect_context)
          );
        end if;

        v_effect_result := public.add_character_effect(
          jsonb_build_object(
            'character_id', v_target_character_id,
            'effect_code', v_link_effect_code,
            'effect_key', v_ability.ability_code || ':' || v_link_effect_code,
            'name', v_ability.ability_name,
            'description', v_ability.ability_description,
            'category',
              case
                when v_ability.source_type = 'psionic' then 'psionic'
                when v_ability.source_type in ('implant', 'prosthetic', 'equipment', 'item') then 'equipment'
                else 'custom'
              end,
            'duration_type', case when v_level.duration_rounds is not null and v_level.duration_rounds > 0 then 'rounds' else 'manual' end,
            'rounds_left', v_level.duration_rounds,
            'source', v_ability.ability_name,
            'source_type', v_ability.source_type,
            'source_id', v_character_ability_id::text,
            'source_character_id', v_character_id::text,
            'data', v_effect_instance_data,
            'created_by', v_created_by
          )
        );

        if coalesce((v_effect_result->>'ok')::boolean, false) = false then
          return v_effect_result;
        end if;

        v_refresh := coalesce(v_effect_result->'combat_state', v_refresh);
        v_effect_results := v_effect_results || jsonb_build_array(coalesce(v_effect_result->'effect', '{}'::jsonb));
      end loop;

      v_effect_result := jsonb_build_object(
        'ok', true,
        'effects', v_effect_results,
        'combat_state', v_refresh
      );
    elsif v_effect_code <> '' then
      v_effect_instance_data := v_effect_payload_data;
      if v_effect_context <> '{}'::jsonb then
        v_effect_instance_data := public.odyssey_merge_effect_data(
          v_effect_instance_data,
          jsonb_build_object('context', v_effect_context)
        );
      end if;

      v_effect_result := public.add_character_effect(
        jsonb_build_object(
          'character_id', v_target_character_id,
          'effect_code', v_effect_code,
          'effect_key', v_ability.ability_code,
          'name', v_ability.ability_name,
          'description', v_ability.ability_description,
          'category',
            case
              when v_ability.source_type = 'psionic' then 'psionic'
              when v_ability.source_type in ('implant', 'prosthetic', 'equipment', 'item') then 'equipment'
              else 'custom'
            end,
          'duration_type', case when v_level.duration_rounds is not null and v_level.duration_rounds > 0 then 'rounds' else 'manual' end,
          'rounds_left', v_level.duration_rounds,
          'source', v_ability.ability_name,
          'source_type', v_ability.source_type,
          'source_id', v_character_ability_id::text,
          'source_character_id', v_character_id::text,
          'data', v_effect_instance_data,
          'created_by', v_created_by
        )
      );

      if coalesce((v_effect_result->>'ok')::boolean, false) = false then
        return v_effect_result;
      end if;

      v_refresh := coalesce(v_effect_result->'combat_state', '{}'::jsonb);
    else
      v_refresh := coalesce(public.odyssey_refresh_character_combat_state(v_target_character_id)->'combat_state', '{}'::jsonb);
      v_effect_result := jsonb_build_object(
        'ok', true,
        'narrative_only', true,
        'combat_state', v_refresh
      );
    end if;
  elsif v_ability.effect_mode = 'grant_special' then
    select
      b.id,
      b.character_id,
      b.part_key,
      b.max_critical,
      b.critical
    into v_target_part
    from public.odyssey_character_body_parts b
    left join public.odyssey_body_part_defs d on d.id = b.body_part_def_id
    where b.character_id = v_target_character_id
      and coalesce(d.code, public.odyssey_normalize_part_code(b.part_key)) = 'special'
    limit 1
    for update of b;

    if not found then
      return jsonb_build_object(
        'ok', false,
        'error', 'SPECIAL_BODY_PART_NOT_FOUND',
        'target_character_id', v_target_character_id
      );
    end if;

    update public.odyssey_character_body_parts
    set
      natural_armor_value = greatest(coalesce(v_level.special_armor_value, 0), 0),
      max_critical = greatest(coalesce(v_level.special_max_critical, max_critical), 0),
      critical = 0,
      serious = 0,
      minor = 0,
      disabled = false,
      destroyed = false
    where id = v_target_part.id;

    perform public.recompute_character_armor(v_target_character_id);
    v_refresh := coalesce(public.odyssey_refresh_character_combat_state(v_target_character_id)->'combat_state', '{}'::jsonb);
    v_effect_result := jsonb_build_object(
      'ok', true,
      'special', public.odyssey_get_character_body_part_state(v_target_part.id),
      'combat_state', v_refresh
    );
  else
    v_refresh := coalesce(public.odyssey_refresh_character_combat_state(v_target_character_id)->'combat_state', '{}'::jsonb);
    v_effect_result := jsonb_build_object(
      'ok', true,
      'narrative_only', true,
      'combat_state', v_refresh
    );
  end if;

  v_message := format(
    '%s uses %s.',
    coalesce(
      (
        select coalesce(nullif(trim(c.resources->>'name'), ''), c.character_key)
        from public.odyssey_characters c
        where c.id = v_character_id
      ),
      v_character_id::text
    ),
    v_ability.ability_name
  );

  v_log_data := jsonb_build_object(
    'type', 'ability_use',
    'ok', true,
    'character_ability_id', v_character_ability_id,
    'character_id', v_character_id,
    'target_character_id', v_target_character_id,
    'target_body_part_id', v_target_body_part_id,
    'target_armor_item_id', v_target_armor_item_id,
    'ability',
      jsonb_build_object(
        'code', v_ability.ability_code,
        'name', v_ability.ability_name,
        'ability_kind', v_ability.ability_kind,
        'source_type', v_ability.source_type,
        'effect_mode', v_ability.effect_mode,
        'effective_level', v_effective_level
      ),
    'resource', v_resource_result,
    'result', v_effect_result
  );

  insert into public.odyssey_combat_log (
    campaign_id,
    room_id,
    scene_id,
    encounter_id,
    actor_character_id,
    target_character_id,
    event_type,
    message,
    data,
    created_by
  )
  values (
    coalesce((select c.campaign_id from public.odyssey_characters c where c.id = v_character_id), ''),
    coalesce((select c.room_id from public.odyssey_characters c where c.id = v_character_id), ''),
    v_scene_id,
    v_encounter_id,
    v_character_id,
    v_target_character_id,
    'ability_use',
    v_message,
    v_log_data,
    v_created_by
  )
  returning id into v_log_id;

  perform public.odyssey_trim_combat_log(v_encounter_id, coalesce((select c.room_id from public.odyssey_characters c where c.id = v_character_id), ''));

  return jsonb_build_object(
    'ok', true,
    'character_ability_id', v_character_ability_id,
    'character_id', v_character_id,
    'target_character_id', v_target_character_id,
    'target_body_part_id', v_target_body_part_id,
    'target_armor_item_id', v_target_armor_item_id,
    'ability',
      jsonb_build_object(
        'code', v_ability.ability_code,
        'name', v_ability.ability_name,
        'ability_kind', v_ability.ability_kind,
        'source_type', v_ability.source_type,
        'effect_mode', v_ability.effect_mode,
        'effective_level', v_effective_level
      ),
    'resource', v_resource_result,
    'result', v_effect_result,
    'combat_state', v_refresh,
    'log_id', v_log_id
  );
end;
$$;

grant execute on function public.creator_upsert_ability(jsonb) to anon, authenticated;
grant execute on function public.creator_delete_ability(uuid) to anon, authenticated;
grant execute on function public.use_ability(jsonb) to anon, authenticated;



-- 57_creator_ammo_catalogs.sql

create or replace function public.creator_list_calibers(
  p_search text default null
)
returns jsonb
language sql
stable
as $$
  with search_input as (
    select nullif(trim(coalesce(p_search, '')), '') as search_text
  ),
  filtered as (
    select
      caliber.id,
      caliber.code,
      caliber.name,
      caliber.sort_order,
      caliber.base_damage_per_round,
      coalesce(caliber.tags, '[]'::jsonb) as tags
    from public.odyssey_caliber_defs caliber
    cross join search_input
    where search_input.search_text is null
      or caliber.code ilike '%' || search_input.search_text || '%'
      or caliber.name ilike '%' || search_input.search_text || '%'
      or caliber.tags::text ilike '%' || search_input.search_text || '%'
  )
  select jsonb_build_object(
    'ok', true,
    'items',
      coalesce(
        jsonb_agg(
          jsonb_build_object(
            'id', id,
            'code', code,
            'name', name,
            'base_damage_per_round', base_damage_per_round,
            'tags', tags
          )
          order by sort_order, name, code
        ),
        '[]'::jsonb
      )
  )
  from filtered;
$$;

create or replace function public.creator_get_caliber(
  p_caliber_id uuid
)
returns jsonb
language sql
stable
as $$
  select coalesce(
    (
      select jsonb_build_object(
        'ok', true,
        'caliber',
          jsonb_build_object(
            'id', caliber.id,
            'code', caliber.code,
            'name', caliber.name,
            'base_damage_per_round', caliber.base_damage_per_round,
            'description', coalesce(caliber.description, ''),
            'tags', coalesce(caliber.tags, '[]'::jsonb),
            'is_custom', caliber.is_custom,
            'sort_order', caliber.sort_order,
            'created_at', caliber.created_at,
            'updated_at', caliber.updated_at
          )
      )
      from public.odyssey_caliber_defs caliber
      where caliber.id = p_caliber_id
    ),
    public.odyssey_creator_error(
      'CALIBER_NOT_FOUND',
      'Caliber was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown caliber id.'))
    )
  );
$$;

create or replace function public.creator_upsert_caliber(
  p_payload jsonb
)
returns jsonb
language plpgsql
as $$
declare
  v_payload jsonb := public.odyssey_creator_normalize_json_object(p_payload);
  v_id uuid := nullif(trim(coalesce(v_payload->>'id', '')), '')::uuid;
  v_code text := public.odyssey_creator_normalize_code(v_payload->>'code');
  v_name text := trim(coalesce(v_payload->>'name', ''));
  v_base_damage_per_round integer := coalesce(nullif(trim(coalesce(v_payload->>'base_damage_per_round', '')), '')::integer, 0);
  v_description text := coalesce(v_payload->>'description', '');
  v_tags jsonb := public.odyssey_creator_normalize_text_array(v_payload->'tags');
  v_sort_order integer := coalesce(nullif(trim(coalesce(v_payload->>'sort_order', '')), '')::integer, 0);
  v_entity_id uuid := null;
  v_result jsonb := '{}'::jsonb;
begin
  if v_code = '' or not public.odyssey_creator_is_valid_code(v_code) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'code must match ^[a-z][a-z0-9_]*$.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Use lowercase snake_case starting with a letter.'))
    );
  end if;

  if v_name = '' then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'name is required.',
      jsonb_build_array(jsonb_build_object('field', 'name', 'message', 'Name cannot be empty.'))
    );
  end if;

  if v_base_damage_per_round < 0 then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'base_damage_per_round must be >= 0.',
      jsonb_build_array(jsonb_build_object('field', 'base_damage_per_round', 'message', 'Base damage cannot be negative.'))
    );
  end if;

  if v_id is not null then
    select caliber.id
    into v_entity_id
    from public.odyssey_caliber_defs caliber
    where caliber.id = v_id;

    if v_entity_id is null then
      return public.odyssey_creator_error(
        'CALIBER_NOT_FOUND',
        'Caliber was not found for update.',
        jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown caliber id.'))
      );
    end if;
  else
    select caliber.id
    into v_entity_id
    from public.odyssey_caliber_defs caliber
    where caliber.code = v_code
    limit 1;
  end if;

  if exists (
    select 1
    from public.odyssey_caliber_defs caliber
    where caliber.code = v_code
      and caliber.id <> coalesce(v_entity_id, '00000000-0000-0000-0000-000000000000'::uuid)
  ) then
    return public.odyssey_creator_error(
      'VALIDATION_ERROR',
      'Caliber code must be unique.',
      jsonb_build_array(jsonb_build_object('field', 'code', 'message', 'Duplicate caliber code.'))
    );
  end if;

  if v_entity_id is null then
    insert into public.odyssey_caliber_defs (
      code,
      name,
      base_damage_per_round,
      description,
      tags,
      is_custom,
      sort_order
    )
    values (
      v_code,
      v_name,
      v_base_damage_per_round,
      v_description,
      v_tags,
      true,
      v_sort_order
    )
    returning id into v_entity_id;
  else
    update public.odyssey_caliber_defs
    set
      code = v_code,
      name = v_name,
      base_damage_per_round = v_base_damage_per_round,
      description = v_description,
      tags = v_tags,
      sort_order = v_sort_order
    where id = v_entity_id;
  end if;

  v_result := public.creator_get_caliber(v_entity_id);

  return jsonb_build_object(
    'ok', true,
    'entity_id', v_entity_id,
    'entity', v_result,
    'warnings', '[]'::jsonb
  );
end;
$$;

create or replace function public.creator_delete_caliber(
  p_caliber_id uuid
)
returns jsonb
language plpgsql
as $$
declare
  v_caliber public.odyssey_caliber_defs%rowtype;
  v_ammo_type_count integer := 0;
  v_magazine_def_count integer := 0;
  v_weapon_model_count integer := 0;
  v_weapon_profile_count integer := 0;
  v_details jsonb := '[]'::jsonb;
begin
  select *
  into v_caliber
  from public.odyssey_caliber_defs caliber
  where caliber.id = p_caliber_id;

  if not found then
    return public.odyssey_creator_error(
      'CALIBER_NOT_FOUND',
      'Caliber was not found.',
      jsonb_build_array(jsonb_build_object('field', 'id', 'message', 'Unknown caliber id.'))
    );
  end if;

  select count(*)::integer
  into v_ammo_type_count
  from public.odyssey_ammo_type_defs ammo
  where ammo.caliber_id = p_caliber_id;

  select count(*)::integer
  into v_magazine_def_count
  from public.odyssey_magazine_defs mag
  where mag.caliber_id = p_caliber_id;

  select count(*)::integer
  into v_weapon_model_count
  from public.odyssey_weapon_model_defs weapon_model
  where weapon_model.caliber_id = p_caliber_id;

  select count(*)::integer
  into v_weapon_profile_count
  from public.odyssey_weapon_model_profiles profile
  where profile.caliber_id = p_caliber_id;

  if v_ammo_type_count > 0 or v_magazine_def_count > 0 or v_weapon_model_count > 0 or v_weapon_profile_count > 0 then
    v_details := v_details
      || jsonb_build_array(jsonb_build_object('field', 'ammo_types', 'message', format('Linked ammo types: %s', v_ammo_type_count)))
      || jsonb_build_array(jsonb_build_object('field', 'magazine_defs', 'message', format('Linked magazine definitions: %s', v_magazine_def_count)))
      || jsonb_build_array(jsonb_build_object('field', 'weapon_models', 'message', format('Linked weapon models: %s', v_weapon_model_count)))
      || jsonb_build_array(jsonb_build_object('field', 'weapon_profiles', 'message', format('Linked weapon profiles: %s', v_weapon_profile_count)));
    return public.odyssey_creator_error(
      'CALIBER_IN_USE',
      'Caliber cannot be deleted while catalog records still depend on it.',
      v_details
    );
  end if;

  delete from public.odyssey_caliber_defs
  where id = p_caliber_id;

  return jsonb_build_object(
    'ok', true,
    'deleted_id', p_caliber_id
  );
end;
$$;

create or replace function public.creator_list_ammo_types(
  p_search text default null
)
returns jsonb
language sql
stable
as $$
  with search_input as (
